(function() {
var luk_ch_1_Verses = [
  {num:1,words:[["E toatele ua taumafai ona tusi faasolo le tala i mea ua mautinoa e i tatou,", "Forasmuch as many have taken in hand to set forth in order a declaration of those things which are most surely believed among us,"]]},
  {num:2,words:[["e faapei ona tuuina mai ia te i tatou e i latou na matamata ai,", "Even as they delivered them unto us, which from the beginning were eyewitnesses,"], ["ma auauna ai i le upu talu le amataga;", "and ministers of the word;"]]},
  {num:3,words:[["o le mea lea ua ou manatu ai,", "It seemed good to me also,"], ["ona ua ou matuā sue i mea uma lava talu le amataga,", "having had perfect understanding of all things from the very first,"], ["ou te tusi faasolo atu ia te oe le alii e,", "to write unto thee in order,"], ["Teofilo,", "most excellent Theophilus,"]]},
  {num:4,words:[["ina ia e silafia le faamaoni o ia tala ua a'oa'oina ai oe.", "That thou mightest know the certainty of those things, wherein thou hast been instructed."]]},
  {num:5,words:[["O ona po o Herota le tupu o Iutaia,", "There was in the days of Herod, the king of Judaea,"], ["sa i ai le tasi faitaulaga e igoa ia Sakaria,", "a certain priest named Zacharias,"], ["sa i le vasega o Avia;", "of the course of Abia:"], ["o lana avā foi o lo sa Aronā,", "and his wife was of the daughters of Aaron, and her name was Elisabeth."]]},
  {num:6,words:[["e igoa ia Elisapeta. Sa amiotonu i laua i luma o le Atua,", "And they were both righteous before God,"], ["o savavali i poloaiga ma tulafono uma a le Alii e le mata'uleagaina.", "walking in all the commandments and ordinances of the Lord blameless."]]},
  {num:7,words:[["E leai sa la fanau,", "And they had no child,"], ["ina ua pa o Elisapeta,", "because that Elisabeth was barren,"], ["ua la matutua uma lava.", "and they both were now well stricken in years."]]},
  {num:8,words:[["Ua faia e ia le faiva o le faitaulaga i luma o le Atua,", "And it came to pass,"], ["e aua'i i lona vasega,", "that while he executed the priest's office before God in the order of his course,"]]},
  {num:9,words:[["pei o le tu a faitaulaga,", "According to the custom of the priest's office,"], ["o lona tofi e ulu i le malumalu o le Alii e faamu ai mea manogi;", "his lot was to burn incense when he went into the temple of the Lord."]]},
  {num:10,words:[["ua tatalo foi i fafo le motu o tagata uma, i le itu aso e mu ai mea manogi.", "And the whole multitude of the people were praying without at the time of incense."]]},
  {num:11,words:[["Ona faaali lea ia te ia le agelu a le Alii, o loo tu i le itu taumatau o le fata e mu ai mea manogi.", "And there appeared unto him an angel of the Lord standing on the right side of the altar of incense."]]},
  {num:12,words:[["Ua iloa e Sakaria,", "And when Zacharias saw him,"], ["ona atuatuvale ai lea,", "he was troubled,"], ["ua oo ia te ia le mata'u.", "and fear fell upon him."]]},
  {num:13,words:[["Ua faapea mai le agelu ia te ia,", "But the angel said unto him,"], ["Sakaria e,", "Fear not,"], ["aua e te mata'u;", "Zacharias:"], ["auā ua faafofogaina lau tatalo;", "for thy prayer is heard;"], ["e fanau lau avā o Elisapeta sou atalii,", "and thy wife Elisabeth shall bear thee a son,"], ["e te faaigoa ia te ia o Ioane.", "and thou shalt call his name John."]]},
  {num:14,words:[["E ia te oe le fiafia ma le olioli;", "And thou shalt have joy and gladness;"], ["e toatele foi e fiafia i lona fanau mai.", "and many shall rejoice at his birth."]]},
  {num:15,words:[["Auā e sili o ia i luma o le Alii;", "For he shall be great in the sight of the Lord,"], ["e le inu o ia i le uaina po o le 'ava;", "and shall drink neither wine nor strong drink; and he shall be filled with the Holy Ghost,"], ["e faatumuina foi o ia i le Agaga Paia e afua ina fanau mai o ia.", "even from his mother's womb."]]},
  {num:16,words:[["E faaliliu e ia le fanauga a Isaraelu e toatele i le Alii lo latou Atua.", "And many of the children of Israel shall he turn to the Lord their God."]]},
  {num:17,words:[["E muamua atu o ia i ona luma ma le loto o Elia ma lona faamalosi,", "And he shall go before him in the spirit and power of Elias,"], ["e faaliliu e ia loto o mātua i le fanau,", "to turn the hearts of the fathers to the children,"], ["e faaliliu foi e ua faalogogata i le poto o e amiotonu;", "and the disobedient to the wisdom of the just;"], ["e sauni le nuu e faatatauina mo le Alii.", "to make ready a people prepared for the Lord."]]},
  {num:18,words:[["Ona fai atu lea o Sakaria i le agelu,", "And Zacharias said unto the angel,"], ["Pe faapefea ona ou iloa le mea nei? auā ua ou toeaina,", "Whereby shall I know this? for I am an old man,"], ["o la'u avā foi ua loomatua ia.", "and my wife well stricken in years."]]},
  {num:19,words:[["Ua tali mai le agelu,", "And the angel answering said unto him,"], ["ua faapea mai ia te ia,", "I am Gabriel,"], ["O a'u o Kaperielu, o lē tu i luma o le Atua;", "that stand in the presence of God;"], ["ua auina mai a'u e fai atu,", "and am sent to speak unto thee,"], ["ma ta'u atu ia te oe lenei tala lelei.", "and to shew thee these glad tidings."]]},
  {num:20,words:[["Faauta foi,", "And,"], ["e gūgū oe,", "behold, thou shalt be dumb,"], ["e te le magagana seia oo i le aso e fai ai nei mea,", "and not able to speak,"], ["auā ua e le talitonu mai i a'u upu,", "until the day that these things shall be performed, because thou believest not my words,"], ["o mea ia e taunuu lava pe a oo i ona po.", "which shall be fulfilled in their season."]]},
  {num:21,words:[["O loo faatali le nuu ia Sakaria,", "And the people waited for Zacharias,"], ["ma ofo ina ua faatuai o ia i le malumalu.", "and marvelled that he tarried so long in the temple."]]},
  {num:22,words:[["Ua alu ia i fafo,", "And when he came out,"], ["a ua le magagana ia te i latou;", "he could not speak unto them:"], ["ua latou iloa ai ua na vaaia se faaaliga i le malumalu;", "and they perceived that he had seen a vision in the temple:"], ["a o ia ua genogeno atu ia te i latou,", "for he beckoned unto them,"], ["ua gūgū pea ia.", "and remained speechless."]]},
  {num:23,words:[["Ua uma ona aso na fai ai le galuega,", "And it came to pass, that,"], ["ona alu ai lea o ia i lona aiga.", "as soon as the days of his ministration were accomplished, he departed to his own house."]]},
  {num:24,words:[["Ua mavae ia aso,", "And after those days his wife Elisabeth conceived,"], ["ona to lea o Elisapeta lana avā, ua nofo faalilo o ia i ona masina e lima,", "and hid herself five months,"], ["ua faapea ane,", "saying,"]]},
  {num:25,words:[["Ua faapea ona faia e le Alii ia te au i ona aso ua silasila mai ai o ia,", "Thus hath the Lord dealt with me in the days wherein he looked on me,"], ["e ave ese ai lo'u luma i tagata.", "to take away my reproach among men."]]},
  {num:26,words:[["O le ono o masina ua auina mai ai e le Atua o le agelu o Kaperielu i le aai o Kalilaia, o Nasareta le igoa,", "And in the sixth month the angel Gabriel was sent from God unto a city of Galilee,"], ["i le taupou o le aiga o Tavita,", "named Nazareth,"]]},
  {num:27,words:[["ua faufautane i le tagata e igoa ia Iosefa;", "To a virgin espoused to a man whose name was Joseph, of the house of David;"], ["o Maria foi le igoa o le taupou.", "and the virgin's name was Mary."]]},
  {num:28,words:[["Ua ulufale mai le agelu ia te ia ona faapea mai lea o ia,", "And the angel came in unto her, and said,"], ["Si o'u alofa ia te oe le ua alofaina,", "Hail,"], ["ua ia te oe le Alii;", "thou that art highly favoured,"], ["amuia oe i fafine.", "the Lord is with thee: blessed art thou among women."]]},
  {num:29,words:[["Ua vaai atu foi o ia,", "And when she saw him,"], ["ona atuatuvale lea o ia i lana upu, ua taumanatunatu foi o ia,", "she was troubled at his saying,"], ["pe se a le uiga o lenei alofa.", "and cast in her mind what manner of salutation this should be."]]},
  {num:30,words:[["Ua fai mai foi le agelu ia te ia,", "And the angel said unto her,"], ["Maria e,", "Fear not,"], ["aua e te fefe;", "Mary:"], ["auā ua alofaina mai oe e le Atua.", "for thou hast found favour with God."]]},
  {num:31,words:[["Faauta foi,", "And,"], ["o le a to oe,", "behold,"], ["ma e fanauina se tama tane,", "thou shalt conceive in thy womb, and bring forth a son,"], ["e te faaigoa ia te ia o Iesu.", "and shalt call his name JESUS."]]},
  {num:32,words:[["E sili o ia,", "He shall be great,"], ["e ta'ua foi o le Alo o le Silisili ese;", "and shall be called the Son of the Highest:"], ["e foai atu e le Alii o le Atua ia te ia le nofoaiga a Tavita lona tamā;", "and the Lord God shall give unto him the throne of his father David:"]]},
  {num:33,words:[["e fai o ia ma tupu i le aiga o Iakopo e faavavau;", "And he shall reign over the house of Jacob for ever;"], ["o lona malo foi e leai sona gataaga.", "and of his kingdom there shall be no end."]]},
  {num:34,words:[["Ona fai atu lea o Maria i le agelu,", "Then said Mary unto the angel,"], ["A faapefea le mea nei;", "How shall this be,"], ["auā ou te lei iloa se tane?", "seeing I know not a man?"]]},
  {num:35,words:[["Ua tali mai le agelu, ua faapea mai ia te ia,", "And the angel answered and said unto her,"], ["E afio ifo le Agaga Paia i luga ia te oe,", "The Holy Ghost shall come upon thee,"], ["e faamalumalu ifo foi ia te oe le mana o le Silisili ese;", "and the power of the Highest shall overshadow thee:"], ["o le mea lea e ta'ua ai le tama paia, o le Alo o le Atua.", "therefore also that holy thing which shall be born of thee shall be called the Son of God."]]},
  {num:36,words:[["Faauta foi,", "And,"], ["o lou aiga o Elisapeta,", "behold,"], ["ua to o ia ina ua loomatua,", "thy cousin Elisabeth, she hath also conceived a son in her old age:"], ["o le tama tane foi lana tama;", "and this is the sixth month with her,"], ["o le onoga masina lenei i lē na ta'ua e pa;", "who was called barren."]]},
  {num:37,words:[["auā e leai lava se mea e tasi e le mafaia e le Atua.", "For with God nothing shall be impossible."]]},
  {num:38,words:[["Ua fai atu Maria,", "And Mary said,"], ["Faauta, o a'u nei o le auauna a le Alii;", "Behold the handmaid of the Lord;"], ["ia faia ia te au e tusa ma lau fetalaiga.", "be it unto me according to thy word."], ["Ona alu ese ai lea o le agelu ia te ia.", "And the angel departed from her."]]},
  {num:39,words:[["Ua tulai Maria i ia ona aso,", "And Mary arose in those days,"], ["ua faatelevave atu i le atu mauga,", "and went into the hill country with haste,"], ["i le tasi aai o Iuta;", "into a city of Juda;"]]},
  {num:40,words:[["ua ulu atu foi o ia i le fale o Sakaria,", "And entered into the house of Zacharias,"], ["ma alofa atu ia Elisapeta.", "and saluted Elisabeth."]]},
  {num:41,words:[["Ua faalogo mai Elisapeta i le alofa o Maria,", "And it came to pass, that,"], ["ona osooso ai lea o le tama i lona manava;", "when Elisabeth heard the salutation of Mary,"], ["ua faatumuina foi Elisapeta i le Agaga Paia;", "the babe leaped in her womb; and Elisabeth was filled with the Holy Ghost:"]]},
  {num:42,words:[["ua alaga ia,", "And she spake out with a loud voice,"], ["ua leo tele,", "and said,"], ["ua faapea mai, Amuia oe i fafine,", "Blessed art thou among women,"], ["amuia foi lē a fanau mai ia te oe.", "and blessed is the fruit of thy womb."]]},
  {num:43,words:[["Pe faapefea foi lenei mea,", "And whence is this to me,"], ["ina ua sau le tinā o lo'u Alii ia te au nei?", "that the mother of my Lord should come to me?"]]},
  {num:44,words:[["Faauta foi,", "For,"], ["ua oo mai le leo o lou alofa i o'u taliga,", "lo, as soon as the voice of thy salutation sounded in mine ears,"], ["ona osooso ai lea o le tama i lo'u manava ma le olioli.", "the babe leaped in my womb for joy."]]},
  {num:45,words:[["E manuia foi le fafine e talitonu,", "And blessed is she that believed:"], ["auā e taunuu upu na fetalai mai le Alii ia te ia.", "for there shall be a performance of those things which were told her from the Lord."]]},
  {num:46,words:[["Ona fai ane lea o Maria,", "And Mary said,"], ["Ua vivii atu lo'u loto i le Alii.", "My soul doth magnify the Lord,"]]},
  {num:47,words:[["Ua fiafia lava lo'u loto i le Atua lo'u Faaola;", "And my spirit hath rejoiced in God my Saviour."]]},
  {num:48,words:[["ina ua silasila mai o ia i lana auauna fafine ua faamaulaloina;", "For he hath regarded the low estate of his handmaiden: for,"], ["auā e amata mai nei ona faaamuia mai ia te au o tupulaga uma.", "behold, from henceforth all generations shall call me blessed."]]},
  {num:49,words:[["Auā o Le e ona le mana, ua faia e ia mea silisili mo a'u;", "For he that is mighty hath done to me great things;"], ["e paia foi lona suafa.", "and holy is his name."]]},
  {num:50,words:[["O lona alofa foi i e matatau ia te ia e āu tupulaga lava lea.", "And his mercy is on them that fear him from generation to generation."]]},
  {num:51,words:[["Ua faamalosi lona aao,", "He hath shewed strength with his arm;"], ["ua faataapeapeina e ia o e faamaualuluga i manatu o latou loto.", "he hath scattered the proud in the imagination of their hearts."]]},
  {num:52,words:[["Ua tulei ifo e ia o alii nai o latou nofoālii,", "He hath put down the mighty from their seats,"], ["a ua faaeaina e ia o e faamaulalo.", "and exalted them of low degree."]]},
  {num:53,words:[["Ua fagaina e ia i mea lelei e sa fia aai,", "He hath filled the hungry with good things;"], ["a o e mau mea ua aufuaina atu e ia.", "and the rich he hath sent empty away."]]},
  {num:54,words:[["Ua fesoasoani ia i lana auauna o Isaraelu,", "He hath holpen his servant Israel,"], ["ina ua manatu mai le alofa ia.", "in remembrance of his mercy;"]]},
  {num:55,words:[["Aperaamo ma ana fanau e faavavau,", "As he spake to our fathers, to Abraham,"], ["pei ona fetalai mai o ia i o tatou tamā.", "and to his seed for ever."]]},
  {num:56,words:[["Ua nofo Maria ma ia, pe tolu masina,", "And Mary abode with her about three months,"], ["ona foi ai lea o ia i lona aiga.", "and returned to her own house."]]},
  {num:57,words:[["Ua oo i le masina o Elisapeta e fanau ai,", "Now Elisabeth's full time came that she should be delivered;"], ["ona fanau ai lea e ia o le tama tane.", "and she brought forth a son."]]},
  {num:58,words:[["Ua faalogo e ua latou tuaoi atoa ma lona aiga, ua alofa tele mai le Alii ia te ia,", "And her neighbours and her cousins heard how the Lord had shewed great mercy upon her;"], ["ona olioli ai lea o i latou faatasi ma ia.", "and they rejoiced with her."]]},
  {num:59,words:[["Ua oo i le aso valu,", "And it came to pass,"], ["ona o mai lea o i latou e peritome ai le tama,", "that on the eighth day they came to circumcise the child;"], ["o le a faaigoa e i latou ia te ia i le igoa o lona tamā,", "and they called him Zacharias,"], ["o Sakaria.", "after the name of his father."]]},
  {num:60,words:[["Ona fai atu lea o lona tinā,", "And his mother answered and said,"], ["ua faapea atu, Aua;", "Not so;"], ["e igoa lava o ia ia Ioane.", "but he shall be called John."]]},
  {num:61,words:[["Ona latou fai mai lea ia te ia,", "And they said unto her,"], ["E leai se tasi o lou aiga e igoa i lea igoa.", "There is none of thy kindred that is called by this name."]]},
  {num:62,words:[["Ua latou genogeno atu i lona tamā,", "And they made signs to his father,"], ["pe se a lona loto i sona igoa.", "how he would have him called."]]},
  {num:63,words:[["Ona fai ane lea o ia i se papatusi e au mai,", "And he asked for a writing table,"], ["ona tusi ai lea e ia,", "and wrote,"], ["ua faapea,", "saying,"], ["O Ioane lona igoa. Ona latou ofo uma ai lea.", "His name is John. And they marvelled all."]]},
  {num:64,words:[["Ona matala loa lea o lona leo ma lona laulaufaiva,", "And his mouth was opened immediately,"], ["ona tautala lea o ia,", "and his tongue loosed, and he spake,"], ["ma faafetai i le Atua.", "and praised God."]]},
  {num:65,words:[["Ua oo ai le mata'u i e ua latou tuaoi uma,", "And fear came on all that dwelt round about them:"], ["ua soo foi le atu mauga uma o Iutaia i le tala i nei mea uma.", "and all these sayings were noised abroad throughout all the hill country of Judaea."]]},
  {num:66,words:[["O i latou uma na faalogo ai ua mafaufau i ai,", "And all they that heard them laid them up in their hearts,"], ["ua faapea ane,", "saying,"], ["Pe iu ina faapefea lena tama? Ua ia te ia foi le aao o le Alii.", "What manner of child shall this be! And the hand of the Lord was with him."]]},
  {num:67,words:[["Ua faatumuina Sakaria lona tamā i le Agaga Paia,", "And his father Zacharias was filled with the Holy Ghost,"], ["ona perofeta ane ai lea o ia,", "and prophesied,"], ["ua faapea ane,", "saying,"]]},
  {num:68,words:[["Faafetai i le Alii le Atua o Isaraelu, ina ua asiasi mai o ia,", "Blessed be the Lord God of Israel;"], ["ma togiolaina lona nuu,", "for he hath visited and redeemed his people,"]]},
  {num:69,words:[["ma ua faatuina le nifo o le olataga mo i tatou i le aiga o lana auauna o Tavita,", "And hath raised up an horn of salvation for us in the house of his servant David;"]]},
  {num:70,words:[["(faapei ona fetalai mai e ia i fofoga o ana perofeta paia talu mai anamua,", "As he spake by the mouth of his holy prophets,"], [")", "which have been since the world began:"]]},
  {num:71,words:[["o lo tatou olataga lava lea i e ua fai i tatou ma fili,", "That we should be saved from our enemies,"], ["ma lima o e ita mai uma lava ia te i tatou;", "and from the hand of all that hate us;"]]},
  {num:72,words:[["i lona alofa i o tatou tamā,", "To perform the mercy promised to our fathers,"], ["ma lona manatu mai i lana feagaiga paia;", "and to remember his holy covenant;"]]},
  {num:73,words:[["le tautoga na ia tauto ai ia Aperaamo lo tatou tamā;", "The oath which he sware to our father Abraham,"]]},
  {num:74,words:[["e foai mai ina ia laveaiina i tatou mai lima o e ita mai, tatou te le fefefe ai,", "That he would grant unto us,"], ["a e", "that we being delivered out of the hand of our enemies might serve him without fear,"]]},
  {num:75,words:[["auauna ia te ia ma le paia ma le amiotonu i ona luma i aso uma o lo tatou ola.", "In holiness and righteousness before him, all the days of our life."]]},
  {num:76,words:[["O oe foi le tama,", "And thou,"], ["e ta'ua oe o le perofeta a le Silisili ese,", "child, shalt be called the prophet of the Highest:"], ["auā e te muamua atu i luma o le Alii e sauni i ona ala;", "for thou shalt go before the face of the Lord to prepare his ways;"]]},
  {num:77,words:[["e faailoa atu le olataga i lona nuu i le faamagaloina o a latou agasala,", "To give knowledge of salvation unto his people by the remission of their sins,"]]},
  {num:78,words:[["ona ua muitmuti vale le alofa o lo tatou Atua,", "Through the tender mercy of our God;"], ["ua asiasi mai ai le malamalama mai lugā,", "whereby the dayspring from on high hath visited us,"]]},
  {num:79,words:[["e faamalamalama ai i e nonofo i le pouliuli ma le ata o le oti,", "To give light to them that sit in darkness and in the shadow of death,"], ["e ta'ita'i i o tatou vae i le ala o le manuia.", "to guide our feet into the way of peace."]]},
  {num:80,words:[["Ua tupu le tama,", "And the child grew,"], ["ma ua malosi lona loto; sa i le vao o ia,", "and waxed strong in spirit,"], ["ua oo i le aso na faaalia ai o ia ia Isaraelu.", "and was in the deserts till the day of his shewing unto Israel."]]},
];
renderVerseSet(luk_ch_1_Verses, 'luk-ch1-verses');

var luk_ch_2_Verses = [
  {num:1,words:[["O aso lava ia na oo mai ai le poloaiga a Kaisara Aokuso ia tusia uma ai le lalolagi.", "And it came to pass in those days, that there went out a decree from Caesar Augustus, that all the world should be taxed."]]},
  {num:2,words:[["(Na faia lenei uluai tusi ina o pule Kurenio i Suria).", "(And this taxing was first made when Cyrenius was governor of Syria.)"]]},
  {num:3,words:[["Ua o uma atu foi i latou ia tusia,", "And all went to be taxed,"], ["e taitasi i lana lava aai.", "every one into his own city."]]},
  {num:4,words:[["Ua alu ae foi Iosefa mai Kalilaia,", "And Joseph also went up from Galilee,"], ["mai le aai o Nasareta,", "out of the city of Nazareth, into Judaea,"], ["i Iutaia i le aai a Tavita,", "unto the city of David,"], ["ua igoa ia Peteleema,", "which is called Bethlehem; (because he was of the house and lineage of David:"], ["auā o le aiga ia ma le gafa o Tavita,", ")"]]},
  {num:5,words:[["ia tusia faatasi ma Maria lana avā sa fāufautane ia te ia,", "To be taxed with Mary his espoused wife,"], ["ua to o ia.", "being great with child."]]},
  {num:6,words:[["Sa i ai i laua,", "And so it was, that,"], ["ona oo lea i ona po e fanau ai o ia.", "while they were there, the days were accomplished that she should be delivered."]]},
  {num:7,words:[["Ua fanau e ia lana tama ulumatua,", "And she brought forth her firstborn son,"], ["ua ia aui ia te ia i le ie,", "and wrapped him in swaddling clothes,"], ["ma faataoto ia te ia i le fale povi,", "and laid him in a manger;"], ["auā latou te le ofi i le fale e tali ai malo.", "because there was no room for them in the inn."]]},
  {num:8,words:[["Sa i le vao o lea nuu leoleo mamoe,", "And there were in the same country shepherds abiding in the field,"], ["sa nonofo ai ma leoleo po i lo latou lafu mamoe.", "keeping watch over their flock by night."]]},
  {num:9,words:[["Faauta foi,", "And,"], ["ua tu mai ia i latou le agelu a le Alii,", "lo,"], ["ua pupula faataaliolio mai foi ia te i latou le pupula o le Alii,", "the angel of the Lord came upon them, and the glory of the Lord shone round about them:"], ["ua matuā fefefe ai lava i latou.", "and they were sore afraid."]]},
  {num:10,words:[["Ona fai mai lea o le agelu ia te i latou,", "And the angel said unto them, Fear not:"], ["Aua tou te matatau;", "for,"], ["auā faauta,", "behold,"], ["ou te au mai ia te outou le tala e olioli tele i le nuu uma;", "I bring you good tidings of great joy, which shall be to all people."]]},
  {num:11,words:[["auā o le aso nei ua fanau ai i le aai a Tavita, lo outou Faaola,", "For unto you is born this day in the city of David a Saviour,"], ["o le Alii ia o Keriso.", "which is Christ the Lord."]]},
  {num:12,words:[["O le faailoga lenei ia te outou,", "And this shall be a sign unto you;"], ["e iloa e outou le tama meamea ua aui i le ie,", "Ye shall find the babe wrapped in swaddling clothes,"], ["o loo taoto i le fale povi.", "lying in a manger."]]},
  {num:13,words:[["Ona faafuasei lea ona faatasi mai ma le agelu o 'au mai le lagi e toatele, ua vivii i le Atua,", "And suddenly there was with the angel a multitude of the heavenly host praising God,"], ["ua faapea ane,", "and saying,"]]},
  {num:14,words:[["O le viiga i le Atua i mea aupitoaluga;", "Glory to God in the highest,"], ["ma le manuia i le lalolagi;", "and on earth peace,"], ["o le finagalo alofa i tagata.", "good will toward men."]]},
  {num:15,words:[["Ua o i le lagi agelu sa ia i latou,", "And it came to pass,"], ["ona fetautalatala'i ai lea o leoleo mamoe,", "as the angels were gone away from them into heaven,"], ["Ina tatou o ia i Peteleema,", "the shepherds said one to another, Let us now go even unto Bethlehem,"], ["tatou te vaavaai i lenei mea ua faia,", "and see this thing which is come to pass,"], ["ua faailoa mai ia te i tatou e le Alii.", "which the Lord hath made known unto us."]]},
  {num:16,words:[["Ua latou faataalise atu,", "And they came with haste,"], ["ona maua lea o Maria,", "and found Mary,"], ["ma Iosefa,", "and Joseph,"], ["ma le tama meamea o taoto i le fale povi.", "and the babe lying in a manger."]]},
  {num:17,words:[["Ua latou iloa,", "And when they had seen it,"], ["ona latou faailoa ai lea o le upu na ta'ua mai ia te i latou i lea tama.", "they made known abroad the saying which was told them concerning this child."]]},
  {num:18,words:[["O i latou uma e na faalogo ai, ua ofo i latou i mea ua ta'ua mai ia te i latou e leoleo mamoe.", "And all they that heard it wondered at those things which were told them by the shepherds."]]},
  {num:19,words:[["A o Maria ua taofi ia upu uma,", "But Mary kept all these things,"], ["ua mafaufau ai lona loto.", "and pondered them in her heart."]]},
  {num:20,words:[["Ona foi mai lea o leoleo mamoe,", "And the shepherds returned,"], ["o vivii ma faafetai i le Atua, ona o mea uma ua latou faalogo ai ma vaai i ai,", "glorifying and praising God for all the things that they had heard and seen,"], ["pei ona ta'ua mai ia te i latou.", "as it was told unto them."]]},
  {num:21,words:[["Ua oo i le aso valu e peritome ai le tama,", "And when eight days were accomplished for the circumcising of the child,"], ["ona faaigoaina ai lea o ia o Iesu,", "his name was called JESUS,"], ["na faaigoa ai e le agelu a o lei i le manava o lona tinā .", "which was so named of the angel before he was conceived in the womb."]]},
  {num:22,words:[["Ua atoa ona aso o le faamamāina o ia,", "And when the days of her purification according to the law of Moses were accomplished,"], ["e tusa ma le tulafono a Mose, ona la au mai lea ia te ia i Ierusalema,", "they brought him to Jerusalem,"], ["e tuu atu ai i luma o le Alii;", "to present him to the Lord;"]]},
  {num:23,words:[["(pei ona tusia i le tulafono a le Alii,", "(As it is written in the law of the Lord,"], ["O tama tane ulumatua uma e taua i latou e paia mo le Alii;", "Every male that openeth the womb shall be called holy to the Lord;"], [")", ")"]]},
  {num:24,words:[["e avatu foi le taulaga,", "And to offer a sacrifice according to that which is said in the law of the Lord,"], ["pei ona fai mai ai le tulafono a le Alii, O le uluga manutagi,", "A pair of turtledoves,"], ["po o tamai lupe e lua fua.", "or two young pigeons."]]},
  {num:25,words:[["Faauta foi,", "And,"], ["sa i Ierusalema le tagata e igoa ia Simeona;", "behold, there was a man in Jerusalem,"], ["o le tagata amiotonu o ia ma le mata'u i le Atua,", "whose name was Simeon;"], ["sa faatalitali atu o ia i le faamafanafanaina o Isaraelu;", "and the same man was just and devout, waiting for the consolation of Israel:"], ["ua i luga ia te ia le Agaga Paia.", "and the Holy Ghost was upon him."]]},
  {num:26,words:[["Ua iloa e ia i le Agaga Paia,", "And it was revealed unto him by the Holy Ghost, that he should not see death,"], ["e le oo ia te ia le oti seia muai iloa atu le Keriso o le Alii.", "before he had seen the Lord's Christ."]]},
  {num:27,words:[["O le Agaga ua alu ai o ia i le malumalu;", "And he came by the Spirit into the temple:"], ["ua au mai le tama o Iesu e ona mātua,", "and when the parents brought in the child Jesus,"], ["ia la faia ia te ia faapei ona tatau i le tulafono,", "to do for him after the custom of the law,"]]},
  {num:28,words:[["ona sapaia lea e ia i ona lima,", "Then took he him up in his arms,"], ["ua faafetai atu i le Atua,", "and blessed God,"], ["ua faapea atu,", "and said,"]]},
  {num:29,words:[["Le Alii e,", "Lord, now lettest thou thy servant depart in peace,"], ["e te tuuina atu nei lau auauna ia alu ma le manuia pei o lau afioga;", "according to thy word:"]]},
  {num:30,words:[["auā ua iloa e o'u mata le faaolataga mai ia te oe,", "For mine eyes have seen thy salvation,"]]},
  {num:31,words:[["ua e saunia i luma o nuu uma lava;", "Which thou hast prepared before the face of all people;"]]},
  {num:32,words:[["o le malamalama e faamalamalama a'i nuu ese,", "A light to lighten the Gentiles,"], ["ma le mamalu o lou nuu o Isaraelu.", "and the glory of thy people Israel."]]},
  {num:33,words:[["Ua ofo lava Iosefa ma lona tinā i mea ua ta'ua ia te ia.", "And Joseph and his mother marvelled at those things which were spoken of him."]]},
  {num:34,words:[["Ua faamanuia atu Simeona ia te i laua,", "And Simeon blessed them,"], ["ua fai atu foi ia Maria lona tinā,", "and said unto Mary his mother,"], ["Faauta,", "Behold,"], ["ua tuu le tama nei e pauu ai ma toe tutū ai tagata e toatele o i Isaraelu;", "this child is set for the fall and rising again of many in Israel;"], ["e fai foi ma faailoga e faaleagaina;", "and for a sign which shall be spoken against;"]]},
  {num:35,words:[["(e tū'ia foi lou lava loto ia ati i le pelu),", "(Yea, a sword shall pierce through thy own soul also,"], ["ina ia faaalia mai ai manatu o loto i tagata e toatele.", ") that the thoughts of many hearts may be revealed."]]},
  {num:36,words:[["Sa i ai le perofeta fafine o Ana,", "And there was one Anna,"], ["o le afafine o Fanuelu o le itu aiga o Asera,", "a prophetess,"], ["ua loomatua ia,", "the daughter of Phanuel, of the tribe of Aser:"], ["sa la nonofo ma lana tane talu ina o taupou,", "she was of a great age,"], ["ua oo i lona fitu o tausaga.", "and had lived with an husband seven years from her virginity;"]]},
  {num:37,words:[["O ia foi le fafine nofo fua,", "And she was a widow of about fourscore and four years,"], ["pe atoa ona tausaga e valugafulu ma le fa, e lei alu ese ia i le malumalu,", "which departed not from the temple,"], ["a ua auauna o ia i le Atua i anapogi ma talosaga i le ao ma le po.", "but served God with fastings and prayers night and day."]]},
  {num:38,words:[["O lea lava itu aso, ua sau ai o ia,", "And she coming in that instant gave thanks likewise unto the Lord,"], ["ua faafetai atu i le Alii, ma tautala ia te ia i tagata uma lava e na faatali atu i le togiola i Ierusalema.", "and spake of him to all them that looked for redemption in Jerusalem."]]},
  {num:39,words:[["Ua uma ona faia e i laua o mea uma e tatau i le tulafono a le Alii,", "And when they had performed all things according to the law of the Lord,"], ["ona foi atu lea i Kalilaia,", "they returned into Galilee,"], ["i la laua aai o Nasareta.", "to their own city Nazareth."]]},
  {num:40,words:[["Ua tupu le tama,", "And the child grew,"], ["ma ua malosi lona loto,", "and waxed strong in spirit,"], ["ua tumu i le poto;", "filled with wisdom:"], ["ua ia te ia foi le alofa o le Atua.", "and the grace of God was upon him."]]},
  {num:41,words:[["Ua o i Ierusalema ona mātua i lea tausaga ma lea tausaga i le tausamiga o le paseka.", "Now his parents went to Jerusalem every year at the feast of the passover."]]},
  {num:42,words:[["Ua oo i ona tausaga e sefulu ma le lua, ona o ae lea o i latou i Ierusalema,", "And when he was twelve years old,"], ["e tusa ma le tu o le tausamiga.", "they went up to Jerusalem after the custom of the feast."]]},
  {num:43,words:[["Ua mavae ona aso,", "And when they had fulfilled the days,"], ["ona foi mai lea o i laua,", "as they returned,"], ["a ua nofo le tama o Iesu i Ierusalema,", "the child Jesus tarried behind in Jerusalem;"], ["a e lei iloa e Iosefa ma lona tinā.", "and Joseph and his mother knew not of it."]]},
  {num:44,words:[["Fa te i laua o i le au malaga o ia;", "But they,"], ["ua la po tasi i le ala,", "supposing him to have been in the company, went a day's journey;"], ["ona la saili lea ia te ia i lo la aiga ma e na latou masani.", "and they sought him among their kinsfolk and acquaintance."]]},
  {num:45,words:[["Ua le iloa o ia,", "And when they found him not,"], ["ona la foi atu lea i Ierusalema,", "they turned back again to Jerusalem,"], ["o saili ia te ia.", "seeking him."]]},
  {num:46,words:[["Ua mavae aso e tolu,", "And it came to pass,"], ["ona la maua ai lea o ia i le malumalu o nofo i totonu o le au a'oa'o,", "that after three days they found him in the temple,"], ["o loo faalogologo ia te i latou,", "sitting in the midst of the doctors, both hearing them,"], ["ma taufesili ia te i latou.", "and asking them questions."]]},
  {num:47,words:[["Ua matuā ofo uma lava e na faalogo ia te ia i lona poto ma ana upu e tali.", "And all that heard him were astonished at his understanding and answers."]]},
  {num:48,words:[["Ua la ofo ina ua iloa atu o ia e i laua;", "And when they saw him, they were amazed:"], ["ona fai ane lea o lona tinā ia te ia,", "and his mother said unto him,"], ["La'u tama e se a le mea ua e faapea mai ai ia te i maua? Faauta,", "Son,"], ["o i maua ma lou tamā sa ma saili lava ia te oe ma le tiga.", "why hast thou thus dealt with us? behold, thy father and I have sought thee sorrowing."]]},
  {num:49,words:[["Ona fai atu lea o ia ia te i laua,", "And he said unto them,"], ["Se a ea le mea na oulua saili mai ai ia te au? lua te le iloa ea e tatau ona ou i le fale o lo'u Tamā?", "How is it that ye sought me? wist ye not that I must be about my Father's business?"]]},
  {num:50,words:[["A ua le lagona e i laua le upu ua fai mai ai o ia ia te i laua.", "And they understood not the saying which he spake unto them."]]},
  {num:51,words:[["Ua latou o ifo ma i laua,", "And he went down with them,"], ["ua oo i Nasareta,", "and came to Nazareth,"], ["ua anaana o ia ia te i laua;", "and was subject unto them:"], ["a o lona tinā ua taofi ia mea uma i lona loto.", "but his mother kept all these sayings in her heart."]]},
  {num:52,words:[["Ua tupu le poto ma le tino o Iesu,", "And Jesus increased in wisdom and stature,"], ["ua alofagia o ia e le Atua atoa ma tagata.", "and in favour with God and man."]]},
];
renderVerseSet(luk_ch_2_Verses, 'luk-ch2-verses');

var luk_ch_3_Verses = [
  {num:1,words:[["O le tausaga e tasi le sefulu ma le lima i le nofoaiga a Tiperio Kaisara,", "Now in the fifteenth year of the reign of Tiberius Caesar,"], ["sa pule Ponotio Pilato i Iutaia,", "Pontius Pilate being governor of Judaea,"], ["o Herota foi o le tupu ia o Kalilaia,", "and Herod being tetrarch of Galilee,"], ["ma Filipo lona uso o le tupu ia o Ituraia ma le nuu o Terekoniti,", "and his brother Philip tetrarch of Ituraea and of the region of Trachonitis,"], ["o Lusanio foi o le tupu ia o Apilene;", "and Lysanias the tetrarch of Abilene,"]]},
  {num:2,words:[["o Ana ma Kaiafa o faitaulaga sili i laua,", "Annas and Caiaphas being the high priests,"], ["ua oo ane ai le afioga a le Atua ia Ioane le atalii o Sakaria i le vao.", "the word of God came unto John the son of Zacharias in the wilderness."]]},
  {num:3,words:[["Ona alu atu ai lea o ia i le itu uma o Ioritana,", "And he came into all the country about Jordan,"], ["ua tala'i atu le papatisoga o le salamo ina ia faamagaloina agasala.", "preaching the baptism of repentance for the remission of sins;"]]},
  {num:4,words:[["Pei ona tusia i le tusi o upu a Isaia le perofeta,", "As it is written in the book of the words of Esaias the prophet,"], ["ua faapea mai,", "saying,"], ["O le leo o le ua alaga i le vao,", "The voice of one crying in the wilderness,"], ["Ina teuteu ia outou le ala o le Alii,", "Prepare ye the way of the Lord,"], ["ia faalaulelei ona ala.", "make his paths straight."]]},
  {num:5,words:[["E faatumuina o vanu uma,", "Every valley shall be filled,"], ["e faamaulaloina foi mauga ma mea maupuepue uma;", "and every mountain and hill shall be brought low;"], ["e faasa'oina foi o mea piopio,", "and the crooked shall be made straight,"], ["ma mea gaoa e fai ma ala laulelei ia.", "and the rough ways shall be made smooth;"]]},
  {num:6,words:[["E vaaia foi e tagata uma le faaolataga mai le Atua.", "And all flesh shall see the salvation of God."]]},
  {num:7,words:[["Ua fai atu ia i le motu o tagata e na o mai e papatisoina e ia,", "Then said he to the multitude that came forth to be baptized of him,"], ["Fanau a gata feai e,", "O generation of vipers,"], ["o ai ea na na faaali atu ia te outou e sosola ese i le toasa atali?", "who hath warned you to flee from the wrath to come?"]]},
  {num:8,words:[["Ia outou fua mai ni fua e tatau ma le salamo,", "Bring forth therefore fruits worthy of repentance,"], ["a e aua tou te faapea ifo i o outou loto,", "and begin not to say within yourselves,"], ["O Aperaamo, o ia o lo matou tamā;", "We have Abraham to our father:"], ["auā ou te fai atu ia te outou,", "for I say unto you,"], ["e mafaia lava e le Atua ona faatupuina mai i nei maa ni fanau mā Aperaamo.", "That God is able of these stones to raise up children unto Abraham."]]},
  {num:9,words:[["O loo tuu nei foi le mătau i tafu'e o laau;", "And now also the axe is laid unto the root of the trees:"], ["o laau uma foi e le fua mai i fua lelei,", "every tree therefore which bringeth not forth good fruit is hewn down,"], ["e taia ma lafoina i le afi.", "and cast into the fire."]]},
  {num:10,words:[["Ua fesili mai le motu o tagata ia te ia,", "And the people asked him,"], ["ua faapea mai,", "saying,"], ["Se a foi se mea matou te faia?", "What shall we do then?"]]},
  {num:11,words:[["Ua tali atu ia,", "He answereth and saith unto them,"], ["ua faapea atu ia te i latou,", "He that hath two coats,"], ["O le tagata e lua ona ofu tino, ia avane ia te ia e leai sona ofu;", "let him impart to him that hath none;"], ["o le ua ia te ia mea e 'ai,", "and he that hath meat,"], ["ia faapea foi ona fai.", "let him do likewise."]]},
  {num:12,words:[["Ua o mai foi telona ia papatisoina,", "Then came also publicans to be baptized,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["Le a'oa'o e,", "Master,"], ["se a se mea matou te faia?", "what shall we do?"]]},
  {num:13,words:[["Ona faapea atu lea o ia ia te i latou,", "And he said unto them,"], ["Aua tou te faasili i mea ua totogi mai ia te outou.", "Exact no more than that which is appointed you."]]},
  {num:14,words:[["Ua fesili foi ia te ia tagata tau,", "And the soldiers likewise demanded of him,"], ["ua faapea mai,", "saying,"], ["Se a foi se mea matou te faia? Ona faapea atu lea o ia ia te i latou,", "And what shall we do? And he said unto them,"], ["Aua tou te faasaua i se tasi,", "Do violence to no man,"], ["aua tou te tuua'i fua se tasi;", "neither accuse any falsely;"], ["ia outou tali filemu i lo outou taui.", "and be content with your wages."]]},
  {num:15,words:[["O loo faatalitali le nuu,", "And as the people were in expectation,"], ["ma manatunatu uma lava i o latou loto ia Ioane,", "and all men mused in their hearts of John, whether he were the Christ,"], ["po o ia le Keriso;", "or not;"]]},
  {num:16,words:[["ua tali atu Ioane ia te i latou uma,", "John answered,"], ["ua faapea atu,", "saying unto them all,"], ["O a'u nei lē papatiso atu ia te outou i le vai, a o lē maliu mai,", "I indeed baptize you with water;"], ["e silisili o ia ia te au,", "but one mightier than I cometh,"], ["e le aoga a'u ona tatala le nonoa o ona seevae;", "the latchet of whose shoes I am not worthy to unloose:"], ["o ia lava na te papatiso ia te outou i le Agaga Paia ma le afi.", "he shall baptize you with the Holy Ghost and with fire:"]]},
  {num:17,words:[["O i lona aao lana asu,", "Whose fan is in his hand,"], ["e faamamā ai e ia lana faaputugāsaito;", "and he will throughly purge his floor,"], ["e faapotopoto foi e ia le saito i lona fale saito,", "and will gather the wheat into his garner;"], ["a e susunuina le otaota o saito i le afi e le matineia.", "but the chaff he will burn with fire unquenchable."]]},
  {num:18,words:[["O isi foi upu faamafanafana e tele ua ia folafola ai le tala lelei i le nuu.", "And many other things in his exhortation preached he unto the people."]]},
  {num:19,words:[["A ua aoaiina le tupu o Herota e ia,", "But Herod the tetrarch,"], ["ona o Herotia le avā a lona uso o Filipo,", "being reproved by him for Herodias his brother Philip's wife,"], ["atoa foi ma mea leaga uma na faia e Herota;", "and for all the evils which Herod had done,"]]},
  {num:20,words:[["ua na faaopoopoina lenei mea i mea uma,", "Added yet this above all,"], ["ua tuuina atu e ia o Ioane i le fale puipui.", "that he shut up John in prison."]]},
  {num:21,words:[["Ua papatisoina le nuu uma,", "Now when all the people were baptized,"], ["ona papatisoina ai lea o Iesu,", "it came to pass,"], ["ua tatalo ia,", "that Jesus also being baptized, and praying,"], ["ona faaavanoaina ai lea o le lagi,", "the heaven was opened,"]]},
  {num:22,words:[["ona afio ifo lea o le Agaga Paia i ona luga,", "And the Holy Ghost descended in a bodily shape like a dove upon him,"], ["ua tino mai e peiseai se lupe,", "and a voice came from heaven,"], ["ua oo mai foi le siufofoga mai le lagi, ua faapea mai,", "which said,"], ["O lo'u Atalii pele oe,", "Thou art my beloved Son;"], ["ua ou fiafia lava ia te oe.", "in thee I am well pleased."]]},
  {num:23,words:[["O Iesu foi, ua faatoa oo i le tolugafulu o ona tausaga,", "And Jesus himself began to be about thirty years of age,"], ["ua manatu foi tagata ,", "being (as was supposed) the son of Joseph,"], ["o ia le atalii o Iosefa, o le atalii ia o Heli,", "which was the son of Heli,"]]},
  {num:24,words:[["o le atalii ia o Matata,", "Which was the son of Matthat,"], ["o le atalii ia o Levi,", "which was the son of Levi,"], ["o le atalii ia o Meleki,", "which was the son of Melchi,"], ["o le atalii ia o Iana,", "which was the son of Janna,"], ["o le atalii ia o Iosefa,", "which was the son of Joseph,"]]},
  {num:25,words:[["o le atalii ia o Matatia,", "Which was the son of Mattathias,"], ["o le atalii ia o Amosa,", "which was the son of Amos,"], ["o le atalii ia o Nauma,", "which was the son of Naum,"], ["o le atalii ia o Eseli,", "which was the son of Esli,"], ["o le atalii ia o Nagae,", "which was the son of Nagge,"]]},
  {num:26,words:[["o le atalii ia o Maato,", "Which was the son of Maath,"], ["o le atalii ia o Matatia,", "which was the son of Mattathias,"], ["o le atalii ia o Semei,", "which was the son of Semei,"], ["o le atalii ia o Iosefa,", "which was the son of Joseph,"], ["o le atalii ia o Iuta,", "which was the son of Juda,"]]},
  {num:27,words:[["o le atalii ia o Ioana,", "Which was the son of Joanna,"], ["o le atalii ia o Resa,", "which was the son of Rhesa,"], ["o le atalii ia o Serupapelu,", "which was the son of Zorobabel,"], ["o le atalii ia o Salatielu,", "which was the son of Salathiel,"], ["o le atalii ia o Neri,", "which was the son of Neri,"]]},
  {num:28,words:[["o le atalii ia o Meleki,", "Which was the son of Melchi,"], ["o le atalii ia o Ati,", "which was the son of Addi,"], ["o le atalii ia o Kosamo,", "which was the son of Cosam,"], ["o le atalii ia o Elemotamo,", "which was the son of Elmodam,"], ["o le atalii ia o Eru,", "which was the son of Er,"]]},
  {num:29,words:[["o le atalii ia o Iose,", "Which was the son of Jose,"], ["o le atalii ia Elisara,", "which was the son of Eliezer,"], ["o le atalii ia o Iorimo,", "which was the son of Jorim,"], ["o le atalii ia o Matata,", "which was the son of Matthat,"], ["o le atalii ia o Levi,", "which was the son of Levi,"]]},
  {num:30,words:[["o le atalii ia o Simeona,", "Which was the son of Simeon,"], ["o le atalii ia o Iuta,", "which was the son of Juda,"], ["o le atalii ia o Iosefa,", "which was the son of Joseph,"], ["o le atalii ia o Ionano,", "which was the son of Jonan,"], ["o le atalii ia o Eliakimo,", "which was the son of Eliakim,"]]},
  {num:31,words:[["o le atalii ia o Melea,", "Which was the son of Melea,"], ["o le atalii ia o Mainano,", "which was the son of Menan,"], ["o le atalii ia o Matata,", "which was the son of Mattatha, which was the son of Nathan,"], ["o le atalii ia o Natano,", "which was the son of David,"]]},
  {num:32,words:[["o le atalii ia o Tavita,", "Which was the son of Jesse,"], ["o le atalii ia o Iese,", "which was the son of Obed,"], ["o le atalii ia o Opeta, o le atalii ia o Poasa,", "which was the son of Booz,"], ["o le atalii ia o Salemona,", "which was the son of Salmon,"], ["o le atalii ia o Naasona,", "which was the son of Naasson,"]]},
  {num:33,words:[["o le atalii ia o Aminatapu,", "Which was the son of Aminadab,"], ["o le atalii ia o Arama,", "which was the son of Aram,"], ["o le atalii ia o Eseroma,", "which was the son of Esrom, which was the son of Phares,"], ["o le atalii ia o Faresa,", "which was the son of Juda,"]]},
  {num:34,words:[["o le atalii ia o Iuta,", "Which was the son of Jacob,"], ["o le atalii ia o Iakopo,", "which was the son of Isaac,"], ["o le atalii ia o Isaako, o le atalii ia o Aperaamo,", "which was the son of Abraham,"], ["o le atalii ia o Tara,", "which was the son of Thara,"], ["o le atalii ia o Nakori,", "which was the son of Nachor,"]]},
  {num:35,words:[["o le atalii ia o Seruka,", "Which was the son of Saruch,"], ["o le atalii ia o Reu,", "which was the son of Ragau,"], ["o le atalii ia o Peleko,", "which was the son of Phalec,"], ["o le atalii ia o Eperu,", "which was the son of Heber,"], ["o le atalii ia o Selaa,", "which was the son of Sala,"]]},
  {num:36,words:[["o le atalii ia o Kainano,", "Which was the son of Cainan,"], ["o le atalii ia o Afasata,", "which was the son of Arphaxad,"], ["o le atalii ia o Semu,", "which was the son of Sem, which was the son of Noe,"], ["o le atalii ia o Noa,", "which was the son of Lamech,"]]},
  {num:37,words:[["o le atalii ia o Lameko,", "Which was the son of Mathusala,"], ["o le atalii ia o Metusela,", "which was the son of Enoch,"], ["o le atalii ia o Enoka, o le atalii ia o Iareto,", "which was the son of Jared,"], ["o le atalii ia o Maalaelu,", "which was the son of Maleleel,"], ["o le atalii ia o Kainano,", "which was the son of Cainan,"]]},
  {num:38,words:[["o le atalii ia o Enosa,", "Which was the son of Enos,"], ["o le atalii ia o Setu,", "which was the son of Seth,"], ["o le atalii ia o Atamu,", "which was the son of Adam,"], ["o le atalii ia o le Atua.", "which was the son of God."]]},
];
renderVerseSet(luk_ch_3_Verses, 'luk-ch3-verses');

var luk_ch_4_Verses = [
  {num:1,words:[["Ua foi ae Iesu mai Ioritana, ua tumu o ia i le Agaga Paia,", "And Jesus being full of the Holy Ghost returned from Jordan,"], ["ona ave lea o ia e le Agaga i le vao,", "and was led by the Spirit into the wilderness,"]]},
  {num:2,words:[["ua faaosoosoina e le tiapolo i aso e fagafulu. O aso lava ia e lei taumafa ai e ia sina mea e tasi;", "Being forty days tempted of the devil. And in those days he did eat nothing:"], ["ua mavae ia aso,", "and when they were ended,"], ["mulimuli ane ona fia taumafa ai lea o ia.", "he afterward hungered."]]},
  {num:3,words:[["Ona fai mai lea o le tiapolo ia te ia,", "And the devil said unto him,"], ["Afai o oe le Alo o le Atua,", "If thou be the Son of God,"], ["ina fetalai ane ia i lenei maa ia liu areto.", "command this stone that it be made bread."]]},
  {num:4,words:[["Ona tali atu lea o Iesu ia te ia,", "And Jesus answered him,"], ["ua faapea atu,", "saying,"], ["Ua tusia,", "It is written,"], ["E le na o mea e 'ai e ola ai le tagata,", "That man shall not live by bread alone,"], ["a o afioga uma a le Atua.", "but by every word of God."]]},
  {num:5,words:[["Ona aveina ae lea o ia e le tiapolo i le mauga maualuga,", "And the devil,"], ["ma faaali ia te ia malo uma o le lalolagi,", "taking him up into an high mountain,"], ["ua se emo lava.", "shewed unto him all the kingdoms of the world in a moment of time."]]},
  {num:6,words:[["Ona fai mai lea o le tiapolo ia te ia,", "And the devil said unto him,"], ["Ou te avatua ia te oe lenei pule uma,", "All this power will I give thee,"], ["ma lo latou mamalu;", "and the glory of them:"], ["auā ua tuuina mai ia te au,", "for that is delivered unto me;"], ["ou te avatu ai foi i lē ou te manao i ai;", "and to whomsoever I will I give it."]]},
  {num:7,words:[["o lenei, afai e te ifo mai ia te au,", "If thou therefore wilt worship me,"], ["e fai ma au nei mea uma.", "all shall be thine."]]},
  {num:8,words:[["Ona tali atu lea o Iesu,", "And Jesus answered and said unto him,"], ["ua faapea atu ia te ia,", "Get thee behind me,"], ["Satani e, ina alu ese ia oe i o'u tua;", "Satan:"], ["auā ua tusia,", "for it is written,"], ["E te ifo i le Alii lou Atua,", "Thou shalt worship the Lord thy God,"], ["ua na o ia lava e te auauna i ai.", "and him only shalt thou serve."]]},
  {num:9,words:[["Ona ave ai lea o ia ia te ia i Ierusalema,", "And he brought him to Jerusalem,"], ["ua faatu ia te ia i le tumutumu o le malumalu,", "and set him on a pinnacle of the temple,"], ["ona fai mai lea o ia ia te ia, Afai o oe le Alo o le Atua,", "and said unto him,"], ["ina oso ia oe i lalo i le mea nei;", "If thou be the Son of God,"], ["auā ua tusia,", "cast thyself down from hence:"]]},
  {num:10,words:[["E poloai o ia i ana agelu ia te oe,", "For it is written, He shall give his angels charge over thee,"], ["e tausi ia te oe;", "to keep thee:"]]},
  {num:11,words:[["latou te ave ia te oe i o latou lima,", "And in their hands they shall bear thee up,"], ["ne'i tū'ia lou vae i se maa.", "lest at any time thou dash thy foot against a stone."]]},
  {num:12,words:[["Ona tali atu lea o Iesu,", "And Jesus answering said unto him,"], ["ua faapea atu ia te ia, O loo faapea le upu,", "It is said,"], ["Aua e te tofotofo i le Alii lou Atua.", "Thou shalt not tempt the Lord thy God."]]},
  {num:13,words:[["Ua faauma e le tiapolo le tofotofoga uma,", "And when the devil had ended all the temptation,"], ["ona alu ese ai lea ia te ia seia i se aso.", "he departed from him for a season."]]},
  {num:14,words:[["Ona foi atu lea o Iesu i le mana o le Agaga i Kalilaia;", "And Jesus returned in the power of the Spirit into Galilee:"], ["ua logo atu foi le tala ia te ia ua soo ai lava le itu uma.", "and there went out a fame of him through all the region round about."]]},
  {num:15,words:[["Ua a'oa'o ia i o latou sunako,", "And he taught in their synagogues,"], ["ua viia ai o ia e tagata uma.", "being glorified of all."]]},
  {num:16,words:[["Ua oo foi o ia i Nasareta,", "And he came to Nazareth,"], ["na tupu ai o ia,", "where he had been brought up:"], ["ona ulufale lea o ia i le sunako i le aso sapati,", "and, as his custom was,"], ["o lana masani lea;", "he went into the synagogue on the sabbath day,"], ["ua tu i luga foi e faitau.", "and stood up for to read."]]},
  {num:17,words:[["Ua tuuina mai ia te ia le Tusi a le perofeta o Isaia. Ona fofola lea e ia le Tusi,", "And there was delivered unto him the book of the prophet Esaias. And when he had opened the book,"], ["ona maua ai lea o le mea ua tusia ai lenei upu .", "he found the place where it was written,"]]},
  {num:18,words:[["Ua i o'u luga le Agaga o le Alii,", "The Spirit of the Lord is upon me,"], ["auā ua na faauu mai ia te au e folafola le tala lelei i e matitiva;", "because he hath anointed me to preach the gospel to the poor;"], ["ua auina mai a'u e ia e faamalolo i e loto momomo,", "he hath sent me to heal the brokenhearted,"], ["e tala'i le saolotoga i le tafeaga,", "to preach deliverance to the captives,"], ["ma ia pupula mata o e tauaso,", "and recovering of sight to the blind,"], ["e tuu saoloto i e ua faasauaina,", "to set at liberty them that are bruised,"]]},
  {num:19,words:[["e tala'i le tausaga e finagalo malie mai ai le Alii.", "To preach the acceptable year of the Lord."]]},
  {num:20,words:[["Ua taai e ia le Tusi,", "And he closed the book,"], ["ona tuu atu ai lea i le auauna, ua nofo i lalo;", "and he gave it again to the minister,"], ["ona pulatoa mai lea ia te ia o mata o tagata uma i le sunako.", "and sat down. And the eyes of all them that were in the synagogue were fastened on him."]]},
  {num:21,words:[["Ona amata lea ona fetalai atu o ia ia te i latou, O le aso nei ua taunuu ai lenei Tusi,", "And he began to say unto them,"], ["o outou o faalogologo ai.", "This day is this scripture fulfilled in your ears."]]},
  {num:22,words:[["Ua latou vivii uma ia te ia,", "And all bare him witness,"], ["ua ofo foi i upu alofa na paū mai lona fofoga; ma ua latou fai ane,", "and wondered at the gracious words which proceeded out of his mouth. And they said,"], ["E le o le atalii ea lenei o Iosefa?", "Is not this Joseph's son?"]]},
  {num:23,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["E fai mai lava e outou lenei upu faatusa ia te au,", "Ye will surely say unto me this proverb,"], ["Le fomai e, ina faamalolo ia oe ia te oe;", "Physician,"], ["o mea uma na faia i Kapanaumi,", "heal thyself:"], ["na matou faalogo i ai,", "whatsoever we have heard done in Capernaum,"], ["ia e faia foi iinei i lou nuu moni.", "do also here in thy country."]]},
  {num:24,words:[["Ua fetalai atu ia,", "And he said,"], ["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["E le talia se perofeta i lona nuu moni.", "No prophet is accepted in his own country."]]},
  {num:25,words:[["E moni, ou te fai atu ia te outou;", "But I tell you of a truth,"], ["sa i Isaraelu i ona po o Elia,", "many widows were in Israel in the days of Elias,"], ["o fafine e toatele ua oti a latou tane,", "when the heaven was shut up three years and six months,"], ["na punitia ai le lagi i tausaga e tolu ma masina e ono, ua oge tele ai le nuu uma.", "when great famine was throughout all the land;"]]},
  {num:26,words:[["A e lei auina atu Elia i so latou,", "But unto none of them was Elias sent,"], ["ua na o Sarefata le aai o Saitonu,", "save unto Sarepta, a city of Sidon,"], ["i le fafine ua oti lana tane.", "unto a woman that was a widow."]]},
  {num:27,words:[["Sa i Isaraelu foi lepela e toatele i ona po o le perofeta o Elisaia;", "And many lepers were in Israel in the time of Eliseus the prophet;"], ["a e lei faamamāina so latou,", "and none of them was cleansed,"], ["ua na o Naamanu lava le Suria.", "saving Naaman the Syrian."]]},
  {num:28,words:[["Ua faalogo i latou uma ua i le sunako i nei mea,", "And all they in the synagogue, when they heard these things,"], ["ona lilivau ai lea o i latou.", "were filled with wrath,"]]},
  {num:29,words:[["Ua latou tutū mai,", "And rose up,"], ["ma tuli ia te ia i tua o le aai,", "and thrust him out of the city,"], ["ua ta'ita'i foi ia te ia i le tofē o le mauga ua tu ai la latou aai,", "and led him unto the brow of the hill whereon their city was built,"], ["ina ia latou faatito ifo ia te ia.", "that they might cast him down headlong."]]},
  {num:30,words:[["A ua savali ane ia i o latou va, ua maliu ese.", "But he passing through the midst of them went his way,"]]},
  {num:31,words:[["Ona maliu ifo lea o ia i Kapanaumi,", "And came down to Capernaum,"], ["o le aai o Kalilaia;", "a city of Galilee,"], ["ua a'oa'o o ia ia te i latou i sapati.", "and taught them on the sabbath days."]]},
  {num:32,words:[["Ua matuā ofo i latou i lana mataupu;", "And they were astonished at his doctrine:"], ["auā o lana fetalaiga ua i ai le pule.", "for his word was with power."]]},
  {num:33,words:[["Sa i le sunako o le tagata ua i ai le agaga o le temoni leaga;", "And in the synagogue there was a man,"], ["ua alaga mai foi o ia,", "which had a spirit of an unclean devil,"], ["ua leo tele,", "and cried out with a loud voice,"]]},
  {num:34,words:[["ua faapea mai,", "Saying,"], ["Aue! Iesu e,", "Let us alone;"], ["le Nasareta,", "what have we to do with thee,"], ["se a ea lau na ia te i matou? Ua e maliu mai ea ia fanoia i matou? Ua ou iloa oe,", "thou Jesus of Nazareth? art thou come to destroy us? I know thee who thou art;"], ["o le Paia oe o le Atua.", "the Holy One of God."]]},
  {num:35,words:[["Ona vavao lea o Iesu ia te ia,", "And Jesus rebuked him,"], ["ua faapea atu,", "saying,"], ["Ina faalologo ia,", "Hold thy peace,"], ["ma ē alu i fafo nai ia te ia. Ona lafo i lalo lea o le temoni ia te ia i o latou uma;", "and come out of him. And when the devil had thrown him in the midst,"], ["ona alu lea i fafo ia te ia,", "he came out of him,"], ["ua le afaina lava ia.", "and hurt him not."]]},
  {num:36,words:[["Ona ofo lea o i latou uma,", "And they were all amazed,"], ["ua fetautalatala'i foi,", "and spake among themselves,"], ["ua faapea ane,", "saying,"], ["O le a lenei mataupu? auā o le pule ma le mana ua fetalai atu ai o ia i agaga leaga,", "What a word is this! for with authority and power he commandeth the unclean spirits,"], ["ona latou o ese lea i fafo.", "and they come out."]]},
  {num:37,words:[["Ona logo atu lava lea o le tala ia te ia i mea uma o lea itu.", "And the fame of him went out into every place of the country round about."]]},
  {num:38,words:[["Ua tuua e ia le sunako,", "And he arose out of the synagogue,"], ["a e ulu atu i le fale o Simona.", "and entered into Simon's house."], ["Ua maua le tinā o le avā a Simona e le ma'i vevela, ua tele;", "And Simon's wife's mother was taken with a great fever;"], ["ua latou faatoga atu ia te ia mo ia.", "and they besought him for her."]]},
  {num:39,words:[["Ona tu lea o ia i ona tafatafa,", "And he stood over her,"], ["ua vavao le ma'i vevela,", "and rebuked the fever;"], ["ona mavae ai lea; ona tulai loa lea o ia,", "and it left her:"], ["ua auauna ia te i latou.", "and immediately she arose and ministered unto them."]]},
  {num:40,words:[["O i latou uma sa i ai tagata e mamai i ma'i eseese,", "Now when the sun was setting,"], ["ua latou aumaia i latou ia te ia i le goto o le la;", "all they that had any sick with divers diseases brought them unto him;"], ["ua pa'ipa'i tasi atu ona aao ia te i latou,", "and he laid his hands on every one of them,"], ["ma faamalolo ia te i latou.", "and healed them."]]},
  {num:41,words:[["Ua o atu foi temoni i fafo i e toatele,", "And devils also came out of many,"], ["o alalaga,", "crying out,"], ["ua faapea mai, O oe lava le Keriso,", "and saying,"], ["le Alo o le Atua.", "Thou art Christ the Son of God."], ["Ona vavao lea o ia ia te i latou , ua ia le mafai ona latou tautala;", "And he rebuking them suffered them not to speak:"], ["auā ua latou iloa o ia o le Keriso.", "for they knew that he was Christ."]]},
  {num:42,words:[["Ua ao,", "And when it was day,"], ["ona ulufafo lea o ia,", "he departed and went into a desert place:"], ["ua maliu atu i le mea tuufua; ua saili foi ia te ia le motu o tagata,", "and the people sought him,"], ["ona o mai ai lea ia te ia,", "and came unto him,"], ["ma taofi ia te ia,", "and stayed him,"], ["ina ia le maliu ese o ia ia te i latou.", "that he should not depart from them."]]},
  {num:43,words:[["A ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["E tatau ona ou folafola le tala lelei o le malo o le Atua i nisi aai foi;", "I must preach the kingdom of God to other cities also:"], ["auā o le mea lea na auina mai ai a'u.", "for therefore am I sent."]]},
  {num:44,words:[["Ona tala'i atu lea o ia i sunako o Kalilaia.", "And he preached in the synagogues of Galilee."]]},
];
renderVerseSet(luk_ch_4_Verses, 'luk-ch4-verses');

var luk_ch_5_Verses = [
  {num:1,words:[["Ua tu o ia i le auvai o le vai o Kenesareta,", "And it came to pass, that,"], ["ua fetuleni mai foi le motu o tagata ia te ia e faalogologo i le afioga a le Atua.", "as the people pressed upon him to hear the word of God, he stood by the lake of Gennesaret,"]]},
  {num:2,words:[["Ona silafia lea e ia vaa e lua ua talanai i le auvai,", "And saw two ships standing by the lake:"], ["a ua o ese ai le au faiva,", "but the fishermen were gone out of them,"], ["ua ta o latou upega.", "and were washing their nets."]]},
  {num:3,words:[["Ona maliu ae lea o ia i le tasi vaa,", "And he entered into one of the ships,"], ["o le vaa lea o Simona,", "which was Simon's,"], ["ma faatoga atu ia te ia ia faaitiiti atu le vaa nai le auvai. Ona nofo lea o ia i lalo,", "and prayed him that he would thrust out a little from the land. And he sat down,"], ["ma a'oa'o atu nai le vaa i le motu o tagata.", "and taught the people out of the ship."]]},
  {num:4,words:[["Ua uma lana lauga,", "Now when he had left speaking,"], ["ona fetalai atu lea o ia ia Simona,", "he said unto Simon,"], ["Ina tuutuu atu ia i le loloto,", "Launch out into the deep,"], ["ma tuu ifo ai o outou upega e maua ai ni i'a.", "and let down your nets for a draught."]]},
  {num:5,words:[["Ua tali mai Simona,", "And Simon answering said unto him,"], ["ua faapea mai ia te ia,", "Master,"], ["Le Alii e, ua atoa le po ua tigaina ai i matou,", "we have toiled all the night,"], ["e leai ni mea ua maua;", "and have taken nothing:"], ["a ona o lau fetalaiga ou te tuu ifo ai le upega.", "nevertheless at thy word I will let down the net."]]},
  {num:6,words:[["Ua uma ona latou faia o lea mea,", "And when they had this done,"], ["ona latou siomia lea o le au i'a tele lava,", "they inclosed a great multitude of fishes:"], ["ua masae ai lo latou upega.", "and their net brake."]]},
  {num:7,words:[["Ua latou genogeno atu i o latou o i le tasi vaa,", "And they beckoned unto their partners,"], ["e o mai e fesoasoani ia te i latou;", "which were in the other ship,"], ["ona latou o mai lea,", "that they should come and help them. And they came,"], ["ua faatumu e i latou vaa uma e lua,", "and filled both the ships,"], ["ua tāli gogoto ai.", "so that they began to sink."]]},
  {num:8,words:[["Ua iloa e Simona Peteru,", "When Simon Peter saw it,"], ["ona faapaū lea o ia i tulivae o Iesu,", "he fell down at Jesus' knees,"], ["ua faapea mai,", "saying,"], ["Le Alii e,", "Depart from me;"], ["ina maliu ese atu ia oe ia te au,", "for I am a sinful man,"], ["auā o a'u le tagata agasala.", "O Lord."]]},
  {num:9,words:[["Auā ua ofo o ia atoa ma i latou uma sa ia te ia,", "For he was astonished, and all that were with him,"], ["auā o le au i'a ua latou maua;", "at the draught of the fishes which they had taken:"]]},
  {num:10,words:[["ua faapea foi Iakopo ma Ioane,", "And so was also James,"], ["o atalii o Sepetaio,", "and John, the sons of Zebedee,"], ["o i latou ua fai faiva faatasi ma Simona.", "which were partners with Simon."], ["Ona fetalai atu lea o Iesu ia Simona,", "And Jesus said unto Simon,"], ["Aua e te fefe,", "Fear not;"], ["e amata i nei ona po ona e maua tagata.", "from henceforth thou shalt catch men."]]},
  {num:11,words:[["Ua tūta o latou vaa,", "And when they had brought their ships to land,"], ["ona latou tuu ai lea o mea uma,", "they forsook all,"], ["a e mulimuli atu ia te ia.", "and followed him."]]},
  {num:12,words:[["Sa i le tasi aai o ia,", "And it came to pass,"], ["faauta o le tagata ua liloia i le lepela;", "when he was in a certain city,"], ["ua iloa atu e ia o Iesu,", "behold a man full of leprosy:"], ["ona faapaū fao ai lea o ia,", "who seeing Jesus fell on his face,"], ["ma aioi mai ia te ia,", "and besought him,"], ["ua faapea mai,", "saying,"], ["Le Alii e,", "Lord,"], ["a e finagalo i ai ,", "if thou wilt,"], ["e mafai lava ia te oe ona faamamā ia te au.", "thou canst make me clean."]]},
  {num:13,words:[["Ona aapa atu lea e ia lona aao,", "And he put forth his hand,"], ["ua pa'i atu ia te ia,", "and touched him,"], ["ua faapea atu,", "saying,"], ["Ou te loto i ai;", "I will:"], ["ia mamā oe. Ona te'a ese loa lava lea o le ma'i lepela ia te ia.", "be thou clean. And immediately the leprosy departed from him."]]},
  {num:14,words:[["Ona fetalai atu lea o ia ia te ia,", "And he charged him to tell no man:"], ["Aua le ta'u atu i se tasi;", "but go,"], ["a ia e alu,", "and shew thyself to the priest,"], ["ma faaali oe i le faitaulaga,", "and offer for thy cleansing,"], ["ma avatu mo lou faamamāina e tusa ma le poloaiga a Mose,", "according as Moses commanded,"], ["e fai ma faailoga ia te i latou.", "for a testimony unto them."]]},
  {num:15,words:[["A ua atili ai ona logo atu le tala ia te ia. Ona faapotopoto mai lea o le motu o tagata e toatele e faalogologo ia te ia,", "But so much the more went there a fame abroad of him: and great multitudes came together to hear,"], ["ma ia faamaloloina e ia o latou ma'i.", "and to be healed by him of their infirmities."]]},
  {num:16,words:[["A ua maliu ia i le mea tuufua ua tatalo ai.", "And he withdrew himself into the wilderness, and prayed."]]},
  {num:17,words:[["Sa a'oa'o atu ia i le tasi aso,", "And it came to pass on a certain day,"], ["ua nonofo mai ai faresaio ma a'oa'o o le tulafono,", "as he was teaching,"], ["e na o mai mai faoa aai uma o Kalilaia,", "that there were Pharisees and doctors of the law sitting by, which were come out of every town of Galilee,"], ["ma Iutaia,", "and Judaea,"], ["ma Ierusalema;", "and Jerusalem:"], ["ua i ai foi le mana o le Alii e faamalolo ia te i latou.", "and the power of the Lord was present to heal them."]]},
  {num:18,words:[["Faauta foi,", "And,"], ["o tagata o loo fata mai i le moega le tagata ua ma'i i le supa;", "behold,"], ["ua latou mananao ina ia au mai ia te ia,", "men brought in a bed a man which was taken with a palsy: and they sought means to bring him in,"], ["ma tuu ifo i ona luma.", "and to lay him before him."]]},
  {num:19,words:[["A e lei iloa e i latou se mea e au mai ai ia te ia,", "And when they could not find by what way they might bring him in because of the multitude,"], ["ona o le motu o tagata, ona o ae lea o i latou i luga o le fale,", "they went upon the housetop,"], ["ua tuutuu ifo ia te ia ma lona moega i maa omea o le fale i totonu i luma o Iesu.", "and let him down through the tiling with his couch into the midst before Jesus."]]},
  {num:20,words:[["Ua silafia e ia lo latou faatuatua,", "And when he saw their faith,"], ["ona fetalai atu lea o ia ia te ia,", "he said unto him,"], ["Sole,", "Man,"], ["ua faamagaloina au agasala.", "thy sins are forgiven thee."]]},
  {num:21,words:[["Ona manatunatu lea o le au tusiupu ma le au faresaio,", "And the scribes and the Pharisees began to reason,"], ["ua faapea ane,", "saying,"], ["O ai ea lenei ua na upu leaga i le Atua? O ai na te mafaia ona faamagaloina agasala,", "Who is this which speaketh blasphemies? Who can forgive sins,"], ["ua na o le Atua lava?", "but God alone?"]]},
  {num:22,words:[["Ua silafia e Iesu o latou manatunatu,", "But when Jesus perceived their thoughts,"], ["ona tali atu ai lea o ia, ua faapea atu ia te i latou,", "he answering said unto them,"], ["Se a le mea tou te manatunatu ai i o outou loto?", "What reason ye in your hearts?"]]},
  {num:23,words:[["Po o le fea le faigofie? po o le fai atu. Ua faamagaloina au agasala;", "Whether is easier,"], ["po o le fai atu,", "to say,"], ["Tulai ia,", "Thy sins be forgiven thee; or to say,"], ["ina savali?", "Rise up and walk?"]]},
  {num:24,words:[["A e peitai ina ia iloa ai e outou o i le Atalii o le tagata le pule i le lalolagi e faamagalo ai agasala,", "But that ye may know that the Son of man hath power upon earth to forgive sins,"], ["(ua fetalai atu ia i le supa,", "(he said unto the sick of the palsy,"], [") Ou te fai atu ia te oe,", ") I say unto thee,"], ["Tulai ia,", "Arise,"], ["ina ave lou moega,", "and take up thy couch,"], ["ma e alu i lou fale.", "and go into thine house."]]},
  {num:25,words:[["Ona tulai loa lea o ia i o latou luma,", "And immediately he rose up before them,"], ["ua ave le mea na taoto ai o ia,", "and took up that whereon he lay,"], ["ona alu ai lea i lona fale,", "and departed to his own house,"], ["ua vivii atu i le Atua.", "glorifying God."]]},
  {num:26,words:[["Ua matuā ofo i latou uma,", "And they were all amazed,"], ["ma vivii atu i le Atua;", "and they glorified God,"], ["ua latou matuā fefefe foi,", "and were filled with fear,"], ["ua faapea ane,", "saying,"], ["Ua fāi ese na mea ua tatou iloa i le aso nei.", "We have seen strange things to day."]]},
  {num:27,words:[["Ua mavae ia mea,", "And after these things he went forth,"], ["ona ulufafo ai lea o ia,", "and saw a publican,"], ["ua silafia e ia le telona e igoa ia Levi,", "named Levi,"], ["ua nofo i le fale e tali ai taulaga;", "sitting at the receipt of custom:"], ["ona faapea atu lea ia te ia,", "and he said unto him,"], ["Ina mulimuli mai ia ia te au.", "Follow me."]]},
  {num:28,words:[["Ona tuua lea e ia o mea uma,", "And he left all, rose up,"], ["ua tulai ma mulimuli ia te ia.", "and followed him."]]},
  {num:29,words:[["Ua faia foi e Levi le faigaai tele māna i lona fale; sa i ai telona e toatele lava,", "And Levi made him a great feast in his own house:"], ["ma isi tagata e na taooto e aai faatasi ma i latou.", "and there was a great company of publicans and of others that sat down with them."]]},
  {num:30,words:[["A o latou tusiupu ma faresaio,", "But their scribes and Pharisees murmured against his disciples,"], ["ua latou muimui i ona soo, ua faapea atu,", "saying,"], ["Se a le mea tou te aai ai ma feinu ai faatasi ma le au telona ma e ua agasala?", "Why do ye eat and drink with publicans and sinners?"]]},
  {num:31,words:[["Ua tali atu Iesu,", "And Jesus answering said unto them,"], ["ua faapea atu ia te i latou, O e malolo e le aoga i ai le fomai,", "They that are whole need not a physician;"], ["na o e mamai.", "but they that are sick."]]},
  {num:32,words:[["Ou te lei sau e valaau i e ua amiotonu, a o e ua agasala,", "I came not to call the righteous,"], ["ina ia latou salamo.", "but sinners to repentance."]]},
  {num:33,words:[["Ua latou fai mai ia te ia,", "And they said unto him,"], ["Se a le mea e anapopogi soo ai,", "Why do the disciples of John fast often,"], ["ma tatalo ai le au soo o Ioane, ua faapea foi ma soo o le au faresaio,", "and make prayers,"], ["peitai ou soo ,", "and likewise the disciples of the Pharisees;"], ["ua latou aai ma inu?", "but thine eat and drink?"]]},
  {num:34,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["E mafai ea ona anapopogi o aumea a le faatoafaiavā,", "Can ye make the children of the bridechamber fast,"], ["ina o ia te i latou le faatoafaiavā?", "while the bridegroom is with them?"]]},
  {num:35,words:[["A e oo mai ona po e aveeseina ai ia te i latou le faatoafaiavā,", "But the days will come, when the bridegroom shall be taken away from them,"], ["o ona po ia latou te anapopogi ai.", "and then shall they fast in those days."]]},
  {num:36,words:[["Ua fetalai atu foi o ia ia te i latou i le faataoto,", "And he spake also a parable unto them;"], ["E leai se tagata na te fonoa le matuā ofu i le fasi ie o le ofu fou;", "No man putteth a piece of a new garment upon an old;"], ["a faapea,", "if otherwise,"], ["ona masae lea i le mea fou,", "then both the new maketh a rent,"], ["e le tusa foi le fasi ie fou ma le mea pala.", "and the piece that was taken out of the new agreeth not with the old."]]},
  {num:37,words:[["E leai foi se tasi na te utufia le uaina fou i fagu pa'u tuai;", "And no man putteth new wine into old bottles;"], ["a faapea,", "else the new wine will burst the bottles,"], ["ona pa ai lea o fagu pa'u i le uaina fou, ona masaa ai lea,", "and be spilled,"], ["e māumau foi fagu pa'u.", "and the bottles shall perish."]]},
  {num:38,words:[["A e peitai e utufia le uaina fou i fagu pa'u fou,", "But new wine must be put into new bottles;"], ["ona faatau saogalemu ai lea.", "and both are preserved."]]},
  {num:39,words:[["E leai foi se tagata e inu i le uaina tuai,", "No man also having drunk old wine straightway desireth new:"], ["ona manao loa lea i le uaina fou; auā ua fai mai o ia,", "for he saith,"], ["Ua lelei le uaina tuai.", "The old is better."]]},
];
renderVerseSet(luk_ch_5_Verses, 'luk-ch5-verses');

var luk_ch_6_Verses = [
  {num:1,words:[["O le sapati e tuaoi ma le aso muamua,", "And it came to pass on the second sabbath after the first,"], ["ua savali ai o ia i tosaito;", "that he went through the corn fields;"], ["ona ooti ai lea e ona soo o 'au saito,", "and his disciples plucked the ears of corn,"], ["ua mili ai i o latou lima,", "and did eat,"], ["ma aai ai.", "rubbing them in their hands."]]},
  {num:2,words:[["Ona fai mai lea ia te i latou o isi o le au faresaio,", "And certain of the Pharisees said unto them,"], ["Se a le mea tou te fai ai le mea e sa ona fai i le sapati?", "Why do ye that which is not lawful to do on the sabbath days?"]]},
  {num:3,words:[["Ua tali atu Iesu,", "And Jesus answering them said,"], ["ua faapea atu ia te i latou,", "Have ye not read so much as this,"], ["E lei faitau ea e outou le mea ua faia e Tavita,", "what David did,"], ["ina ua fia 'ai o ia,", "when himself was an hungred,"], ["atoa ma lana au malaga;", "and they which were with him;"]]},
  {num:4,words:[["ina ua ulu atu ia i le fale o le Atua, ma ua talia areto e laulauina i luma,", "How he went into the house of God,"], ["ua 'ai ai,", "and did take and eat the shewbread,"], ["ma avane i lana au malaga,", "and gave also to them that were with him;"], ["e sa ona 'ai ai, ua na o le au faitaulaga lava?", "which it is not lawful to eat but for the priests alone?"]]},
  {num:5,words:[["Ua fetalai atu foi o ia ia te i latou, O le Atalii o le tagata,", "And he said unto them,"], ["o le Alii lea o le sapati.", "That the Son of man is Lord also of the sabbath."]]},
  {num:6,words:[["O le tasi sapati foi ua ulu ai o ia i le sunako,", "And it came to pass also on another sabbath,"], ["ma a'oa'o atu;", "that he entered into the synagogue and taught:"], ["sa i ai le tagata ua gase lona lima taumatau.", "and there was a man whose right hand was withered."]]},
  {num:7,words:[["Ua lamalama ia te ia le au tusiupu ma le au faresaio,", "And the scribes and Pharisees watched him,"], ["pe faamalolo e ia i le sapati,", "whether he would heal on the sabbath day;"], ["ina ia latou maua se mea e momoli ai o ia.", "that they might find an accusation against him."]]},
  {num:8,words:[["A ua silafia e ia lo latou manatunatu,", "But he knew their thoughts,"], ["ona fetalai atu lea i le tagata ua gase lona lima,", "and said to the man which had the withered hand,"], ["Ina tulai ia,", "Rise up,"], ["ma tu mai i totonu.", "and stand forth in the midst."], ["Ona tulai loa o ia, ua tu mai.", "And he arose and stood forth."]]},
  {num:9,words:[["Ona fetalai atu lea o Iesu ia te i latou,", "Then said Jesus unto them,"], ["Ou te fesili atu ia te outou i le mea e tasi,", "I will ask you one thing;"], ["Pe tatau ea i le sapati ona agalelei,", "Is it lawful on the sabbath days to do good,"], ["pe agaleaga? po o le faaola,", "or to do evil? to save life,"], ["po o le fasioti?", "or to destroy it?"]]},
  {num:10,words:[["Ua silasila solo o ia ia te i latou uma, ona fetalai atu lea i le tagata,", "And looking round about upon them all,"], ["Ina faaloaloa ia lou lima;", "he said unto the man,"], ["ona faapea ai lea o ia;", "Stretch forth thy hand. And he did so:"], ["ona toe lelei ai lea o lona lima, e pei o le tasi.", "and his hand was restored whole as the other."]]},
  {num:11,words:[["Ona matuā ita ai lea o i latou,", "And they were filled with madness;"], ["ua fetautalatala'i i se mea latou te faia ia Iesu.", "and communed one with another what they might do to Jesus."]]},
  {num:12,words:[["O aso lava ia ua maliu ae ai o ia i le mauga e tatalo;", "And it came to pass in those days, that he went out into a mountain to pray,"], ["ua aoina lana tatalo i le Atua.", "and continued all night in prayer to God."]]},
  {num:13,words:[["Ua ao foi,", "And when it was day,"], ["ona valaau atu lea o ia i ona soo,", "he called unto him his disciples:"], ["ua filifilia e ia ni o latou e toasefulu ma le toalua,", "and of them he chose twelve,"], ["ua faaigoa foi i latou e ia o aposetolo;", "whom also he named apostles;"]]},
  {num:14,words:[["o Simona,", "Simon,"], ["ua ia faaigoa atu foi ia te ia o Peteru,", "(whom he also named Peter,"], ["ma Aneterea lona uso,", ") and Andrew his brother,"], ["o Iakopo ma Ioane,", "James and John,"], ["o Filipo ma Patolomaio,", "Philip and Bartholomew,"]]},
  {num:15,words:[["o Mataio ma Toma,", "Matthew and Thomas, James the son of Alphaeus,"], ["o Iakopo le atalii o Alefaio ma Simona ua igoa ia Selote,", "and Simon called Zelotes,"]]},
  {num:16,words:[["o Iuta foi le uso o Iakopo ma Iuta le Sekara,", "And Judas the brother of James, and Judas Iscariot,"], ["o ia lē faalata.", "which also was the traitor."]]},
  {num:17,words:[["Ua maliu ifo o ia faatasi ma i latou,", "And he came down with them,"], ["ona tu lea o ia i le mea laugatasai, ma ona soo e toatele,", "and stood in the plain,"], ["ma le motu o tagata e toatele,", "and the company of his disciples,"], ["mai Iutaia uma,", "and a great multitude of people out of all Judaea and Jerusalem,"], ["ma Ierusalema,", "and from the sea coast of Tyre and Sidon,"], ["ma le itu i tai o Turo ma Saitonu, ua latou o mai e faalogologo ia te ia,", "which came to hear him,"], ["ma ia faamaloloina o latou ma'i;", "and to be healed of their diseases;"]]},
  {num:18,words:[["o e na tigaina foi i agaga leaga,", "And they that were vexed with unclean spirits:"], ["ua faamaloloina foi i latou.", "and they were healed."]]},
  {num:19,words:[["Ua tausisi le motu o tagata uma e pa'i atu ia te ia;", "And the whole multitude sought to touch him:"], ["auā ua alu ane le mana nai ia te ia,", "for there went virtue out of him,"], ["ua faamaloloina ai i latou uma.", "and healed them all."]]},
  {num:20,words:[["Ua silasila atu ia i ona soo,", "And he lifted up his eyes on his disciples,"], ["ma fetalai atu,", "and said,"], ["Amuia outou e matitiva;", "Blessed be ye poor:"], ["auā e o outou le malo o le Atua.", "for your's is the kingdom of God."]]},
  {num:21,words:[["Amuia outou e fia aai nei;", "Blessed are ye that hunger now:"], ["auā e maoona outou. Amuia outou e tagi nei;", "for ye shall be filled. Blessed are ye that weep now:"], ["aua e featani outou.", "for ye shall laugh."]]},
  {num:22,words:[["Amuia outou pe a itagia outou e tagata,", "Blessed are ye,"], ["pe a faateaeseina foi outou,", "when men shall hate you,"], ["ma faaleagaina e i latou,", "and when they shall separate you from their company,"], ["ma lafoaiina lo outou igoa,", "and shall reproach you,"], ["pei o se mea leaga,", "and cast out your name as evil,"], ["ona o le Atalii o le tagata.", "for the Son of man's sake."]]},
  {num:23,words:[["Ia outou olioli i lea aso,", "Rejoice ye in that day,"], ["ma ia outou osooso ma le fiafia;", "and leap for joy:"], ["auā faauta,", "for, behold,"], ["o i le lagi lo outou taui ua tele;", "your reward is great in heaven:"], ["auā sa faapea ona fai e o latou tamā i perofeta.", "for in the like manner did their fathers unto the prophets."]]},
  {num:24,words:[["A e peitai oi talofa ia te outou o e mauoa! auā ua outou maua lo outou lelei.", "But woe unto you that are rich! for ye have received your consolation."]]},
  {num:25,words:[["Oi talofa ia te outou e ua maoona! auā e fia aai outou.", "Woe unto you that are full! for ye shall hunger."], ["Oi talofa ia te outou o e featani nei! auā e faanoanoa outou, ma fetagisi.", "Woe unto you that laugh now! for ye shall mourn and weep."]]},
  {num:26,words:[["Oi talofa ia te outou pe a tautala lelei tagata uma ia te outou! auā sa faapea lava ona fai e o latou tamā i perofeta pepelo.", "Woe unto you, when all men shall speak well of you! for so did their fathers to the false prophets."]]},
  {num:27,words:[["A ou te fai atu ia te outou o e faalogo mai. Ia alofa atu i e o fai outou mo latou fili:", "But I say unto you which hear, Love your enemies,"], ["ia agalelei atu i e ita mai ia te outou,", "do good to them which hate you,"]]},
  {num:28,words:[["ia outou faamanuia atu i e fetuu mai ia te outou,", "Bless them that curse you,"], ["ia outou tatalo foi mo e tuua'i fua mai ia te outou;", "and pray for them which despitefully use you."]]},
  {num:29,words:[["o lē po ia te oe i le tasi alafau, ina liliu atu i ai le tasi;", "And unto him that smiteth thee on the one cheek offer also the other;"], ["o lē ave ese lou ofu tele, aua e te vaoia atu foi lou ofu tino.", "and him that taketh away thy cloke forbid not to take thy coat also."]]},
  {num:30,words:[["Ina avatu ia i tagata uma o e ole mai ia te oe; o lē fao i au mea,", "Give to every man that asketh of thee;"], ["aua e te toe aamiina atu.", "and of him that taketh away thy goods ask them not again."]]},
  {num:31,words:[["Pei ona outou loto i tagata ona ia latou faia ia te outou,", "And as ye would that men should do to you,"], ["ia faapea lava ona outou faia ia te i latou.", "do ye also to them likewise."]]},
  {num:32,words:[["Pe afai tou te alofa atu i e alolofa mai ia te outou,", "For if ye love them which love you,"], ["pe se a ea se faafetai ia te outou i lea mea? auā ua alolofa atu ē agasala i e alolofa mai ia te i latou.", "what thank have ye? for sinners also love those that love them."]]},
  {num:33,words:[["Pe afai foi tou te agalelei atu i e agalelei mai ia te outou,", "And if ye do good to them which do good to you,"], ["se a ea se faafetai ia te outou i lea mea? auā ua faia lea lava mea e ua agasala.", "what thank have ye? for sinners also do even the same."]]},
  {num:34,words:[["Pe afai tou te avatu tupe i e nono mai,", "And if ye lend to them of whom ye hope to receive,"], ["ma outou faamoemoe i ai e toe maua mai ai,", "what thank have ye? for sinners also lend to sinners,"], ["se a ea se faafetai ia te outou i lea mea? auā e avatu e tagata agasala tupe e nonoina e tagata agasala ina ia latou maua mai sona faatusa.", "to receive as much again."]]},
  {num:35,words:[["Peitai outou,", "But love ye your enemies,"], ["ia outou alolofa atu i e o fai outou mo latou fili, ma ia agalelei atu,", "and do good,"], ["ma ia avatu tupe e nonoina,", "and lend,"], ["aua le faamoemoe i se mea e tasi e au mai;", "hoping for nothing again;"], ["e tele ai so outou totogi,", "and your reward shall be great,"], ["e avea foi outou ma fanau a le Silisili ese; auā o ia le agamalu i e agavale,", "and ye shall be the children of the Highest:"], ["atoa ma e amio leaga.", "for he is kind unto the unthankful and to the evil."]]},
  {num:36,words:[["O lenei, ia mutimuti vale lo outou alofa,", "Be ye therefore merciful,"], ["pei ona alofa mutimuti vale o lo outou Tamā.", "as your Father also is merciful."]]},
  {num:37,words:[["Aua tou te faamasino atu,", "Judge not,"], ["ona le faamasinoina mai ai lea o outou;", "and ye shall not be judged:"], ["aua tou te faasala,", "condemn not,"], ["ona le faasalaina mai ai lea o outou;", "and ye shall not be condemned:"], ["ia outou faamagaloina atu,", "forgive,"], ["e faamagaloina mai ai outou.", "and ye shall be forgiven:"]]},
  {num:38,words:[["Ia outou foai atu,", "Give,"], ["e foaiina mai ai ia te outou;", "and it shall be given unto you; good measure,"], ["e foai mai e i latou i lo outou lava ie pulupulu le fua lelei,", "pressed down,"], ["e lolomi ma luluina,", "and shaken together, and running over,"], ["e tumu ma solo i tua.", "shall men give into your bosom."], ["Auā o le fua tou te fuaina atu ai, e fuaina mai ai ia te outou.", "For with the same measure that ye mete withal it shall be measured to you again."]]},
  {num:39,words:[["Ua fetalai atu ia le faataoto ia te i latou,", "And he spake a parable unto them,"], ["E mafai ea le tauaso ona ta'ita'i i le tauaso? la te le pauu uma lava ea i le utu?", "Can the blind lead the blind? shall they not both fall into the ditch?"]]},
  {num:40,words:[["E le sili le soo i lona a'oa'o,", "The disciple is not above his master:"], ["a ua taitasi ma faapei o lona a'oa'o o e ua atoatoa ona lelei.", "but every one that is perfect shall be as his master."]]},
  {num:41,words:[["Se a le mea e te vaai atu ai i si fasi laau i le mata o lou uso,", "And why beholdest thou the mote that is in thy brother's eye,"], ["a e le iloa e oe le utupoto i lou lava mata?", "but perceivest not the beam that is in thine own eye?"]]},
  {num:42,words:[["Pe mafai faapefea ona e fai atu i lou uso,", "Either how canst thou say to thy brother,"], ["Lo'u uso e,", "Brother,"], ["ina tuu mai ia so'u eu ese le fasi laau i lou mata,", "let me pull out the mote that is in thine eye,"], ["a e iloa e oe le utupoto i lou lava mata? O oe na le pepelo,", "when thou thyself beholdest not the beam that is in thine own eye? Thou hypocrite,"], ["ia e muai tiai le utupoto i lou mata,", "cast out first the beam out of thine own eye,"], ["ona e iloa lelei ai lea e eu ese le fasi laau i le mata o lou uso.", "and then shalt thou see clearly to pull out the mote that is in thy brother's eye."]]},
  {num:43,words:[["E leai foi se laau lelei e fua mai i fua leaga;", "For a good tree bringeth not forth corrupt fruit;"], ["e leai foi se laau leaga e fua mai i fua lelei.", "neither doth a corrupt tree bring forth good fruit."]]},
  {num:44,words:[["Auā o laau taitasi ma lona lava fua e iloa ai; auā e le tau e tagata fua o le mati i laau tuitui,", "For every tree is known by his own fruit. For of thorns men do not gather figs,"], ["latou te le tau foi se fuifui vine i le laau talatala.", "nor of a bramble bush gather they grapes."]]},
  {num:45,words:[["Ua au mai mea lelei e le tagata amio lelei i mea lelei ua teu i lona loto;", "A good man out of the good treasure of his heart bringeth forth that which is good;"], ["o le tagata amio leaga foi ua au mai e ia mea leaga i mea leaga ua teu i lona loto;", "and an evil man out of the evil treasure of his heart bringeth forth that which is evil:"], ["auā o le tele o mea i le loto e tautala mai ai lona gutu.", "for of the abundance of the heart his mouth speaketh."]]},
  {num:46,words:[["Se a ea le mea e ta'ua ai a'u e outou,", "And why call ye me,"], ["Le Alii e,", "Lord,"], ["le Alii e,", "Lord,"], ["a e tou te le faia mea ou te fai atu ai?", "and do not the things which I say?"]]},
  {num:47,words:[["O sē sau ia te au ma faalogo i a'u upu,", "Whosoever cometh to me,"], ["ma faia e ia,", "and heareth my sayings, and doeth them,"], ["ou te faailoa atu ia te outou le ua tusa i ai o ia.", "I will shew you to whom he is like:"]]},
  {num:48,words:[["E tusa ia ma le tagata ua fai lona fale,", "He is like a man which built an house,"], ["ua ia eli maulalo,", "and digged deep,"], ["ua tuu le faavae i luga o le papa;", "and laid the foundation on a rock:"], ["ona sau ai lea o le tafe,", "and when the flood arose,"], ["ua fafati mai le vaitafe i lea fale,", "the stream beat vehemently upon that house,"], ["ua le magaoioi ai lava;", "and could not shake it:"], ["auā ua faavaeina i luga o le papa.", "for it was founded upon a rock."]]},
  {num:49,words:[["A o lē faalogo,", "But he that heareth,"], ["a e le faia,", "and doeth not,"], ["e tusa ia ma le tagata ua fai lona fale i luga o le eleele, e leai sona faavae;", "is like a man that without a foundation built an house upon the earth;"], ["ua fafati mai i ai le vaitafe,", "against which the stream did beat vehemently,"], ["ona paū loa lea,", "and immediately it fell;"], ["ona matuā nutipalaina lea o lea fale.", "and the ruin of that house was great."]]},
];
renderVerseSet(luk_ch_6_Verses, 'luk-ch6-verses');

var luk_ch_7_Verses = [
  {num:1,words:[["Ua faauma e ia ana fetalaiga uma, o faalogo ai le nuu,", "Now when he had ended all his sayings in the audience of the people,"], ["ona maliu ai lea o ia i Kapanaumi.", "he entered into Capernaum."]]},
  {num:2,words:[["Ua ma'i le auauna a le tasi ta'ita'i o le toaselau,", "And a certain centurion's servant,"], ["sa faapelepeleina e ia,", "who was dear unto him, was sick,"], ["ua tāli oti.", "and ready to die."]]},
  {num:3,words:[["Ua faalogo o ia ia Iesu,", "And when he heard of Jesus, he sent unto him the elders of the Jews,"], ["ona auina mai lea e ia o toeaina o Iutaia e aioi mai ia te ia ina ia maliu atu ma faaola lana auauna.", "beseeching him that he would come and heal his servant."]]},
  {num:4,words:[["Ua latou o mai ia Iesu,", "And when they came to Jesus,"], ["ona latou matuā faatoga mai lea ia te ia,", "they besought him instantly,"], ["ua faapea mai,", "saying,"], ["Ua aoga o ia e te fai ai le mea nei;", "That he was worthy for whom he should do this:"]]},
  {num:5,words:[["auā ua alofa mai o ia i lo tatou nuu,", "For he loveth our nation,"], ["ua na faia foi le sunako mo i matou.", "and he hath built us a synagogue."]]},
  {num:6,words:[["Ona maliu atu ai lea o Iesu ma i latou;", "Then Jesus went with them. And when he was now not far from the house,"], ["ua latalata ia i le fale,", "the centurion sent friends to him,"], ["ona auina mai lea e le ta'ita'i o le toaselau o ana uo ia te ia, ua faapea mai ia te ia,", "saying unto him,"], ["Le Alii e,", "Lord,"], ["aua ne'i faalavelaveina oe;", "trouble not thyself:"], ["auā ou te le aoga ina ia ulu mai oe i lo'u fale.", "for I am not worthy that thou shouldest enter under my roof:"]]},
  {num:7,words:[["O lea foi na ou manatu ai ou te le aoga ona ou alu atu ia te oe;", "Wherefore neither thought I myself worthy to come unto thee:"], ["a ia oo mai sau fetalaiga,", "but say in a word,"], ["e faamaloloina ai la'u auauna.", "and my servant shall be healed."]]},
  {num:8,words:[["Auā o a'u foi le tagata ua pule i ai le tasi,", "For I also am a man set under authority,"], ["ua ou pule foi i le 'au tau;", "having under me soldiers,"], ["a a'u fai atu i se tasi,", "and I say unto one,"], ["Ina alu ia,", "Go,"], ["ona alu ai lea;", "and he goeth;"], ["ma le tasi,", "and to another,"], ["Ina sau ia,", "Come,"], ["ona sau ai lea;", "and he cometh;"], ["ma la'u auauna,", "and to my servant,"], ["Ina faia lenei mea,", "Do this,"], ["ona fai ai lea.", "and he doeth it."]]},
  {num:9,words:[["Ua faafofoga Iesu i nei mea,", "When Jesus heard these things,"], ["ona ofo ai lea ia te ia;", "he marvelled at him, and turned him about,"], ["ua fāliu o ia,", "and said unto the people that followed him,"], ["ma fetalai atu i le motu o tagata e ua mulimuli mai ia te ia,", "I say unto you,"], ["Ou te fai atu ia te outou,", "I have not found so great faith, no,"], ["ou te lei iloa ia Isaraelu lava se faatuatua e faapena ona tele.", "not in Israel."]]},
  {num:10,words:[["O e na auina mai ua foi atu i le fale,", "And they that were sent,"], ["ona iloa lea e i latou o le auauna sa ma'i,", "returning to the house,"], ["ua malolo.", "found the servant whole that had been sick."]]},
  {num:11,words:[["O le taeao ua maliu ai o ia i le aai,", "And it came to pass the day after,"], ["o Naina le igoa,", "that he went into a city called Nain;"], ["ua o faatasi ma ia ona soo e toetele,", "and many of his disciples went with him,"], ["ma le motu o tagata e toatele.", "and much people."]]},
  {num:12,words:[["Ua latalata ia i le faitotoa o le aai,", "Now when he came nigh to the gate of the city,"], ["faauta foi,", "behold,"], ["ua fata mai le tagata oti,", "there was a dead man carried out,"], ["o le tama e toatasi o ia a lona tinā,", "the only son of his mother,"], ["o ia foi le fafine ua oti lana tane;", "and she was a widow:"], ["ua ia te ia foi tagata o le aai e toatele.", "and much people of the city was with her."]]},
  {num:13,words:[["Ua silasila atu le Alii ia te ia,", "And when the Lord saw her,"], ["ona mutimuti alofa lea o ia ia te ia,", "he had compassion on her,"], ["ua fetalai atu ia te ia,", "and said unto her,"], ["Aua e te tagi.", "Weep not."]]},
  {num:14,words:[["Ua maliu ane ia,", "And he came and touched the bier:"], ["ua pa'i atu i le fata; ona tutū mai ai lea o le au fata,", "and they that bare him stood still. And he said,"], ["ona fetalai atu lea o ia,", "Young man,"], ["Le tauleale e, ou te fai atu ia te oe,", "I say unto thee,"], ["Ina tulai ia.", "Arise."]]},
  {num:15,words:[["Ona nofo ai lea i luga o le na oti, ua tautala;", "And he that was dead sat up,"], ["ona ia tuuina atu lea o ia i lona tinā.", "and began to speak. And he delivered him to his mother."]]},
  {num:16,words:[["Ua oo le mata'u ia te i latou uma,", "And there came a fear on all:"], ["ua latou vivii atu i le Atua,", "and they glorified God,"], ["ua faapea ane,", "saying,"], ["Ua tu mai ia te i tatou le perofeta sili;", "That a great prophet is risen up among us;"], ["i le ma lea,", "and,"], ["Ua asiasi mai le Atua i lona nuu.", "That God hath visited his people."]]},
  {num:17,words:[["Ua soo lava Iutaia uma ma le itu uma i lenei tala ia te ia.", "And this rumour of him went forth throughout all Judaea, and throughout all the region round about."]]},
  {num:18,words:[["Ua faailoa atu ia Ioane nei mea uma e ona soo.", "And the disciples of John shewed him of all these things."]]},
  {num:19,words:[["Ona valaau atu lea e Ioane i ona soo se toalua,", "And John calling unto him two of his disciples sent them to Jesus,"], ["ua aauina atu i laua ia Iesu, ua faapea ane,", "saying,"], ["Po o oe ea lē maliu mai? pe matou te faatali atu i se tasi?", "Art thou he that should come? or look we for another?"]]},
  {num:20,words:[["Ua o mai ia tagata ia te ia,", "When the men were come unto him,"], ["ua faapea mai,", "they said,"], ["Ua aauina mai i maua e Ioane le papatiso ia te oe,", "John Baptist hath sent us unto thee,"], ["ua fai mai,", "saying,"], ["Po o oe ea lē maliu mai? pe matou te faatali atu i se tasi?", "Art thou he that should come? or look we for another?"]]},
  {num:21,words:[["O lea lava itu aso ua faamalolo ai e ia tagata e toatele sa i ai ma'i,", "And in that same hour he cured many of their infirmities and plagues,"], ["ma ma'i tiga, ma agaga leaga;", "and of evil spirits;"], ["ua foai atu foi ina ia vaai o e tauaso e toatele.", "and unto many that were blind he gave sight."]]},
  {num:22,words:[["Ona tali atu lea o Iesu ia te i laua,", "Then Jesus answering said unto them,"], ["ua faapea atu,", "Go your way,"], ["Ina o atu ia oulua, ma faailoa atu ia Ioane o mea ua oulua vaai i ai,", "and tell John what things ye have seen and heard;"], ["ma faalogo i ai;", "how that the blind see,"], ["ua pupula tauaso,", "the lame walk,"], ["ua savavali pipili,", "the lepers are cleansed,"], ["ua faamamāina lepela, ua logo tutuli,", "the deaf hear,"], ["ua faatutūina e na oti,", "the dead are raised,"], ["ua folafolaina le tala lelei i e matitiva.", "to the poor the gospel is preached."]]},
  {num:23,words:[["E manuia foi se le tausuai ia te a'u.", "And blessed is he, whosoever shall not be offended in me."]]},
  {num:24,words:[["Ua o e na auina mai e Ioane,", "And when the messengers of John were departed,"], ["ona oo ane ai lea o lana lauga i le motu o tagata ia Ioane,", "he began to speak unto the people concerning John,"], ["Na outou o i le vao e matamata i ni a? o le u ea na luluina e le matagi?", "What went ye out into the wilderness for to see? A reed shaken with the wind?"]]},
  {num:25,words:[["Pe na outou o e matamata i ni a? o le tagata ea ua ofu i ofu malulu? faauta,", "But what went ye out for to see? A man clothed in soft raiment? Behold,"], ["o e ofu i ofu matagofie,", "they which are gorgeously apparelled,"], ["ma ua solo lelei,", "and live delicately,"], ["o i maota o tupu ia.", "are in kings' courts."]]},
  {num:26,words:[["Pe na outou o e matamata i ni a? o le perofeta ea? E moni,", "But what went ye out for to see? A prophet? Yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E sili lava ia i le perofeta.", "and much more than a prophet."]]},
  {num:27,words:[["O ia lea ua tusi mai i ai,", "This is he,"], ["Faauta,", "of whom it is written,"], ["ou te auina atu la'u sāvali i ou luma,", "Behold, I send my messenger before thy face,"], ["na te teuteua lou ala i ou luma.", "which shall prepare thy way before thee."]]},
  {num:28,words:[["Ou te fai atu foi ia te outou,", "For I say unto you,"], ["E leai se perofeta i e na fananau i fafine e sili ia Ioane le papatiso; a o lē aupito itiiti i le malo o le Atua,", "Among those that are born of women there is not a greater prophet than John the Baptist:"], ["e sili lea ia te ia.", "but he that is least in the kingdom of God is greater than he."]]},
  {num:29,words:[["Ona ta'uamiotonuina ai lea o le Atua e le nuu uma lava e na faalogo ai,", "And all the people that heard him,"], ["atoa ma le au telona,", "and the publicans, justified God,"], ["ina ua papatisoina i latou i le papatisoga a Ioane.", "being baptized with the baptism of John."]]},
  {num:30,words:[["A o le au faresaio ma le au a'oa'a tulafono, ua latou faaleaoga ia te i latou le pule a le Atua,", "But the Pharisees and lawyers rejected the counsel of God against themselves,"], ["ina ua le papatisoina i latou e ia.", "being not baptized of him."]]},
  {num:31,words:[["Ua fetalai atu le Alii,", "And the Lord said,"], ["Ou te faatusa i ni a tagata o lenei tupulaga? latou te tusa ma ni a?", "Whereunto then shall I liken the men of this generation? and to what are they like?"]]},
  {num:32,words:[["E tusa ia ma tama iti ua nonofo i le malae,", "They are like unto children sitting in the marketplace,"], ["ma fevalaauai,", "and calling one to another,"], ["ua faapea ane,", "and saying,"], ["Ua matou faaili atu ia te outou,", "We have piped unto you,"], ["a e tou te lei saasaa mai;", "and ye have not danced;"], ["ua matou fetagisi atu ia te outou,", "we have mourned to you,"], ["a e tou te lei taufaitagitu'i mai.", "and ye have not wept."]]},
  {num:33,words:[["Auā na sau Ioane le papatiso,", "For John the Baptist came neither eating bread nor drinking wine;"], ["ua le 'ai areto, ua le inu foi uaina;", "and ye say,"], ["ona outou fai ane lea Ua ia te ia le temoni.", "He hath a devil."]]},
  {num:34,words:[["Ua sau le Atalii o le tagata,", "The Son of man is come eating and drinking;"], ["ua 'ai o ia ma inu;", "and ye say,"], ["ona outou fai ane lea, Faauta,", "Behold a gluttonous man,"], ["o le tagata 'ai tele ma le inu uaina,", "and a winebibber,"], ["o le uo a telona ma ē agasala.", "a friend of publicans and sinners!"]]},
  {num:35,words:[["A ua ta'uamiotonuina le poto e ana tama uma.", "But wisdom is justified of all her children."]]},
  {num:36,words:[["Ua fai mai le tasi o le au faresaio se'i la aai ma ia; ua maliu atu ia i le fale o le faresaio,", "And one of the Pharisees desired him that he would eat with him. And he went into the Pharisee's house,"], ["ona taoto ai lea o ia e taumafa.", "and sat down to meat."]]},
  {num:37,words:[["Faauta foi,", "And,"], ["o le fafine o le aai,", "behold,"], ["o ia o le fafine agasala,", "a woman in the city, which was a sinner,"], ["ua iloa e ia ua taoto o ia e taumafa i le fale o le faresaio,", "when she knew that Jesus sat at meat in the Pharisee's house,"], ["ona au mai lea e ia o le fagu alapasa ua tumu i le suāuu manogi;", "brought an alabaster box of ointment,"]]},
  {num:38,words:[["ua tu foi o ia i tua i ona vae,", "And stood at his feet behind him weeping,"], ["ua tagi,", "and began to wash his feet with tears,"], ["ua faasisina ifo e ia loimata i ona vae, ua sōloi ai i lona lava lauulu,", "and did wipe them with the hairs of her head,"], ["ua sogi foi i ona vae,", "and kissed his feet,"], ["ma faauuina i le suāuu manogi.", "and anointed them with the ointment."]]},
  {num:39,words:[["Ua iloa e le faresaio na fai atu ia te ia,", "Now when the Pharisee which had bidden him saw it,"], ["ona faapea ifo ai lea o ia i lona loto,", "he spake within himself,"], ["A se perofeta lenei,", "saying,"], ["po ua iloa e ia lenei fafine,", "This man,"], ["ma lana amio,", "if he were a prophet,"], ["ua ia pa'i atu ia te ia;", "would have known who and what manner of woman this is that toucheth him:"], ["auā o le fafine agasala ia.", "for she is a sinner."]]},
  {num:40,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "And Jesus answering said unto him,"], ["ua faapea atu, Simona e,", "Simon,"], ["o la'u upu ou te fai atu ia te oe.", "I have somewhat to say unto thee."], ["Ua fai mai o ia,", "And he saith,"], ["Le a'oa'o e,", "Master,"], ["fetalai mai ia.", "say on."]]},
  {num:41,words:[["O tagata e toalua sa la nonō mai tupe i le tagata e toatasi;", "There was a certain creditor which had two debtors:"], ["sa nonō mai le tasi i tenari e lima selau,", "the one owed five hundred pence,"], ["e a le tasi e limagafulu.", "and the other fifty."]]},
  {num:42,words:[["Ua leai ni a la tupe e toe avatu,", "And when they had nothing to pay,"], ["ona faamagalo fua lea o ia ia te i laua uma. Ina fai mai ia,", "he frankly forgave them both. Tell me therefore,"], ["po o ai so laua e tele lona alofa ia te ia?", "which of them will love him most?"]]},
  {num:43,words:[["Ua tali mai Simona,", "Simon answered and said,"], ["ua faapea mai,", "I suppose that he,"], ["Ai lava o lea na faamagaloina atu ana mea e tele. Ua fetalai atu ia ia te ia,", "to whom he forgave most. And he said unto him,"], ["Ua tonu lau taofi.", "Thou hast rightly judged."]]},
  {num:44,words:[["Ona fāliu atu lea o ia i le fafine,", "And he turned to the woman,"], ["ua fetalai atu ia Simona,", "and said unto Simon,"], ["Ua e iloa ea le fafine nei? na ou ulu mai i lou fale, e te lei au mai ni vai mo o'u vae;", "Seest thou this woman? I entered into thine house,"], ["peitai o ia,", "thou gavest me no water for my feet:"], ["ua faasisina ifo e ia o loimata i o'u vae,", "but she hath washed my feet with tears,"], ["ma sōloi ai i lona lava lauulu.", "and wiped them with the hairs of her head."]]},
  {num:45,words:[["E te lei feasogi mai ia te au; peitai o ia,", "Thou gavest me no kiss:"], ["ua le aunoa ona sogi i o'u vae talu lava ona ulufale mai o ia.", "but this woman since the time I came in hath not ceased to kiss my feet."]]},
  {num:46,words:[["E te lei faauu mai i lo'u ulu i le suāuu fua; peitai o ia,", "My head with oil thou didst not anoint:"], ["ua faauu e ia i o'u vae i le suāuu manogi.", "but this woman hath anointed my feet with ointment."]]},
  {num:47,words:[["O lea foi ou te fai atu ai ia te oe,", "Wherefore I say unto thee,"], ["Ua faamagaloina ana agasala e tele,", "Her sins, which are many,"], ["auā ua alofa tele mai o ia;", "are forgiven;"], ["a o le ua faamagaloina i ai se mea itiiti,", "for she loved much: but to whom little is forgiven,"], ["ua itiiti foi lona alofa.", "the same loveth little."]]},
  {num:48,words:[["Ua fetalai atu ia i le fafine,", "And he said unto her,"], ["Ua faamagaloina au agasala.", "Thy sins are forgiven."]]},
  {num:49,words:[["O e na taooto e aai ua latou faapea ifo i o latou loto,", "And they that sat at meat with him began to say within themselves,"], ["O ai foi lenei o lē faamagaloina agasala?", "Who is this that forgiveth sins also?"]]},
  {num:50,words:[["Ua fetalai atu o ia i le fafine,", "And he said to the woman,"], ["Ua e ola i lou faatuatua;", "Thy faith hath saved thee;"], ["ina alu ia oe ma le manuia.", "go in peace."]]},
];
renderVerseSet(luk_ch_7_Verses, 'luk-ch7-verses');

var luk_ch_8_Verses = [
  {num:1,words:[["Mulimuli ane ua faataamilo o ia i aai ma faoa aai,", "And it came to pass afterward,"], ["ua tala'i ma folafola le tala lelei o le malo o le Atua;", "that he went throughout every city and village, preaching and shewing the glad tidings of the kingdom of God:"], ["ua faatasi foi ma ia le toasefulu ma le toalua,", "and the twelve were with him,"]]},
  {num:2,words:[["atoa ma nisi fafine sa i ai agaga leaga ma ma'i,", "And certain women,"], ["a ua faamaloloina;", "which had been healed of evil spirits and infirmities,"], ["o Maria ua ta'ua o le Makatala,", "Mary called Magdalene,"], ["na ō i fafo ia te ia temoni e toafitu,", "out of whom went seven devils,"]]},
  {num:3,words:[["ma Ioana le avā a Kusa le auauna pule lea a Herota,", "And Joanna the wife of Chuza Herod's steward,"], ["ma Susana;", "and Susanna,"], ["atoa ma isi fafine e toatele,", "and many others,"], ["e na auauna atu ia te ia i a latou mea.", "which ministered unto him of their substance."]]},
  {num:4,words:[["Ua faapotopotoina mai le motu o tagata e toatele,", "And when much people were gathered together,"], ["ua o mai ia te ia mai lea aai ma lea aai,", "and were come to him out of every city,"], ["ona fetalai atu lea o ia le faataoto.", "he spake by a parable:"]]},
  {num:5,words:[["Ua alu atu le tagata lulu saito e lulu ai ana saito;", "A sower went out to sow his seed:"], ["ua ia lulu saito,", "and as he sowed,"], ["ua paū ai isi i le auala;", "some fell by the way side;"], ["ona solia lea,", "and it was trodden down,"], ["ua 'aina foi e manu felelei.", "and the fowls of the air devoured it."]]},
  {num:6,words:[["Ua paū isi i le mea papa;", "And some fell upon a rock;"], ["ua tupu,", "and as soon as it was sprung up,"], ["ona magumagu ai lea,", "it withered away,"], ["auā e le su.", "because it lacked moisture."]]},
  {num:7,words:[["A ua paū isi i le vao tuitui;", "And some fell among thorns;"], ["ua tutupu faatasi ia ma le vao tuitui,", "and the thorns sprang up with it,"], ["ona fetinaiina ai lea.", "and choked it."]]},
  {num:8,words:[["Ua paū foi isi i le eleele lelei;", "And other fell on good ground,"], ["ua tupu,", "and sprang up,"], ["ua fua mai taiselau i fua. Ua fetalai atu ia i nei mea,", "and bare fruit an hundredfold. And when he had said these things,"], ["ona alaga atu lea,", "he cried,"], ["O le ua i ai taliga e faalogo ai,", "He that hath ears to hear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
  {num:9,words:[["A ua fesili mai ona soo ia te ia,", "And his disciples asked him,"], ["ua faapea mai,", "saying,"], ["Se a ea le faataoto nei?", "What might this parable be?"]]},
  {num:10,words:[["Ona fetalai atu lea o ia,", "And he said,"], ["Ua foaiina atu ia te outou ina ia outou iloa mea lilo a le malo o le Atua;", "Unto you it is given to know the mysteries of the kingdom of God:"], ["a ua fai atu i nisi i faataoto;", "but to others in parables;"], ["ina ia latou le vaai i lo latou vaai,", "that seeing they might not see,"], ["ina ia le lagona foi i lo latou faalogo.", "and hearing they might not understand."]]},
  {num:11,words:[["O le faataoto lenei, O le saito,", "Now the parable is this:"], ["o le afioga lea a le Atua.", "The seed is the word of God."]]},
  {num:12,words:[["O e i le auala,", "Those by the way side are they that hear;"], ["o e faalogo ia;", "then cometh the devil,"], ["ona alu ane ai lea o le tiapolo, ma aveeseina le upu nai o latou loto,", "and taketh away the word out of their hearts,"], ["ne'i faatuatua ma faaolaina i latou.", "lest they should believe and be saved."]]},
  {num:13,words:[["O e i le mea papa,", "They on the rock are they,"], ["o i latou ia,", "which,"], ["pe a faalogo i le upu,", "when they hear,"], ["ua talia ma le fiafia; a e leai ni o latou aa,", "receive the word with joy;"], ["ua faaletumau lo latou faatuatua,", "and these have no root,"], ["ua oo atu i aso e faaosoosoina ai,", "which for a while believe,"], ["ona o ese ai lea.", "and in time of temptation fall away."]]},
  {num:14,words:[["O le mea na paū i le vao tuitui,", "And that which fell among thorns are they,"], ["o i latou ia e ua faalogo,", "which,"], ["ua o atu ai, ona fetinaiina ai lea i mea e popole ai,", "when they have heard,"], ["ma oloa,", "go forth,"], ["ma mea faafiafia o le olaga nei,", "and are choked with cares and riches and pleasures of this life,"], ["ona le oo lea ina matua o latou fua.", "and bring no fruit to perfection."]]},
  {num:15,words:[["Peitai o le mea na i le eleele lelei,", "But that on the good ground are they,"], ["o i latou ia e ua faalogo i le upu,", "which in an honest and good heart,"], ["ma tausi i ai i le loto ua faamaoni ma le lelei,", "having heard the word, keep it,"], ["ona fua mai ai lea ma le onosai.", "and bring forth fruit with patience."]]},
  {num:16,words:[["E leai se tagata na te tŭtŭ se lamepa,", "No man,"], ["ma ufiufi ai i le tanoa,", "when he hath lighted a candle,"], ["pe tuu i lalo o le moega;", "covereth it with a vessel, or putteth it under a bed;"], ["a e tuu i luga o le tuugālamepa,", "but setteth it on a candlestick,"], ["ina ia iloa atu le malamalama e i latou ua ulufale mai.", "that they which enter in may see the light."]]},
  {num:17,words:[["Auā e leai se mea lilo e le faaalia;", "For nothing is secret,"], ["e leai foi se mea natia e le faailoa,", "that shall not be made manifest; neither any thing hid,"], ["a e iu ina faaalia.", "that shall not be known and come abroad."]]},
  {num:18,words:[["O lenei,", "Take heed therefore how ye hear:"], ["ia outou, pe faapefea lo outou faalogo;", "for whosoever hath,"], ["auā o se ua i ai mea,", "to him shall be given;"], ["e foaiina mai ia te ia; a o se ua le i ai mea,", "and whosoever hath not,"], ["e aveeseina ia te ia o mea ua peiseai ua ia te ia.", "from him shall be taken even that which he seemeth to have."]]},
  {num:19,words:[["Ua o mai ia te ia lona tinā ma ona uso,", "Then came to him his mother and his brethren,"], ["a ua le masao mai ia te ia ona o le motu o tagata.", "and could not come at him for the press."]]},
  {num:20,words:[["Ua fai mai nisi ia te ia,", "And it was told him by certain which said,"], ["ua faapea mai, Ua tutū lou tinā ma ou uso i fafo,", "Thy mother and thy brethren stand without,"], ["ua fia feiloai ma oe.", "desiring to see thee."]]},
  {num:21,words:[["Ua tali atu ia, ua faapea atu ia te i latou,", "And he answered and said unto them,"], ["O e faalogo i le afioga a le Atua,", "My mother and my brethren are these which hear the word of God,"], ["ma latou faia, o lo'u tinā ma o'u uso lava ia.", "and do it."]]},
  {num:22,words:[["Ua maliu ae ia ma ona soo i le tasi aso i le vaa;", "Now it came to pass on a certain day,"], ["ua fetalai atu foi o ia ia te i latou,", "that he went into a ship with his disciples:"], ["Tatou o ia i le tasi itu vai,", "and he said unto them,"], ["ona latou tuuvaa atu lea.", "Let us go over unto the other side of the lake. And they launched forth."]]},
  {num:23,words:[["Ua alu lo latou vaa,", "But as they sailed he fell asleep:"], ["a e tofa o ia,", "and there came down a storm of wind on the lake;"], ["ona to ifo lea o le afā i le vai, ua osofia lo latou vaa ,", "and they were filled with water,"], ["ua tāli goto.", "and were in jeopardy."]]},
  {num:24,words:[["Ona latou o ane lea ua fafagu ia te ia,", "And they came to him,"], ["ua faapea mai,", "and awoke him,"], ["Le Alii e,", "saying, Master,"], ["le Alii e,", "master,"], ["o le a matou fano.", "we perish."], ["Ona tu lea o ia,", "Then he arose,"], ["ua vavao i le matagi ma peau o le vai;", "and rebuked the wind and the raging of the water:"], ["ona mavae ai lea,", "and they ceased,"], ["ua malū.", "and there was a calm."]]},
  {num:25,words:[["Ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["O ifea ea lo outou faatuatua? Ua matatau lava i latou ma ofo;", "Where is your faith? And they being afraid wondered,"], ["ua fetautalatala'i i latou,", "saying one to another,"], ["O ai ea lenei? auā ua fetalai o ia i le matagi ma le vai,", "What manner of man is this! for he commandeth even the winds and water,"], ["ona usiusitai ai lea ia te ia.", "and they obey him."]]},
  {num:26,words:[["Ua latou oo atu i le laueleele o Katara,", "And they arrived at the country of the Gadarenes,"], ["o le itu vai lea ua feagai ma Kalilaia.", "which is over against Galilee."]]},
  {num:27,words:[["Ua maliu ae ia i uta,", "And when he went forth to land,"], ["ona fetaiai lea ma ia o le tasi tagata mai le aai ua leva ona ia te ia o temoni,", "there met him out of the city a certain man,"], ["ua le ofu o ia,", "which had devils long time, and ware no clothes,"], ["ua le nofo foi i se fale,", "neither abode in any house,"], ["a o tuugamau.", "but in the tombs."]]},
  {num:28,words:[["Ua iloa mai e ia o Iesu,", "When he saw Jesus,"], ["ona alaga mai lea o ia,", "he cried out,"], ["ma faapaū mai i ona luma,", "and fell down before him,"], ["ua fai mai ia te ia ma le leo tele,", "and with a loud voice said,"], ["Se a lau na ia te au nei,", "What have I to do with thee,"], ["Iesu e,", "Jesus,"], ["o oe na le Alo o le Atua silisili ese? ou te aioi atu ia te oe,", "thou Son of God most high? I beseech thee,"], ["aua e te faatiga mai ia te au.", "torment me not."]]},
  {num:29,words:[["Auā na fetalai o ia i le agaga leaga e alu i fafo i le tagata.", "(For he had commanded the unclean spirit to come out of the man."], ["Auā na atu lasi ona pue ia te ia;", "For oftentimes it had caught him:"], ["ua fusifusia o ia i maea uamea,", "and he was kept bound with chains and in fetters;"], ["ma mea e faamau a'i vae ua leoleoina ai o ia, a ua motumotusia maea ia te ia,", "and he brake the bands,"], ["ona avea ai lea o ia e le temoni i le vao.)", "and was driven of the devil into the wilderness.)"]]},
  {num:30,words:[["Ua fesili atu Iesu ia te ia,", "And Jesus asked him,"], ["ua faapea atu,", "saying,"], ["O ai ea lou igoa? Ua fai mai o ia,", "What is thy name? And he said,"], ["O Lekeono;", "Legion:"], ["auā ua uluitino ia te ia temoni e toatele.", "because many devils were entered into him."]]},
  {num:31,words:[["Ua latou aioi mai ia te ia, aua le fetalai o ia ia te i latou e o i le fafā.", "And they besought him that he would not command them to go out into the deep."]]},
  {num:32,words:[["Sa i ai le lafu puaa e tele, sa tataa i le mauga;", "And there was there an herd of many swine feeding on the mountain:"], ["ua latou faanoi mai ia te ia ia tuu atu latou te uluitino i ai.", "and they besought him that he would suffer them to enter into them."], ["Ona tuu atu ai lea ia te i latou.", "And he suffered them."]]},
  {num:33,words:[["Ona o lea o temoni i fafo nai le tagata,", "Then went the devils out of the man,"], ["a ua uluitino i puaa;", "and entered into the swine:"], ["ona feosofi ifo lea o le lafu i le tofē i le vai,", "and the herd ran violently down a steep place into the lake,"], ["ua malelemo ai.", "and were choked."]]},
  {num:34,words:[["Ua iloa ē sa faga puaa i le mea ua faia,", "When they that fed them saw what was done,"], ["ona sosola ai lea,", "they fled,"], ["ua o atu ua tala atu i le aai ma ona faoa aai.", "and went and told it in the city and in the country."]]},
  {num:35,words:[["Ona latou o mai lea e matamata i le mea ua faia;", "Then they went out to see what was done;"], ["ua o mai ia Iesu,", "and came to Jesus,"], ["ua latou iloa atu le tagata ua o i fafo ia te ia temoni,", "and found the man,"], ["o loo nofo o ia i vae o Iesu;", "out of whom the devils were departed, sitting at the feet of Jesus,"], ["ua ofu ia,", "clothed,"], ["ma ua atamai;", "and in his right mind:"], ["ona latou matatau ai lea.", "and they were afraid."]]},
  {num:36,words:[["O e na iloa ua latou tala atu ia te i latou le mea na malolo ai le tagata sa uluitinoina.", "They also which saw it told them by what means he that was possessed of the devils was healed."]]},
  {num:37,words:[["Ona aioi mai lea ia te ia o le nuu uma o Katara,", "Then the whole multitude of the country of the Gadarenes round about besought him to depart from them;"], ["ina ia maliu ese o ia ia te i latou;", "for they were taken with great fear:"], ["auā ua oo ia te i latou le mata'u tele; ona maliu ae lea o ia i le vaa,", "and he went up into the ship,"], ["ua toe foi atu.", "and returned back again."]]},
  {num:38,words:[["Ua aioi mai ia te ia le tagata ua o i fafo ia te ia temoni,", "Now the man out of whom the devils were departed besought him that he might be with him:"], ["la te faatasi ma ia; a ua auina atu ia e Iesu,", "but Jesus sent him away,"], ["ua faapea atu,", "saying,"]]},
  {num:39,words:[["Ina foi atu ia oe i lou aiga,", "Return to thine own house,"], ["ma ia faamatala atu i mea tetele ua faia e le Atua ia te oe. Ona alu ai lea o ia,", "and shew how great things God hath done unto thee. And he went his way,"], ["ua tala'i i le aai uma i mea tetele na faia e Iesu ia te ia.", "and published throughout the whole city how great things Jesus had done unto him."]]},
  {num:40,words:[["Ua toe foi atu Iesu,", "And it came to pass, that,"], ["ona talia ai lea o ia e le motu o tagata;", "when Jesus was returned,"], ["auā sa faatali mai i latou uma ia te ia.", "the people gladly received him: for they were all waiting for him."]]},
  {num:41,words:[["Faauta foi,", "And,"], ["ua sau le tagata e igoa ia Iairo,", "behold,"], ["o ia foi le tasi e pule i le sunako;", "there came a man named Jairus, and he was a ruler of the synagogue:"], ["ua faapaū ia i vae o Iesu,", "and he fell down at Jesus' feet,"], ["ma faatoga mai ia te ia ia maliu atu o ia i lona fale;", "and besought him that he would come into his house:"]]},
  {num:42,words:[["auā o lona afafine e toatasi,", "For he had one only daughter,"], ["po ua sefulu ma le lua ona tausaga,", "about twelve years of age,"], ["o le a oti ia.", "and she lay a dying."], ["Ua maliu atu ia, a ua fetaomi mai ia te ia le motu o tagata.", "But as he went the people thronged him."]]},
  {num:43,words:[["O le fafine sa ia te ia le puna toto i tausaga e sefulu ma le lua,", "And a woman having an issue of blood twelve years,"], ["ua uma atu ana mea i fomai,", "which had spent all her living upon physicians,"], ["a ua le mafai ona malolo i se tasi,", "neither could be healed of any,"]]},
  {num:44,words:[["ua alu ane ia i ona tua,", "Came behind him,"], ["ma pa'i ane i le tuupao o lona ofu;", "and touched the border of his garment:"], ["ona utu loa lea o lona puna toto.", "and immediately her issue of blood stanched."]]},
  {num:45,words:[["Ona fetalai ane lea o Iesu,", "And Jesus said,"], ["O ai ea na na pa'i mai ia te au? Ua faafiti mai tagata uma,", "Who touched me? When all denied,"], ["ona fai mai lea o Peteru ma i latou sa faatasi ma ia,", "Peter and they that were with him said,"], ["Le Alii e,", "Master,"], ["ua fetaomi ma fetuleni mai le motu o tagata ia te oe,", "the multitude throng thee and press thee,"], ["e te fetalai mai ea,", "and sayest thou,"], ["O ai na pa'i mai ia te au?", "Who touched me?"]]},
  {num:46,words:[["Ua fetalai atu Iesu,", "And Jesus said,"], ["Na pa'i mai lava se tasi ia te au;", "Somebody hath touched me:"], ["auā ua ou iloa ua alu atu le mana nai ia te au.", "for I perceive that virtue is gone out of me."]]},
  {num:47,words:[["Ua iloa e le fafine ua le lilo o ia,", "And when the woman saw that she was not hid,"], ["ona alu atu lea o ia ma le gatete,", "she came trembling,"], ["ua faapaū mai i ona luma,", "and falling down before him,"], ["ma faamatala mai ia te ia i luma o le nuu uma le mea na pa'i atu ai o ia ia te ia,", "she declared unto him before all the people for what cause she had touched him,"], ["ma le faamaloloina loa o ia.", "and how she was healed immediately."]]},
  {num:48,words:[["Ona fetalai atu lea o ia ia te ia,", "And he said unto her,"], ["Lo'u afafine e,", "Daughter,"], ["ina faalototele ia oe;", "be of good comfort:"], ["ua e ola i lou faatuatua;", "thy faith hath made thee whole;"], ["ina alu ia oe ma le manuia.", "go in peace."]]},
  {num:49,words:[["Ua sau le tasi mai le fale o le pule i le sunako a o fetalai o ia,", "While he yet spake, there cometh one from the ruler of the synagogue's house,"], ["ua fai mai ia te ia. Ua oti lou afafine;", "saying to him,"], ["soia e te faalavelaveina le a'oa'o.", "Thy daughter is dead; trouble not the Master."]]},
  {num:50,words:[["Ua faafofoga i ai Iesu,", "But when Jesus heard it,"], ["ona tali atu lea o ia ia te ia,", "he answered him,"], ["ua faapea atu,", "saying,"], ["Aua e te fefe;", "Fear not:"], ["tau ina e faatuatua,", "believe only,"], ["e ola ai o ia.", "and she shall be made whole."]]},
  {num:51,words:[["Ua ulu atu ia i le fale,", "And when he came into the house,"], ["e le mafai ia te ia ona ulu atu se tasi,", "he suffered no man to go in,"], ["tau o Peteru,", "save Peter,"], ["ma Iakopo,", "and James,"], ["ma Ioane,", "and John,"], ["o le tamā foi ma le tinā o le teine.", "and the father and the mother of the maiden."]]},
  {num:52,words:[["Ua fetagisi i latou uma,", "And all wept,"], ["ma tagitu'i ona o ia;", "and bewailed her:"], ["a ua fetalai atu ia,", "but he said,"], ["Soia le fetagisi;", "Weep not;"], ["e lei oti o ia,", "she is not dead,"], ["a ua moe.", "but sleepeth."]]},
  {num:53,words:[["Ua latou tapisa ia te ia,", "And they laughed him to scorn,"], ["auā ua latou iloa ua oti o ia.", "knowing that she was dead."]]},
  {num:54,words:[["A o ia,", "And he put them all out,"], ["ua na tulia i latou uma i fafo,", "and took her by the hand,"], ["ona tago atu lea o ia i lona lima, ua valaau,", "and called,"], ["ua faapea atu,", "saying,"], ["Funa e,", "Maid,"], ["ina tulai ia.", "arise."]]},
  {num:55,words:[["Ua toe foi mai lona agaga,", "And her spirit came again,"], ["ona tulai loa lea o ia; ua fetalai atu foi o ia,", "and she arose straightway:"], ["ia avatu ni ana mea e 'ai.", "and he commanded to give her meat."]]},
  {num:56,words:[["Ona matuā ofo ai lea o ona mātua; a ua vavao o ia ia te i laua,", "And her parents were astonished:"], ["aua ne'i tala atu i se tasi le mea ua faia.", "but he charged them that they should tell no man what was done."]]},
];
renderVerseSet(luk_ch_8_Verses, 'luk-ch8-verses');

var luk_ch_9_Verses = [
  {num:1,words:[["Ua faapotopotoina e ia ona soo e toasefulu ma le toalua,", "Then he called his twelve disciples together,"], ["ua tuu atu ia te i latou le mana ma le pule i temoni uma,", "and gave them power and authority over all devils,"], ["ma ia faamalolo i ma'i.", "and to cure diseases."]]},
  {num:2,words:[["Ua aauina atu i latou e ia e tala'i i le malo o le Atua,", "And he sent them to preach the kingdom of God,"], ["e faamalolo foi i e mamai.", "and to heal the sick."]]},
  {num:3,words:[["Ua fetalai atu foi o ia ia te i latou,", "And he said unto them,"], ["Aua tou te ave se mea i le malaga,", "Take nothing for your journey,"], ["po o tootoo,", "neither staves,"], ["po o se taga,", "nor scrip,"], ["po o mea e 'ai,", "neither bread,"], ["po o se tupe,", "neither money;"], ["aua foi ne'i tailua ofu tino.", "neither have two coats apiece."]]},
  {num:4,words:[["O se fale foi tou te ulu atu i ai,", "And whatsoever house ye enter into, there abide,"], ["ia nonofo ai i le tou o ai lava.", "and thence depart."]]},
  {num:5,words:[["Ai se lē talia outou,", "And whosoever will not receive you,"], ["a outou o ese i lea aai, ia tūtū atu le eleele i o outou vae,", "when ye go out of that city,"], ["e fai ma molimau ia te i latou.", "shake off the very dust from your feet for a testimony against them."]]},
  {num:6,words:[["Ua latou o atu,", "And they departed,"], ["ona faataamilo ai lea i lea aai ma lea aai e folafola le tala lelei,", "and went through the towns, preaching the gospel,"], ["ma faamalolo i ma'i i mea uma.", "and healing every where."]]},
  {num:7,words:[["Ua faalogo le tupu o Herota i mea uma ua faia e ia,", "Now Herod the tetrarch heard of all that was done by him:"], ["ona fememeai lea o ia,", "and he was perplexed,"], ["ina ua fai mai nisi, Ua tu mai Ioane i e ua oti;", "because that it was said of some,"], ["a o isi,", "that John was risen from the dead;"]]},
  {num:8,words:[["Ua faaali mai Elia;", "And of some, that Elias had appeared;"], ["a o isi. Ua toe tu mai le tasi o le au perofeta anamua.", "and of others, that one of the old prophets was risen again."]]},
  {num:9,words:[["A ua fai ane Herota,", "And Herod said,"], ["Na ou vavaeeseina le ulu o Ioane;", "John have I beheaded: but who is this,"], ["a o ai lenei ua ou faalogo ai i mea faapena? Ua manao o ia i le fia vaai ia te ia.", "of whom I hear such things? And he desired to see him."]]},
  {num:10,words:[["Ua toe foi mai le au aposetolo,", "And the apostles,"], ["ma faamatala mai ia te ia mea uma ua latou faia;", "when they were returned,"], ["ona ave lea o ia ia te i latou, ua ō na o i latou i se mea gaogao o le nuu,", "told him all that they had done. And he took them,"], ["o Petesaita le igoa.", "and went aside privately into a desert place belonging to the city called Bethsaida."]]},
  {num:11,words:[["Ua iloa e le motu o tagata,", "And the people,"], ["ona latou mulimuli atu lea ia te ia;", "when they knew it,"], ["ona talia lea o i latou e ia,", "followed him: and he received them,"], ["ua fetalai foi ia te i latou i le malo o le Atua,", "and spake unto them of the kingdom of God,"], ["ma faamalolo i e na fia faamaloloina.", "and healed them that had need of healing."]]},
  {num:12,words:[["Ua taugagaifo le la,", "And when the day began to wear away,"], ["ona o mai lea ia te ia o le toasefulu ma le toalua,", "then came the twelve,"], ["ua fai mai. Ia e tuuina atu le motu o tagata,", "and said unto him,"], ["ina ia latou o atu i aai ma faoa aai ua latalata mai,", "Send the multitude away, that they may go into the towns and country round about,"], ["e api ai,", "and lodge,"], ["ma maua ai mea e 'ai;", "and get victuals:"], ["auā o le mea gaogao ua tatou i ai nei.", "for we are here in a desert place."]]},
  {num:13,words:[["A ua fetalai atu ia ia te i latou,", "But he said unto them,"], ["Ia outou avane ni mea e 'ai mā latou.", "Give ye them to eat."], ["Ona latou fai mai lea, E leai ni a tatou mea,", "And they said,"], ["na o areto e lima gafua,", "We have no more but five loaves and two fishes;"], ["ma i'a e lua lau; se'i iloga matou te o e faatau ni mea e 'ai mā lenei nuu uma.", "except we should go and buy meat for all this people."]]},
  {num:14,words:[["Auā o i latou pe toalima gaafe o tane.", "For they were about five thousand men."], ["Ua fetalai atu ia i ona soo, Ia outou fai atu ia te i latou ia taooto i vasega,", "And he said to his disciples,"], ["e taitoalimagafulu.", "Make them sit down by fifties in a company."]]},
  {num:15,words:[["Ua latou faapea lava ona fai,", "And they did so,"], ["ma fai atu ia te i latou uma ia taooto i lalo.", "and made them all sit down."]]},
  {num:16,words:[["Ona tago ai lea o ia i areto e lima gafua,", "Then he took the five loaves and the two fishes,"], ["ma i'a e lua lau, ua tepa ae i le lagi,", "and looking up to heaven,"], ["ua faafetai,", "he blessed them,"], ["ma tofitofi, ua avatu i ona soo,", "and brake,"], ["latou te laulau atu ai i le motu o tagata.", "and gave to the disciples to set before the multitude."]]},
  {num:17,words:[["Ua latou aai,", "And they did eat,"], ["ua maoona uma lava; ona fu'e lea o a latou toe 'aiga,", "and were all filled:"], ["ua tumu ato e sefulu ma le lua i fāsi mea.", "and there was taken up of fragments that remained to them twelve baskets."]]},
  {num:18,words:[["Ua tatalo toatasi o ia;", "And it came to pass,"], ["sa faatasi ma ia ona soo;", "as he was alone praying,"], ["ona fesili atu lea o ia ia te i latou,", "his disciples were with him: and he asked them,"], ["ua faapea atu,", "saying,"], ["Se a le upu a tagata ia te au po o ai?", "Whom say the people that I am?"]]},
  {num:19,words:[["Ua latou tali mai,", "They answering said,"], ["ua faapea mai,", "John the Baptist;"], ["O Ioane le papatiso; a o isi,", "but some say,"], ["o Elia;", "Elias;"], ["a o isi,", "and others say,"], ["Ua toe tu mai le tasi o le au perofeta anamua.", "that one of the old prophets is risen again."]]},
  {num:20,words:[["Ua fetalai atu ia ia te i latou, A o outou na,", "He said unto them,"], ["se a la outou upu ia te au nei po o ai? Ona tali mai lea o Peteru,", "But whom say ye that I am? Peter answering said,"], ["ua faapea mai, O oe o le Keriso o le Atua.", "The Christ of God."]]},
  {num:21,words:[["Ona vavao atu lea o ia ia te i latou, ua fetalai atu,", "And he straitly charged them,"], ["ne'i ta'uta'ua lea mea i se tasi; ua faapea atu,", "and commanded them to tell no man that thing;"]]},
  {num:22,words:[["E tatau ona tiga le Atalii o le tagata i mea e tele,", "Saying,"], ["ma ia lafoaiina e toeaina,", "The Son of man must suffer many things,"], ["ma faitaulaga sili, ma le au tusiupu,", "and be rejected of the elders and chief priests and scribes,"], ["ia fasiotia foi;", "and be slain,"], ["e faatuina foi o ia i le aso tolu.", "and be raised the third day."]]},
  {num:23,words:[["Ua fetalai atu ia i tagata uma,", "And he said to them all,"], ["A fia mulimuli mai se tasi ia te au,", "If any man will come after me,"], ["aua le usiusitai o ia ia te ia,", "let him deny himself,"], ["a ia ave e ia lona satauro i aso fai soo,", "and take up his cross daily,"], ["i le mulimuli mai ai ia te au.", "and follow me."]]},
  {num:24,words:[["Auā ai sē fia faasaogalemuina lona ola,", "For whosoever will save his life shall lose it:"], ["e māumau ai ia te ia; a o lē faamāumau i lona ola ona o a'u,", "but whosoever will lose his life for my sake,"], ["e faasaoina e ia.", "the same shall save it."]]},
  {num:25,words:[["Auā se a le aoga i le tagata pe afai na te maua le lalolagi uma,", "For what is a man advantaged,"], ["a e faamāumau e ia ia ia,", "if he gain the whole world, and lose himself,"], ["pe lafoaiina?", "or be cast away?"]]},
  {num:26,words:[["Auā ai se mā ia te au ma a'u upu,", "For whosoever shall be ashamed of me and of my words,"], ["e mā foi ia te ia le Atalii o le tagata,", "of him shall the Son of man be ashamed,"], ["pe a sau o ia i lona mamalu,", "when he shall come in his own glory,"], ["ma lo le tamā,", "and in his Father's,"], ["ma le au agelu paia.", "and of the holy angels."]]},
  {num:27,words:[["E moni,", "But I tell you of a truth,"], ["ou te fai atu ia te outou,", "there be some standing here,"], ["o loo tutū mai nisi iinei, e le oo ia te i latou le oti,", "which shall not taste of death,"], ["seia latou vaaia le malo o le Atua.", "till they see the kingdom of God."]]},
  {num:28,words:[["Ua mavae nei upu, po ua po valu,", "And it came to pass about an eight days after these sayings,"], ["ona ave lea e ia o Peteru, ma Ioane,", "he took Peter and John and James,"], ["ma Iakopo, ua maliu ae i le mauga e tatalo.", "and went up into a mountain to pray."]]},
  {num:29,words:[["O loo tatalo ia,", "And as he prayed,"], ["a ua liua ona fofoga,", "the fashion of his countenance was altered,"], ["ua pa'epa'e ma pupula tele mai ona ofu.", "and his raiment was white and glistering."]]},
  {num:30,words:[["Faauta foi,", "And,"], ["ua tautala ma ia o tagata e toalua,", "behold, there talked with him two men,"], ["o Mose ma Elia i laua,", "which were Moses and Elias:"]]},
  {num:31,words:[["o e na faaali mai ma le pupula;", "Who appeared in glory,"], ["ua latou fetautalatala'i i lona maliu o le a faaiuina i Ierusalema.", "and spake of his decease which he should accomplish at Jerusalem."]]},
  {num:32,words:[["A ua moe gagase Peteru ma e ua faatasi ma ia;", "But Peter and they that were with him were heavy with sleep:"], ["ua latou ala,", "and when they were awake,"], ["ona latou iloa lea o lona pupula,", "they saw his glory,"], ["ma tagata e toalua e ua tutu faatasi ma ia.", "and the two men that stood with him."]]},
  {num:33,words:[["Ua oo ina la o ese ia te ia,", "And it came to pass,"], ["ona fai mai lea o Peteru ia Iesu,", "as they departed from him,"], ["Le Alii e,", "Peter said unto Jesus,"], ["e lelei ina tatou nonofo iinei;", "Master,"], ["matou te faia foi ni fale apitaga se tolu;", "it is good for us to be here: and let us make three tabernacles;"], ["mo oe le tasi,", "one for thee,"], ["mo Mose le tasi,", "and one for Moses,"], ["mo Elia foi le tasi;", "and one for Elias:"], ["ua le iloa e ia le mea ua ia fai atu ai.", "not knowing what he said."]]},
  {num:34,words:[["O loo fai mai ia mea,", "While he thus spake,"], ["a e oo mai le ao,", "there came a cloud,"], ["ma ufitia i latou;", "and overshadowed them:"], ["ua latou matatau ina a oo mai le ao.", "and they feared as they entered into the cloud."]]},
  {num:35,words:[["Ona oo mai lea o le siufofoga mai le ao,", "And there came a voice out of the cloud,"], ["ua faapea mai,", "saying,"], ["O lo'u Atalii pele lena;", "This is my beloved Son:"], ["ia outou faalogo ia te ia.", "hear him."]]},
  {num:36,words:[["Ua mavae atu le siufofoga,", "And when the voice was past,"], ["ona iloa mai lea na o Iesu. Latou te lei gagana lava,", "Jesus was found alone. And they kept it close,"], ["e lei ta'u atu foi i se tasi i ia ona aso se mea e tasi o mea ua latou vaai i ai.", "and told no man in those days any of those things which they had seen."]]},
  {num:37,words:[["O le taeao ua latou o ifo ai i le mauga,", "And it came to pass, that on the next day,"], ["ona fetaiai lea ma ia o le motu o tagata e toatele.", "when they were come down from the hill, much people met him."]]},
  {num:38,words:[["Faauta foi,", "And,"], ["ua alaga mai le tasi mai le motu o tagata,", "behold,"], ["ua faapea mai,", "a man of the company cried out,"], ["Le a'oa'o e,", "saying, Master,"], ["ou te aioi atu ia te oe,", "I beseech thee,"], ["e te silasila mai i lo'u atalii;", "look upon my son:"], ["auā o ia lo'u atalii toatasi.", "for he is mine only child."]]},
  {num:39,words:[["Faauta foi,", "And,"], ["ua pue ia te ia e le agaga,", "lo,"], ["ona alaga loa lea, ma faataafiti ia te ia,", "a spirit taketh him,"], ["ma ua fāuā lona gutu,", "and he suddenly crieth out;"], ["ua tu'i fulifuli ia te ia,", "and it teareth him that he foameth again,"], ["toe ina le alu ese ia te ia.", "and bruising him hardly departeth from him."]]},
  {num:40,words:[["Na ou aioi atu foi i ou soo ia latou tuli ia te ia i fafo;", "And I besought thy disciples to cast him out;"], ["a ua le mafai lava ia te i latou.", "and they could not."]]},
  {num:41,words:[["Ua tali atu Iesu,", "And Jesus answering said,"], ["ua faapea atu,", "O faithless and perverse generation,"], ["Le tupulaga lē faatuatua ma le faapiopio, ou te i ai ia te outou,", "how long shall I be with you,"], ["ma onosai ia te outou seia afea? Ina au mai ia lou atalii iinei.", "and suffer you? Bring thy son hither."]]},
  {num:42,words:[["O loo sau ia,", "And as he was yet a coming, the devil threw him down,"], ["a e lafotu ma faataafiti ia te ia e le temoni.", "and tare him."], ["Ona vavao lea e Iesu i le agaga leaga,", "And Jesus rebuked the unclean spirit,"], ["ma ua faamalolo i le tama,", "and healed the child,"], ["ma toe tuu atu ia te ia i lona tamā.", "and delivered him again to his father."]]},
  {num:43,words:[["Ua latou matuā ofo uma i le vavega o le Atua. O loo ofo i latou uma i mea uma na faia e Iesu,", "And they were all amazed at the mighty power of God. But while they wondered every one at all things which Jesus did,"], ["ona fetalai atu lea o ia i ona soo,", "he said unto his disciples,"]]},
  {num:44,words:[["Ia outou matuā faalogologo i nei upu,", "Let these sayings sink down into your ears:"], ["auā o le a tuuina atu le Atalii o le tagata i lima o tagata.", "for the Son of man shall be delivered into the hands of men."]]},
  {num:45,words:[["A ua le iloa e i latou lea upu,", "But they understood not this saying,"], ["ua lilo ia te i latou,", "and it was hid from them,"], ["o lea na latou le lagona ai lea mea;", "that they perceived it not:"], ["ua latou matatau foi e fesili ia te ia i lea upu.", "and they feared to ask him of that saying."]]},
  {num:46,words:[["Ua tupu le finauga ia te i latou,", "Then there arose a reasoning among them,"], ["po o ai so latou e sili.", "which of them should be greatest."]]},
  {num:47,words:[["Ua silafia e Iesu le manatu o latou loto,", "And Jesus,"], ["ona tago lea o ia i le tama itiiti,", "perceiving the thought of their heart, took a child,"], ["ma faatu ia te ia i ona tafatafa.", "and set him by him,"]]},
  {num:48,words:[["Ua fetalai atu o ia ia te i latou,", "And said unto them,"], ["Ai sē talia lenei tama itiiti i lo'u igoa, ua talia a'u e ia;", "Whosoever shall receive this child in my name receiveth me:"], ["ai sē talia foi a'u,", "and whosoever shall receive me receiveth him that sent me:"], ["ua talia e ia le na auina mai a'u; auā o le aupito itiiti ia te outou uma,", "for he that is least among you all,"], ["e sili lava ia.", "the same shall be great."]]},
  {num:49,words:[["Ona fai mai lea o Ioane,", "And John answered and said,"], ["ua faapea mai,", "Master,"], ["Le Alii e, na matou iloa le tasi na ia tulia temoni i lou suafa;", "we saw one casting out devils in thy name;"], ["ona matou vavao lea ia te ia,", "and we forbad him,"], ["auā ua ia le mulimuli mai ia te i tatou.", "because he followeth not with us."]]},
  {num:50,words:[["Ona fetalai atu lea o Iesu ia te ia,", "And Jesus said unto him,"], ["Aua tou te vaoia; auā o le lē 'au ese ia te i tatou,", "Forbid him not:"], ["e 'au faatasi lea ma i tatou.", "for he that is not against us is for us."]]},
  {num:51,words:[["Ua oo atu i ona po e siitia ai o ia,", "And it came to pass, when the time was come that he should be received up,"], ["ona matuā faasaga atu lea o ia a maliu atu i Ierusalema;", "he stedfastly set his face to go to Jerusalem,"]]},
  {num:52,words:[["ua aauina atu e ia nisi e muamua atu i le feau;", "And sent messengers before his face: and they went,"], ["ua latou o atu ma afe i le tasi aai o Samaria e sauni ai mo ia.", "and entered into a village of the Samaritans, to make ready for him."]]},
  {num:53,words:[["A ua le talia o ia e i latou,", "And they did not receive him,"], ["auā ua faasaga atu lana malaga i Ierusalema.", "because his face was as though he would go to Jerusalem."]]},
  {num:54,words:[["Ua iloa e ona soo o Iakopo ma Ioane,", "And when his disciples James and John saw this,"], ["ona la fai mai lea,", "they said,"], ["Le Alii e, pe e te finagalo,", "Lord,"], ["ma te fai atu ia alu ifo le afi mai le lagi,", "wilt thou that we command fire to come down from heaven,"], ["ia fano ai i latou,", "and consume them,"], ["pei ona faia e Elia?", "even as Elias did?"]]},
  {num:55,words:[["A ua fāliu o ia,", "But he turned,"], ["ma aoai ia te i laua,", "and rebuked them,"], ["ua faapea atu,", "and said,"], ["E le iloa e oulua le uiga o oulua loto;", "Ye know not what manner of spirit ye are of."]]},
  {num:56,words:[["auā e lei sau le Atalii o le tagata e faaumatia le ola o tagata,", "For the Son of man is not come to destroy men's lives,"], ["a ia faaolaina. Ona latou o atu lea i le tasi aai.", "but to save them. And they went to another village."]]},
  {num:57,words:[["Ua latou o i le ala,", "And it came to pass, that,"], ["ona fai mai lea o le tasi ia te ia,", "as they went in the way,"], ["Le Alii e,", "a certain man said unto him,"], ["ou te mulimuli atu ia te oe i mea uma e te maliu atu i ai.", "Lord, I will follow thee whithersoever thou goest."]]},
  {num:58,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "And Jesus said unto him,"], ["E fai lua o alope,", "Foxes have holes,"], ["e fai foi mea e momoe ai manu felelei; a o le Atalii o le tagata,", "and birds of the air have nests;"], ["e leai se mea e moe ai o ia.", "but the Son of man hath not where to lay his head."]]},
  {num:59,words:[["Ua fetalai atu ia i le tasi,", "And he said unto another,"], ["Ina mulimuli mai ia ia te au.", "Follow me."], ["A ua fai mai o ia,", "But he said,"], ["Le Alii e, tuu mai ia ia te au,", "Lord,"], ["se'i ou alu e muai tanu i lo'u tamā.", "suffer me first to go and bury my father."]]},
  {num:60,words:[["A ua fetalai atu Iesu ia te ia,", "Jesus said unto him,"], ["Ina tuu pea ia i e ua oti e tanu i o latou tagata oti; a o oe,", "Let the dead bury their dead:"], ["e te alu ma tala'i atu le malo o le Atua.", "but go thou and preach the kingdom of God."]]},
  {num:61,words:[["Ua fai mai foi le tasi,", "And another also said,"], ["Le Alii e,", "Lord,"], ["ou te mulimuli atu ia te oe;", "I will follow thee;"], ["a ia tuu mai ia te au,", "but let me first go bid them farewell,"], ["se'i ou muai faamavae i lo'u aiga.", "which are at home at my house."]]},
  {num:62,words:[["Ua fetalai atu Iesu ia te ia,", "And Jesus said unto him,"], ["O lē tago lona lima i le suotosina,", "No man,"], ["ma tepa i tua,", "having put his hand to the plough, and looking back,"], ["e le tatau ia i le malo o le Atua.", "is fit for the kingdom of God."]]},
];
renderVerseSet(luk_ch_9_Verses, 'luk-ch9-verses');

var luk_ch_10_Verses = [
  {num:1,words:[["Mulimuli ane ua tofia e le Alii nisi e toafitugafulu,", "After these things the Lord appointed other seventy also,"], ["ua aauina atu o i latou e taitoalua ua muamua atu ia te ia,", "and sent them two and two before his face into every city and place,"], ["i aai uma ma mea uma o le a maliu atu i ai o ia.", "whither he himself would come."]]},
  {num:2,words:[["Ua fetalai atu foi o ia ia te i latou,", "Therefore said he unto them,"], ["E tele le saito e seleseleina,", "The harvest truly is great,"], ["a o le au faigaluega e toaitiiti ia;", "but the labourers are few:"], ["o lea ia outou aioi ai i le Alii e ana le saito e seleseleina,", "pray ye therefore the Lord of the harvest,"], ["ina ia aauina mai e ia ni e galulue i lana saito e seleseleina.", "that he would send forth labourers into his harvest."]]},
  {num:3,words:[["Ina o atu ia,", "Go your ways:"], ["faauta,", "behold,"], ["ou te aauina atu outou pei o tamai mamoe i le va o luko.", "I send you forth as lambs among wolves."]]},
  {num:4,words:[["Aua tou te ave se ete tupe,", "Carry neither purse,"], ["po o se taga,", "nor scrip,"], ["po o seevae;", "nor shoes:"], ["aua foi tou te ofo alofa atu i se tasi i le ala.", "and salute no man by the way."]]},
  {num:5,words:[["O le fale tou te ulu atu i ai,", "And into whatsoever house ye enter,"], ["tou te muai fai atu,", "first say,"], ["Ia manuia le aiga nei.", "Peace be to this house."]]},
  {num:6,words:[["Pe afai o i ai le tagata o le manuia,", "And if the son of peace be there,"], ["e oo atu ia te ia la outou faamanuia;", "your peace shall rest upon it:"], ["a leai,", "if not,"], ["e toe foi mai ai ia te outou.", "it shall turn to you again."]]},
  {num:7,words:[["Ia outou nonofo i lea fale,", "And in the same house remain,"], ["ma aai ma inu i mea latou te avane;", "eating and drinking such things as they give:"], ["auā e tatau ona avatu i le faigaluega lona taui. Aua tou te feoai i lea fale ma lea fale.", "for the labourer is worthy of his hire. Go not from house to house."]]},
  {num:8,words:[["O le aai tou te oo atu i ai,", "And into whatsoever city ye enter,"], ["ua latou talia foi outou,", "and they receive you,"], ["ia outou aai i mea e laulauina mai ia te outou;", "eat such things as are set before you:"]]},
  {num:9,words:[["ia outou faamalolo foi i e mamai o i ai,", "And heal the sick that are therein,"], ["ma ia fai atu ia te i latou,", "and say unto them,"], ["Ua latalata ia te outou le malo o le Atua.", "The kingdom of God is come nigh unto you."]]},
  {num:10,words:[["A o le aai tou te oo atu i ai,", "But into whatsoever city ye enter,"], ["ua latou le talia foi outou,", "and they receive you not,"], ["tou te o ai i o latou malae,", "go your ways out into the streets of the same,"], ["ma faapea atu,", "and say,"]]},
  {num:11,words:[["O le eleele lava mai la outou aai,", "Even the very dust of your city,"], ["ua pipii mai ia te i matou,", "which cleaveth on us,"], ["matou te sōloi atu ia te outou;", "we do wipe off against you:"], ["a e peitai ia outou iloa lenei mea,", "notwithstanding be ye sure of this,"], ["ua latalata ia te outou le malo o le Atua.", "that the kingdom of God is come nigh unto you."]]},
  {num:12,words:[["Ou te fai atu ia te outou,", "But I say unto you, that it shall be more tolerable in that day for Sodom,"], ["O lea aso e feoloolo ai Sotoma i lea lava aai.", "than for that city."]]},
  {num:13,words:[["Oi talofa ia te oe Koasini! oi talofa ia te oe Petesaita! auā ana faia i Turo ma Saitonu o vavega ua faia ia te outou,", "Woe unto thee, Chorazin! woe unto thee, Bethsaida! for if the mighty works had been done in Tyre and Sidon,"], ["po ua leva ona latou salamo o nonofo i le ie talatala ma le lefulefu.", "which have been done in you, they had a great while ago repented, sitting in sackcloth and ashes."]]},
  {num:14,words:[["A e feoloolo Turo ma Saitonu i le faamasinoga ia te outou.", "But it shall be more tolerable for Tyre and Sidon at the judgment, than for you."]]},
  {num:15,words:[["O oe foi Kapanaumi,", "And thou,"], ["ua faaeaina e oo i le lagi,", "Capernaum, which art exalted to heaven,"], ["e lafotuina oe i lalo lava i seoli.", "shalt be thrust down to hell."]]},
  {num:16,words:[["O lē faalogo ia te outou, ua faalogo o ia ia te au;", "He that heareth you heareth me;"], ["o lē faaleaoga ia te outou, ua ia faaleaoga ia te au;", "and he that despiseth you despiseth me;"], ["o lē faaleaoga foi ia te au, ua ia faaleaoga i le na auina mai a'u.", "and he that despiseth me despiseth him that sent me."]]},
  {num:17,words:[["Ua toe foi mai le toafitugafulu ma le olioli,", "And the seventy returned again with joy,"], ["ua faapea mai. Le Alii e,", "saying,"], ["ua usiusitai mai temoni ia te i matou,", "Lord,"], ["ona o lou suafa.", "even the devils are subject unto us through thy name."]]},
  {num:18,words:[["Ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["Na ou iloa Satani ua paū mai le lagi pei o le uila.", "I beheld Satan as lightning fall from heaven."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["ou te foai ia te outou le pule e soli ai gata ma akarava ma le malosi uma o le fili;", "I give unto you power to tread on serpents and scorpions, and over all the power of the enemy:"], ["e leai lava se mea e leaga ai outou.", "and nothing shall by any means hurt you."]]},
  {num:20,words:[["A e peitai aua tou te olioli i lenei mea,", "Notwithstanding in this rejoice not,"], ["ina ua usiusitai agaga ia te outou;", "that the spirits are subject unto you;"], ["na o lenei tou te olioli ai,", "but rather rejoice,"], ["ina ua tusia o outou igoa i le lagi.", "because your names are written in heaven."]]},
  {num:21,words:[["O lea lava itu aso ua matuā fiafia ai le finagalo o Iesu,", "In that hour Jesus rejoiced in spirit,"], ["ua faapea atu. Ou te faafetai ia te oe lo'u Tamā e,", "and said, I thank thee,"], ["o le Alii o le lagi ma le lalolagi,", "O Father,"], ["ina ua e nanā ia mea i e popoto ma e atamamai,", "Lord of heaven and earth, that thou hast hid these things from the wise and prudent,"], ["a ua faaalia atu ia mea i tama valevale;", "and hast revealed them unto babes:"], ["o lea lava lo'u Tamā,", "even so, Father;"], ["auā o lou finagalo lava lea.", "for so it seemed good in thy sight."]]},
  {num:22,words:[["Ua tuuina mai mea uma ia te au e lo'u Tamā;", "All things are delivered to me of my Father:"], ["e leai se tasi ua iloa le Atalii,", "and no man knoweth who the Son is,"], ["ua na o le Tamā;", "but the Father;"], ["e leai foi se tasi ua iloa le Tamā,", "and who the Father is,"], ["ua na o le Atalii,", "but the Son,"], ["ma se ua loto le Atalii e faaali atu i ai.", "and he to whom the Son will reveal him."]]},
  {num:23,words:[["Ua fāliu ia i ona soo,", "And he turned him unto his disciples,"], ["ma fetalai lemu ane,", "and said privately,"], ["Amuia mata ua iloa mea tou te iloa;", "Blessed are the eyes which see the things that ye see:"]]},
  {num:24,words:[["auā ou te fai atu ia te outou,", "For I tell you,"], ["e toatele perofeta ma tupu na fia matamata i nei mea ua outou iloa,", "that many prophets and kings have desired to see those things which ye see,"], ["a ua latou le iloa lava;", "and have not seen them;"], ["na latou fia faalogo foi i nei mea ua outou faalogo ai,", "and to hear those things which ye hear,"], ["a e lei faalogo ai lava.", "and have not heard them."]]},
  {num:25,words:[["Faauta foi,", "And,"], ["ua tulai le tasi a'oa'o tulafono,", "behold,"], ["ma tofotofo ia te ia,", "a certain lawyer stood up, and tempted him,"], ["ua faapea mai,", "saying,"], ["Le a'oa'o e,", "Master,"], ["se a se mea ou te faia ina ia ou maua ai le ola e faavavau?", "what shall I do to inherit eternal life?"]]},
  {num:26,words:[["Ua fetalai atu ia ia te ia,", "He said unto him,"], ["O le a ea ua tusia i le tulafono? O le a lau faitau?", "What is written in the law? how readest thou?"]]},
  {num:27,words:[["Ua tali mai o ia,", "And he answering said,"], ["ua faapea mai, E te alofa atu i le Alii lou Atua ma lou loto atoa,", "Thou shalt love the Lord thy God with all thy heart,"], ["ma lou agaga atoa,", "and with all thy soul,"], ["ma lou malosi atoa,", "and with all thy strength,"], ["ma lou manatu atoa; e te alofa atu foi i lē lua te tuaoi,", "and with all thy mind;"], ["ia pei o oe lava ia te oe.", "and thy neighbour as thyself."]]},
  {num:28,words:[["Ona faapea atu lea o ia ia te ia,", "And he said unto him,"], ["Ua tonu lau tali;", "Thou hast answered right:"], ["ia e faapea ona fai,", "this do,"], ["e te ola ai.", "and thou shalt live."]]},
  {num:29,words:[["A ua faafiatonu o ia,", "But he, willing to justify himself,"], ["ua fai mai ia Iesu. O ai foi le tagata ma te tuaoi?", "said unto Jesus, And who is my neighbour?"]]},
  {num:30,words:[["Ua tali atu Iesu,", "And Jesus answering said,"], ["ua faapea atu, O le tasi tagata na alu ifo mai Ierusalema i Ieriko,", "A certain man went down from Jerusalem to Jericho,"], ["ua maua o ia e tagata fao mea;", "and fell among thieves,"], ["ua latou toeseina ona ofu,", "which stripped him of his raiment,"], ["ma fasi ia te ia,", "and wounded him,"], ["ua latou o, ua tuua ia,", "and departed,"], ["ua tāli oti.", "leaving him half dead."]]},
  {num:31,words:[["Ua soona alu ifo le tasi faitaulaga i lea ala;", "And by chance there came down a certain priest that way:"], ["ua iloa atu ia te ia,", "and when he saw him,"], ["ona ui ane lea o ia i le tasi itu ala.", "he passed by on the other side."]]},
  {num:32,words:[["Ua faapea a foi le sa Levī,", "And likewise a Levite,"], ["ua oo i lea mea,", "when he was at the place,"], ["ua alu ane, ma matamata ai;", "came and looked on him,"], ["ona ui ane foi lea o ia i le tasi itu ala.", "and passed by on the other side."]]},
  {num:33,words:[["A o le tasi Samaria ua alu lana malaga,", "But a certain Samaritan,"], ["ua oo atu i le mea o i ai o ia,", "as he journeyed,"], ["ua iloa o ia,", "came where he was: and when he saw him,"], ["ona mutimuti vale lea o lona alofa;", "he had compassion on him,"]]},
  {num:34,words:[["ua alu atu,", "And went to him,"], ["ma nonoa i ona manua,", "and bound up his wounds,"], ["ua liligi foi i ai le suāuu ma le uaina;", "pouring in oil and wine,"], ["ua faatietie ia te ia i lana lava manu,", "and set him on his own beast,"], ["ma ta'ita'i ia te ia i le fale e tali ai malo,", "and brought him to an inn,"], ["ma tausi ia te ia.", "and took care of him."]]},
  {num:35,words:[["O le taeao o le a alu ia,", "And on the morrow when he departed,"], ["ona to ae lea o tenari e lua,", "he took out two pence, and gave them to the host,"], ["ma avatu i le matai e ona le fale,", "and said unto him,"], ["ua fai atu ia te ia. Ina e tausi ia te ia;", "Take care of him;"], ["ai se mea e te toe faatau ai,", "and whatsoever thou spendest more, when I come again,"], ["ou te taui atu ia te oe pe a ou toe sau.", "I will repay thee."]]},
  {num:36,words:[["Pe ni a fa te oe,", "Which now of these three, thinkest thou,"], ["o ai so latou nei o le toatolu ua fai ma tagata la te tuaoi ma le na maua e tagata fao mea?", "was neighbour unto him that fell among the thieves?"]]},
  {num:37,words:[["Ua fai mai ia,", "And he said,"], ["O le na alofa atu ia te ia. Ona faapea atu ai lea o Iesu ia te ia. Ina alu ia,", "He that shewed mercy on him. Then said Jesus unto him, Go,"], ["ma ia e faapea ona fai.", "and do thou likewise."]]},
  {num:38,words:[["Ua latou o,", "Now it came to pass,"], ["ona afe atu lea o ia i le tasi aai;", "as they went,"], ["o le tasi fafine foi e igoa ia Mareta,", "that he entered into a certain village:"], ["ua na talia o ia i lona fale.", "and a certain woman named Martha received him into her house."]]},
  {num:39,words:[["O lona uso foi e igoa ia Maria,", "And she had a sister called Mary,"], ["ua nofo o ia i lalo i tafatafa o vae o Iesu,", "which also sat at Jesus' feet,"], ["ma faalogo i lana fetalaiga.", "and heard his word."]]},
  {num:40,words:[["A ua tiga Mareta i le fatuaiga,", "But Martha was cumbered about much serving,"], ["ua tu mai, ma faapea mai,", "and came to him,"], ["Le Alii e,", "and said,"], ["e te le manatu mai ea, ina ua tuu mai e lo'u uso ia te au e sauni toatasi? ia e fetalai ane ia te ia,", "Lord,"], ["ia fesoasoani mai ia te au.", "dost thou not care that my sister hath left me to serve alone? bid her therefore that she help me."]]},
  {num:41,words:[["A ua tali atu Iesu, ua faapea atu ia te ia,", "And Jesus answered and said unto her,"], ["Mareta e,", "Martha,"], ["Mareta e,", "Martha,"], ["ua e popole, ma ua pŭpŭ lou loto i mea e tele;", "thou art careful and troubled about many things:"]]},
  {num:42,words:[["a o le mea lava e tasi e ao ina ia maua;", "But one thing is needful:"], ["ua filifilia foi e Maria lea mea lelei,", "and Mary hath chosen that good part,"], ["e le aveeseina ia te ia.", "which shall not be taken away from her."]]},
];
renderVerseSet(luk_ch_10_Verses, 'luk-ch10-verses');

var luk_ch_11_Verses = [
  {num:1,words:[["Sa i le tasi mea o ia,", "And it came to pass,"], ["ua tatalo,", "that,"], ["ua uma,", "as he was praying in a certain place,"], ["ona fai mai lea ia te ia o le tasi o lona au soo,", "when he ceased, one of his disciples said unto him,"], ["Le Alii e,", "Lord,"], ["ia e a'oa'o mai ia te i matou i tatalo;", "teach us to pray,"], ["e faapei o Ioane foi ona a'oa'o i ona soo.", "as John also taught his disciples."]]},
  {num:2,words:[["Ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["Pe a outou tatalo,", "When ye pray,"], ["ia outou fai atu,", "say,"], ["Lo matou Tamā e o i le lagi,", "Our Father which art in heaven,"], ["ia paia lou suafa.", "Hallowed be thy name."], ["Ia oo mai lou malo.", "Thy kingdom come."], ["Ia faia lou finagalo i le lalolagi,", "Thy will be done, as in heaven,"], ["e pei ona faia i le lagi.", "so in earth."]]},
  {num:3,words:[["Ia e foai mai ia te i matou i lea aso ma lea aso a matou mea e 'ai e tatau ma le aso.", "Give us day by day our daily bread."]]},
  {num:4,words:[["Ia e faamagalo ia te i matou i a matou agasala;", "And forgive us our sins;"], ["auā foi matou te faamagaloina atu ia i latou uma o e agaleaga mai ia te i matou. Aua foi e te taitaiina i matou i le tofotofoga;", "for we also forgive every one that is indebted to us. And lead us not into temptation;"], ["a ia e laveai mai ia i matou ai le leaga.", "but deliver us from evil."]]},
  {num:5,words:[["Ua fetalai atu foi o ia ia te i latou,", "And he said unto them,"], ["O ai so outou e ana le uo,", "Which of you shall have a friend,"], ["e alu atu ia te ia i le tulua o po, ma fai atu ia te ia,", "and shall go unto him at midnight,"], ["Sole,", "and say unto him,"], ["se'i au mai ni areto e tolu gafua,", "Friend,"], ["a e taui atu;", "lend me three loaves;"]]},
  {num:6,words:[["auā ua sau la'u uo ia te au i lana malaga,", "For a friend of mine in his journey is come to me,"], ["a e leai ni a'u mea e laulau atu i ai;", "and I have nothing to set before him?"]]},
  {num:7,words:[["e tali mai o ia mai totonu o le fale,", "And he from within shall answer and say,"], ["ua faapea mai,", "Trouble me not:"], ["Aua e te faasoesa mai ia te au; ua uma ona pupuni o le faitotoa,", "the door is now shut,"], ["ua matou taooto ma la'u fanau;", "and my children are with me in bed;"], ["ou te le mafai ona tulai e avatu mā oe.", "I cannot rise and give thee."]]},
  {num:8,words:[["Ou te fai atu ia te outou, E ui lava ina le tulai o ia,", "I say unto you,"], ["ma avatu ia te ia, ona o ia o lana uo,", "Though he will not rise and give him,"], ["a e tulai,", "because he is his friend,"], ["ma avatu mea uma e manao ai o ia, ona o lana faatauanau ane.", "yet because of his importunity he will rise and give him as many as he needeth."]]},
  {num:9,words:[["Ou te fai atu foi a'u ia te outou,", "And I say unto you,"], ["Ia outou ole atu,", "Ask,"], ["ona foaiina mai ai lea ia te outou;", "and it shall be given you;"], ["ia outou saili,", "seek,"], ["ona outou maua ai lea;", "and ye shall find;"], ["ia outou tu'itu'i atu,", "knock,"], ["ona toina mai ai lea ia te outou.", "and it shall be opened unto you."]]},
  {num:10,words:[["Auā ai se ole atu, e maua e ia;", "For every one that asketh receiveth;"], ["o lē saili, e iloa e ia;", "and he that seeketh findeth;"], ["o lē tu'itu'i, e toina mai ia te ia.", "and to him that knocketh it shall be opened."]]},
  {num:11,words:[["O ai se tamā ia te outou e avatu ea e ia i lona atalii se maa,", "If a son shall ask bread of any of you that is a father,"], ["pe a ole mai se areto? pe a ole mai se i'a,", "will he give him a stone? or if he ask a fish,"], ["e avatu ea ia te ia se gata a e le o se i'a?", "will he for a fish give him a serpent?"]]},
  {num:12,words:[["pe a ole mai se fuāmoa,", "Or if he shall ask an egg,"], ["e avatu ea ia te ia se akarava?", "will he offer him a scorpion?"]]},
  {num:13,words:[["O lenei,", "If ye then,"], ["o outou e leaga,", "being evil,"], ["afai ua iloa e outou ona avatu o mea lelei mā a outou fanau;", "know how to give good gifts unto your children:"], ["e le sili ea ona foaiina mai e lo outou Tamā o i le lagi le Agaga Paia i e ole atu ai ia te ia?", "how much more shall your heavenly Father give the Holy Spirit to them that ask him?"]]},
  {num:14,words:[["Sa tuli e ia le temoni,", "And he was casting out a devil,"], ["ua gūgū foi o ia;", "and it was dumb. And it came to pass,"], ["ua alu i fafo le temoni,", "when the devil was gone out,"], ["ona gagana ai lea o le gūgū,", "the dumb spake;"], ["ua ofo ai lava le motu o tagata.", "and the people wondered."]]},
  {num:15,words:[["Peitai o isi o i latou ua fai ane, O Pelesepulo le alii o temoni,", "But some of them said,"], ["ua tulia ai e ia o temoni.", "He casteth out devils through Beelzebub the chief of the devils."]]},
  {num:16,words:[["O isi foi ua faaosooso,", "And others, tempting him,"], ["ua saili mai ia te ia se faailoga mai le lagi.", "sought of him a sign from heaven."]]},
  {num:17,words:[["A ua silafia e ia o latou manatu,", "But he,"], ["ona fetalai atu lea ia te i latou,", "knowing their thoughts,"], ["O malo uma e fevaevaeai, e faaumatia ia;", "said unto them,"], ["po o se aiga e fevaevaeai,", "Every kingdom divided against itself is brought to desolation;"], ["e malaia lea.", "and a house divided against a house falleth."]]},
  {num:18,words:[["Afai foi e fevaevaeai Satani, pe faapefea ea ona tumau o lona malo? auā ua outou fai mai,", "If Satan also be divided against himself,"], ["o Pelesepulo e tulia ai e a'u o temoni.", "how shall his kingdom stand? because ye say that I cast out devils through Beelzebub."]]},
  {num:19,words:[["Afai o Pelesepulo e tulia ai e a'u o temoni, ia,", "And if I by Beelzebub cast out devils,"], ["po ai e tulia ai temoni e a outou fanau? o lea, e fai ai i latou ma faamasino ia te outou.", "by whom do your sons cast them out? therefore shall they be your judges."]]},
  {num:20,words:[["A e afai o le aao o le Atua ou te tulia ai temoni,", "But if I with the finger of God cast out devils,"], ["ua oo mai lava ia te outou le malo o le Atua.", "no doubt the kingdom of God is come upon you."]]},
  {num:21,words:[["A leoleoina e le tagata malosi ma lana auupega lona fale,", "When a strong man armed keepeth his palace,"], ["ona saogalemu ai lea o ana mea.", "his goods are in peace:"]]},
  {num:22,words:[["A e afai e oso atu ia te ia le tasi e sili lona malosi ia te ia,", "But when a stronger than he shall come upon him,"], ["ua manumalo i ai,", "and overcome him,"], ["ona fao ai lea o lana auupega uma na ia faatuatua i ai,", "he taketh from him all his armour wherein he trusted,"], ["ma tufatufa i ana mea na fao.", "and divideth his spoils."]]},
  {num:23,words:[["O se le 'au ia te au, e 'au ese lea ia te au;", "He that is not with me is against me:"], ["o se le faaputu faatasi ma a'u, e faataapeape lea.", "and he that gathereth not with me scattereth."]]},
  {num:24,words:[["Pe a alu le agaga leaga i fafo o le tagata,", "When the unclean spirit is gone out of a man,"], ["ua fealualuai ia i mea matutu,", "he walketh through dry places,"], ["ua saili se mapusaga,", "seeking rest;"], ["a e le maua;", "and finding none,"], ["ona fai ane lea,", "he saith,"], ["Ou te toe foi i lo'u fale na ou sau ai.", "I will return unto my house whence I came out."]]},
  {num:25,words:[["Ua oo i ai, ona iloa ai lea,", "And when he cometh,"], ["ua uma ona tafitafi ma teuteu.", "he findeth it swept and garnished."]]},
  {num:26,words:[["Ona alu ai lea o ia,", "Then goeth he,"], ["ua na aumaia isi agaga e toafitu,", "and taketh to him seven other spirits more wicked than himself;"], ["e sili lo latou leaga i lona; ona latou ulufale ai lea,", "and they enter in,"], ["ua nonofo ai;", "and dwell there:"], ["ona sili ai lea o le leaga o le iuga o lea tagata i lona amataga.", "and the last state of that man is worse than the first."]]},
  {num:27,words:[["O loo fetalai ane ia i nei mea,", "And it came to pass,"], ["a ua alaga tele mai ai le tasi fafine mai le motu o tagata,", "as he spake these things,"], ["ua faapea mai ia te ia,", "a certain woman of the company lifted up her voice, and said unto him,"], ["Amuia le manava na fanau mai ai oe,", "Blessed is the womb that bare thee,"], ["ma susu na e susu ai.", "and the paps which thou hast sucked."]]},
  {num:28,words:[["A ua fetalai atu ia,", "But he said,"], ["E moni,", "Yea rather,"], ["a e sili ona manuia o e faalogo i le afioga a le Atua,", "blessed are they that hear the word of God,"], ["ma tausi i ai.", "and keep it."]]},
  {num:29,words:[["Ua lolofi mai le motu o tagata,", "And when the people were gathered thick together,"], ["ona fetalai atu ai lea o ia,", "he began to say,"], ["O le tupulaga leaga lenei,", "This is an evil generation:"], ["ua saili mai se faailoga,", "they seek a sign;"], ["a le avatu i ai se faailoga,", "and there shall no sign be given it,"], ["tau lava o le faailoga o Iona le perofeta.", "but the sign of Jonas the prophet."]]},
  {num:30,words:[["Auā pei o Iona ona fai ma faailoga ia Nineva,", "For as Jonas was a sign unto the Ninevites,"], ["e faapea foi le Atalii o le tagata i le tupulaga nei.", "so shall also the Son of man be to this generation."]]},
  {num:31,words:[["O le tupu fafine o le itu i toga e tulai o ia i le faamasinoga ma tagata o le tupulaga nei,", "The queen of the south shall rise up in the judgment with the men of this generation,"], ["e faasala foi o ia ia te i latou;", "and condemn them:"], ["auā na sau ia mai le gataaga o le lalolagi e faalogo i le poto o Solomona;", "for she came from the utmost parts of the earth to hear the wisdom of Solomon; and,"], ["faauta foi,", "behold,"], ["o iinei lava lē sili ia Solomona.", "a greater than Solomon is here."]]},
  {num:32,words:[["E tutū tagata o Nineva i le faamasinoga faatasi ma le tupulaga nei,", "The men of Nineve shall rise up in the judgment with this generation,"], ["e faasala i ai;", "and shall condemn it:"], ["auā na latou salamo i le tala'iga a Iona;", "for they repented at the preaching of Jonas; and,"], ["faauta foi,", "behold,"], ["o iinei lava lē sili ia Iona.", "a greater than Jonas is here."]]},
  {num:33,words:[["E leai se tūtū i le lamepa,", "No man,"], ["ma tuu i le mea lilo,", "when he hath lighted a candle,"], ["po o i lalo o le mea e fua a'i saito,", "putteth it in a secret place, neither under a bushel,"], ["a e tuu i luga lava o le tuugālamepa,", "but on a candlestick,"], ["ina ia iloa mai ai le malamalama i e ulufale mai.", "that they which come in may see the light."]]},
  {num:34,words:[["O mata,", "The light of the body is the eye:"], ["o le lamepa lea o le tino; o lenei,", "therefore when thine eye is single,"], ["pe afai ua lelei ou mata,", "thy whole body also is full of light;"], ["e malamalama uma ai lou tino; a e afai ua leaga,", "but when thine eye is evil,"], ["e pouliuli ai lou tino.", "thy body also is full of darkness."]]},
  {num:35,words:[["O lenei, ia oe ne'i pogisa le malamalama ua i totonu ia te oe.", "Take heed therefore that the light which is in thee be not darkness."]]},
  {num:36,words:[["Afai foi ua malamalama lou tino uma,", "If thy whole body therefore be full of light,"], ["e leai sona pouliuli,", "having no part dark,"], ["e malamalama uma ai,", "the whole shall be full of light,"], ["pei ona faamalamalama mai ia te oe o le lamepa i lona pupula mai.", "as when the bright shining of a candle doth give thee light."]]},
  {num:37,words:[["Ua fetalai o ia,", "And as he spake,"], ["a e fai mai le tasi faresaio ia te ia,", "a certain Pharisee besought him to dine with him:"], ["la te aai ma ia; ona ulufale lea o ia,", "and he went in,"], ["ua taoto e taumafa.", "and sat down to meat."]]},
  {num:38,words:[["Ua iloa e le faresaio, ona ofo lava lea ina ua le muai mulumulu ia,", "And when the Pharisee saw it,"], ["i le 'ai ai.", "he marvelled that he had not first washed before dinner."]]},
  {num:39,words:[["Ua fetalai atu le Alii ia te ia,", "And the Lord said unto him,"], ["Outou faresaio, ua faamamaina lava e outou le tua o le ipu ma le tanoa,", "Now do ye Pharisees make clean the outside of the cup and the platter;"], ["peitai o totonu o outou ua tutumu i mea ua faoa ma le amio leaga.", "but your inward part is full of ravening and wickedness."]]},
  {num:40,words:[["Outou na o valea! o le na faia le tua,", "Ye fools,"], ["e lei faia ea foi e ia o totonu?", "did not he that made that which is without make that which is within also?"]]},
  {num:41,words:[["A ia outou avatu a outou mea e fai ma mea alofa;", "But rather give alms of such things as ye have;"], ["faauta foi,", "and, behold,"], ["e mamā ai mea uma ia te outou.", "all things are clean unto you."]]},
  {num:42,words:[["Oi talofa foi ia te outou faresaio! auā tou te avatu mea e sefulu a'i le mili,", "But woe unto you,"], ["ma le pekano,", "Pharisees! for ye tithe mint and rue and all manner of herbs,"], ["ma laau uma e afu, a ua tuua e outou le faamasinoga ma le alofa i le Atua;", "and pass over judgment and the love of God:"], ["e tatau pe ana faia nei mea,", "these ought ye to have done,"], ["a e aua foi le tuu na mea.", "and not to leave the other undone."]]},
  {num:43,words:[["Oi talofa ia te outou faresaio! auā ua mananao outou i nofoa sili i sunako,", "Woe unto you, Pharisees! for ye love the uppermost seats in the synagogues,"], ["ma ia alofaina i malae,", "and greetings in the markets."]]},
  {num:44,words:[["Oi talofa ia te outou tusiupu ma faresaio,", "Woe unto you,"], ["tagata pepelo! auā tou te tutusa ma tuugamau e lilo;", "scribes and Pharisees,"], ["o tagata foi o e ua savavali i o latou luga,", "hypocrites! for ye are as graves which appear not,"], ["ua le iloa e i latou.", "and the men that walk over them are not aware of them."]]},
  {num:45,words:[["Ona fai mai lea o le tasi o le au a'oa'o tulafono,", "Then answered one of the lawyers,"], ["ua faapea mai ia te ia,", "and said unto him,"], ["Le a'oa'o e,", "Master,"], ["ua e faaleaga mai ia te i matou i lau e fai mai na.", "thus saying thou reproachest us also."]]},
  {num:46,words:[["Ua fetalai atu ia,", "And he said,"], ["Oi talofa ia te outou foi le au a'oa'o tulafono! auā ua faaee atu e outou avega mamafa i tagata,", "Woe unto you also,"], ["a o outou,", "ye lawyers! for ye lade men with burdens grievous to be borne,"], ["tou te le tago lava i na avega i so outou tamatamai lima.", "and ye yourselves touch not the burdens with one of your fingers."]]},
  {num:47,words:[["Oi talofa ia te outou! auā ua outou ati ae tuugamau o perofeta; o outou tamā foi,", "Woe unto you! for ye build the sepulchres of the prophets,"], ["na latou fasioti ia te i latou.", "and your fathers killed them."]]},
  {num:48,words:[["Ua molimau lava outou i le amio a o outou tamā,", "Truly ye bear witness that ye allow the deeds of your fathers:"], ["ma fiafia i ai; auā na latou fasioti ia te i latou,", "for they indeed killed them,"], ["a e tou te ati ae o latou tuugamau.", "and ye build their sepulchres."]]},
  {num:49,words:[["O lea foi ua fetalai mai ai le poto o le Atua,", "Therefore also said the wisdom of God,"], ["Ou te aauina atu ia te i latou perofeta ma aposetolo; e fasioti foi e i latou,", "I will send them prophets and apostles,"], ["ma faasaua i nisi:", "and some of them they shall slay and persecute:"]]},
  {num:50,words:[["ina ia suea i le tupulaga nei le toto o perofeta uma ua faamaligiina talu ona faavaeina o le lalolagi;", "That the blood of all the prophets, which was shed from the foundation of the world, may be required of this generation;"]]},
  {num:51,words:[["e afua mai i le toto o Apelu, e oo atu i le toto o Sakaria,", "From the blood of Abel unto the blood of Zacharias,"], ["na fasiotia i le va o le fata faitaulaga ma le malumalu;", "which perished between the altar and the temple:"], ["e moni,", "verily I say unto you,"], ["ou te fai atu ia te outou, e suea lava ia i lenei tupulaga.", "It shall be required of this generation."]]},
  {num:52,words:[["Oi talofa ia te outou le au a'oa'o tulafono! auā ua avea e outou le ki o le malamalama;", "Woe unto you,"], ["tou te le ulu atu ai,", "lawyers! for ye have taken away the key of knowledge: ye entered not in yourselves,"], ["tou te vavao foi i e a ulu atu.", "and them that were entering in ye hindered."]]},
  {num:53,words:[["Ua fetalai atu ia i ia upu ia te i latou,", "And as he said these things unto them,"], ["ona matuā ita lea o le au tusiupu ma le au faresaio;", "the scribes and the Pharisees began to urge him vehemently,"], ["ona latou fesili faaosooso lea ia te ia i mea e tele,", "and to provoke him to speak of many things:"]]},
  {num:54,words:[["o lamalama ia te ia,", "Laying wait for him,"], ["ma saili e taofi i se upu mai lona fofoga,", "and seeking to catch something out of his mouth,"], ["ina ia latou momoli ia te ia.", "that they might accuse him."]]},
];
renderVerseSet(luk_ch_11_Verses, 'luk-ch11-verses');

var luk_ch_12_Verses = [
  {num:1,words:[["Ua faapotopoto mai le motu o tagata e manomano a o faia ia mea,", "In the mean time,"], ["ua latou fesoliai ai,", "when there were gathered together an innumerable multitude of people,"], ["ona oo atu lea o lana lauga i ona soo,", "insomuch that they trode one upon another, he began to say unto his disciples first of all,"], ["Ia outou matuā 'alo ese i le mea faafefete a le au faresaio,", "Beware ye of the leaven of the Pharisees,"], ["o le pepelo lea.", "which is hypocrisy."]]},
  {num:2,words:[["Auā e leai se mea o loo ufiufitia,", "For there is nothing covered,"], ["e le faaalia;", "that shall not be revealed; neither hid,"], ["e leai foi se mea lilo e le faailoina.", "that shall not be known."]]},
  {num:3,words:[["O lea foi, o mea uma ua outou fai atu ai i le pouliuli,", "Therefore whatsoever ye have spoken in darkness shall be heard in the light;"], ["e logoina lea i le malamalama; o le mea foi ua outou tala lemu atu i afeafe, e tala'iina lea i luga o fale.", "and that which ye have spoken in the ear in closets shall be proclaimed upon the housetops."]]},
  {num:4,words:[["A ou te fai atu ia te outou na a'u uo,", "And I say unto you my friends,"], ["aua tou te matatau ia te i latou o e fasioti le tino; a mavae lea,", "Be not afraid of them that kill the body,"], ["ua leai se toe mea latou te mafaia.", "and after that have no more that they can do."]]},
  {num:5,words:[["A e ou te faasino atu ia te outou i lē tou te matatau i ai;", "But I will forewarn you whom ye shall fear:"], ["ia outou matatau ia te ia,", "Fear him,"], ["a mavae ona fasioti e ia, e ana le pule e lafo atu i Kēna;", "which after he hath killed hath power to cast into hell;"], ["e moni,", "yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ia outou matatau ia te ia.", "Fear him."]]},
  {num:6,words:[["E le faataulia ea manu iti e lima gafua i asari e lua? e leai foi so latou e tasi ua galo i luma o le Atua.", "Are not five sparrows sold for two farthings, and not one of them is forgotten before God?"]]},
  {num:7,words:[["A o outou lauulu lava ua faitaulia uma ia.", "But even the very hairs of your head are all numbered."], ["O lena, aua tou te matatau ai;", "Fear not therefore:"], ["ua sili outou i manu iti e tele.", "ye are of more value than many sparrows."]]},
  {num:8,words:[["Ou te fai atu foi ia te outou,", "Also I say unto you,"], ["O sē ta'ua a'u i luma o tagata,", "Whosoever shall confess me before men,"], ["e ta'ua foi o ia e le Atalii o le tagata i luma o agelu a le Atua.", "him shall the Son of man also confess before the angels of God:"]]},
  {num:9,words:[["A o lē faafiti mai ia te au i luma o tagata, e faafitia o ia i luma o agelu a le Atua.", "But he that denieth me before men shall be denied before the angels of God."]]},
  {num:10,words:[["O sē lafo foi se upu i le Atalii o le tagata,", "And whosoever shall speak a word against the Son of man,"], ["e faamagaloina lea; a o lē upu leaga i le Agaga Paia,", "it shall be forgiven him:"], ["e le faamagaloina lea.", "but unto him that blasphemeth against the Holy Ghost it shall not be forgiven."]]},
  {num:11,words:[["Pe a ta'ita'iina outou i sunako,", "And when they bring you unto the synagogues,"], ["ma alii,", "and unto magistrates,"], ["ma faipule, aua tou te popole i sa outou e tali atu,", "and powers,"], ["pe faapefea,", "take ye no thought how or what thing ye shall answer,"], ["pe se a foi tou te fai atu ai;", "or what ye shall say:"]]},
  {num:12,words:[["auā e a'oa'o le Agaga Paia ia te outou i lea lava itu aso i upu e tatau ona fai atu ai.", "For the Holy Ghost shall teach you in the same hour what ye ought to say."]]},
  {num:13,words:[["Ua fai mai ia te ia le tasi mai le motu o tagata,", "And one of the company said unto him,"], ["Le a'oa'o e,", "Master,"], ["ia e fetalai ane i lo'u uso,", "speak to my brother,"], ["ina ia vaeluaina mai le tofi ia te au.", "that he divide the inheritance with me."]]},
  {num:14,words:[["A ua fetalai atu o ia ia te ia,", "And he said unto him,"], ["Sole,", "Man,"], ["o ai ea le na fai a'u ma faamasino ma pule ia te outou?", "who made me a judge or a divider over you?"]]},
  {num:15,words:[["Ua fetalai atu foi o ia ia te i latou,", "And he said unto them,"], ["Ia outou,", "Take heed,"], ["ia leoleo outou ia te outou auā le matapeapea;", "and beware of covetousness:"], ["auā e le ola se tasi i le tele o ana mea ua ia te ia.", "for a man's life consisteth not in the abundance of the things which he possesseth."]]},
  {num:16,words:[["Ua fetalai atu ia ia te i latou le faataoto,", "And he spake a parable unto them,"], ["ua faapea atu,", "saying,"], ["Na fua tele mai le fanua o le tasi tagata mauoa;", "The ground of a certain rich man brought forth plentifully:"]]},
  {num:17,words:[["ona manatunatu ifo lea o ia,", "And he thought within himself,"], ["ua faapea,", "saying,"], ["Se a se mea ou te faia,", "What shall I do,"], ["auā e leai sa'u mea e faaputu ai a'u fua?", "because I have no room where to bestow my fruits?"]]},
  {num:18,words:[["Ua fai ane foi o ia,", "And he said,"], ["O lenei le mea ou te faia;", "This will I do:"], ["ou te sa'ena o'u fale saito,", "I will pull down my barns,"], ["a e faia ia tele;", "and build greater;"], ["ou te faaputu i ai a'u fua ma a'u mea lelei uma.", "and there will I bestow all my fruits and my goods."]]},
  {num:19,words:[["Ou te fai ifo i lo'u agaga,", "And I will say to my soul,"], ["Lo'u agaga e,", "Soul,"], ["ua ia te oe mea lelei e tele ua teuina mo tausaga e tele;", "thou hast much goods laid up for many years; take thine ease,"], ["ina nofonofo filemu ia,", "eat,"], ["ina 'ai ia,", "drink,"], ["ma inu ma ia e olioli.", "and be merry."]]},
  {num:20,words:[["A ua fetalai atu le Atua ia te ia,", "But God said unto him,"], ["O oe na le vale,", "Thou fool,"], ["e aamiina atu lou agaga nai ia te oe i le po nanei;", "this night thy soul shall be required of thee: then whose shall those things be,"], ["a e fai ma ai mea ia ua e saunia?", "which thou hast provided?"]]},
  {num:21,words:[["O loo faapea foi lē faaputu oa ia te ia,", "So is he that layeth up treasure for himself,"], ["a e le mauoa i le Atua.", "and is not rich toward God."]]},
  {num:22,words:[["Ona fetalai atu lea o ia i ona soo,", "And he said unto his disciples,"], ["O lea ou te fai atu ai ia te outou,", "Therefore I say unto you,"], ["aua tou te popole i lo outou ola,", "Take no thought for your life,"], ["i mea tou te aai ai,", "what ye shall eat;"], ["po o le tino,", "neither for the body,"], ["i mea tou te oofu ai.", "what ye shall put on."]]},
  {num:23,words:[["Ua sili le ola i le mea e 'ai,", "The life is more than meat,"], ["ua sili foi le tino i le ofu.", "and the body is more than raiment."]]},
  {num:24,words:[["Ia outou mafaufau i oreva; latou te le lulu saito,", "Consider the ravens:"], ["latou te le selesele foi;", "for they neither sow nor reap;"], ["e leai lava so latou afeafe, po o se fale saito,", "which neither have storehouse nor barn;"], ["a e fagaina i latou e le Atua;", "and God feedeth them:"], ["e le sili ea lo outou lelei, i manu?", "how much more are ye better than the fowls?"]]},
  {num:25,words:[["O ai ea so outou ua mafai ia te ia i lona popole ona faateleina le umi o lona olaga i le kupita e tasi?", "And which of you with taking thought can add to his stature one cubit?"]]},
  {num:26,words:[["Afai foi tou te le mafai i se mea itiiti lava,", "If ye then be not able to do that thing which is least,"], ["se a le mea tou te popole ai i nisi mea?", "why take ye thought for the rest?"]]},
  {num:27,words:[["Ia outou mafaufau i lautalotalo pe faapefea ona tupu;", "Consider the lilies how they grow:"], ["latou te le galue,", "they toil not,"], ["e le milo foi;", "they spin not;"], ["a ou te fai atu ia te outou,", "and yet I say unto you,"], ["e lei ofu lava Solomona ma lona matagofie tele pei o le tasi o na mea.", "that Solomon in all his glory was not arrayed like one of these."]]},
  {num:28,words:[["Afai e faapea ona faaofuina e le Atua le vao o i le fanua,", "If then God so clothe the grass,"], ["o ola mai i le asō,", "which is to day in the field,"], ["a e lafoina a taeao i le ogāumu;", "and to morrow is cast into the oven; how much more will he clothe you,"], ["e le sili ea ona faaofuina outou e ia o outou e faatuatua itiiti?", "O ye of little faith?"]]},
  {num:29,words:[["O outou foi,", "And seek not ye what ye shall eat,"], ["aua tou te saili pe ni a tou te aai ai, ni a foi tou te inu ai;", "or what ye shall drink,"], ["aua foi le feaveaiina o outou loto.", "neither be ye of doubtful mind."]]},
  {num:30,words:[["Auā o mea uma ia ua sailia e nuu o le lalolagi;", "For all these things do the nations of the world seek after:"], ["ua silafia foi e lo outou Tamā o ia mea e aoga ia te outou.", "and your Father knoweth that ye have need of these things."]]},
  {num:31,words:[["A ia outou saili le malo o le Atua;", "But rather seek ye the kingdom of God;"], ["ona faaopoopoina ai lea o ia mea uma ia te outou.", "and all these things shall be added unto you."]]},
  {num:32,words:[["Aua e te fefe oe le lafu mamoe itiiti e;", "Fear not, little flock;"], ["auā ua finagalo lo outou Tamā e foai mai le malo ia te outou.", "for it is your Father's good pleasure to give you the kingdom."]]},
  {num:33,words:[["Ia outou faatau atu i a outou mea,", "Sell that ye have,"], ["tou te avatu ai e fai ma mea alofa;", "and give alms;"], ["ia fai outou ni a outou taga e anagata,", "provide yourselves bags which wax not old,"], ["o le oa i le lagi e le uma lava,", "a treasure in the heavens that faileth not,"], ["e le tāitāi ane i ai se gaoi,", "where no thief approacheth,"], ["e le atia foi e se mogamoga.", "neither moth corrupteth."]]},
  {num:34,words:[["Auā o le mea o i ai lo outou oa,", "For where your treasure is,"], ["e i ai atoa foi ma o outou loto.", "there will your heart be also."]]},
  {num:35,words:[["Ia fusia o outou sulugātiti,", "Let your loins be girded about,"], ["ma ia mumū a outou lamepa;", "and your lights burning;"]]},
  {num:36,words:[["o outou foi,", "And ye yourselves like unto men that wait for their lord,"], ["ia outou faapei o tagata e faatali atu i lo latou alii,", "when he will return from the wedding;"], ["seia foi mai o ia mai le tausamaaga; ia latou to loa mai le puipui ia te ia pe a sau,", "that when he cometh and knocketh,"], ["ma tu'itu'i mai.", "they may open unto him immediately."]]},
  {num:37,words:[["Amuia ia auauna e maua i latou e lo latou alii,", "Blessed are those servants,"], ["o mataala pe a sau. E moni,", "whom the lord when he cometh shall find watching:"], ["ou te fai atu ia te outou, e fusi e ia ona ofu,", "verily I say unto you,"], ["ma fai atu ia te i latou ia taooto e aai,", "that he shall gird himself,"], ["ma alu ane lava,", "and make them to sit down to meat,"], ["ma auauna ia te i latou.", "and will come forth and serve them."]]},
  {num:38,words:[["Pe afai e sau ia i le leoleoga e lua o le po,", "And if he shall come in the second watch,"], ["pe sau i le leoleoga e tolu,", "or come in the third watch,"], ["a maua o i latou o faapea,", "and find them so,"], ["amuia ia auauna.", "blessed are those servants."]]},
  {num:39,words:[["A ia outou iloa lenei mea,", "And this know,"], ["ana iloa e le matai o le aiga le itu po e sau ai le gaoi,", "that if the goodman of the house had known what hour the thief would come,"], ["po ua na leoleoina,", "he would have watched,"], ["a e le tuua e ia lona fale ia elia.", "and not have suffered his house to be broken through."]]},
  {num:40,words:[["O lenei, ia outou nofo sauni;", "Be ye therefore ready also:"], ["auā o le itu aso tou te le manatunatu ai, e sau ai le Atalii o le tagata.", "for the Son of man cometh at an hour when ye think not."]]},
  {num:41,words:[["Ona fai mai lea o Peteru ia te ia,", "Then Peter said unto him,"], ["Le Alii e,", "Lord,"], ["ua e fetalai mai ea lena faataoto ia te i matou,", "speakest thou this parable unto us,"], ["po o tagata uma?", "or even to all?"]]},
  {num:42,words:[["Ona fetalai atu lea o le Alii,", "And the Lord said,"], ["O ai foi le auauna e pule,", "Who then is that faithful and wise steward,"], ["ua faamaoni ma le mafaufau, ua tofia e lona alii e pule i ana auauna,", "whom his lord shall make ruler over his household,"], ["ia avatu mea e 'ai ia te i latou i ona itu aso?", "to give them their portion of meat in due season?"]]},
  {num:43,words:[["Amuia lea auauna,", "Blessed is that servant,"], ["pe a sau lona alii e maua ia o loo faapea ona fai.", "whom his lord when he cometh shall find so doing."]]},
  {num:44,words:[["E moni, ou te fai atu ia te outou,", "Of a truth I say unto you,"], ["na te tofia o ia e pule i ana mea uma.", "that he will make him ruler over all that he hath."]]},
  {num:45,words:[["A e afai e fai ifo lea auauna i lona loto. E faatuai mai lo'u alii;", "But and if that servant say in his heart,"], ["ona fasi ai lea o ia i auauna tane ma auauna fafine,", "My lord delayeth his coming;"], ["e 'ai foi,", "and shall begin to beat the menservants and maidens,"], ["ma inu,", "and to eat and drink,"], ["ma onā.", "and to be drunken;"]]},
  {num:46,words:[["E sau lava le alii o lea auauna i le aso e le faatalitali atu ai o ia,", "The lord of that servant will come in a day when he looketh not for him,"], ["o le itu aso foi e le iloa ai e ia;", "and at an hour when he is not aware,"], ["ona matuā faasala lea ia te ia,", "and will cut him in sunder,"], ["ma avatu lona tofi faatasi ma e le faalogo.", "and will appoint him his portion with the unbelievers."]]},
  {num:47,words:[["O lea auauna foi ua na iloa le finagalo o lona alii,", "And that servant,"], ["a e lei sauni lava ia,", "which knew his lord's will,"], ["e lei faia foi mea e tatau ma lona finagalo,", "and prepared not himself, neither did according to his will,"], ["e tele ona sasaina.", "shall be beaten with many stripes."]]},
  {num:48,words:[["A o le ua le iloa,", "But he that knew not,"], ["ua faia foi e ia mea e tatau ina sasaina ai,", "and did commit things worthy of stripes,"], ["e māmā ona sasaina o ia. Auā o le ua foaiina atu i ai o mea e tele,", "shall be beaten with few stripes. For unto whomsoever much is given,"], ["e sueina atu foi ia te ia o mea e tele;", "of him shall be much required:"], ["o ia foi ua tuuina atu i ai o mea e tele,", "and to whom men have committed much,"], ["latou te fai atu ia te ia e au mai mea e sili ona tele.", "of him they will ask the more."]]},
  {num:49,words:[["Ua ou sau e lafo le afi i le lalolagi;", "I am come to send fire on the earth;"], ["se a se mea ou te toe manao i ai,", "and what will I,"], ["pe ana mu nei lava?", "if it be already kindled?"]]},
  {num:50,words:[["O lo'u papatisoga o le a papatisoina ai a'u;", "But I have a baptism to be baptized with;"], ["ua ou matuā tiga lava seia faaiuina.", "and how am I straitened till it be accomplished!"]]},
  {num:51,words:[["Fa te outou ea ua ou sau e avatu le filemu i le lalolagi? Ou te fai atu ia te outou,", "Suppose ye that I am come to give peace on earth? I tell you,"], ["e leai;", "Nay;"], ["a o le fevaevaeai.", "but rather division:"]]},
  {num:52,words:[["Auā e amata i nei ona po e i ai i le fale e tasi tagata e toalima e favaevaeai i latou,", "For from henceforth there shall be five in one house divided,"], ["o le toatolu e faamasesei ma le toalua,", "three against two,"], ["o le toalua foi e faamasesei ma le toatolu.", "and two against three."]]},
  {num:53,words:[["E fevaevaeai le tamā ma le atalii,", "The father shall be divided against the son,"], ["o le atalii foi ma le tamā;", "and the son against the father;"], ["o le tinā ma le tama teine,", "the mother against the daughter,"], ["o le tama teine foi ma le tinā;", "and the daughter against the mother;"], ["o le tinā o le tane ma le avā a lana tama,", "the mother in law against her daughter in law,"], ["o le avā foi ma le tinā o lana tane.", "and the daughter in law against her mother in law."]]},
  {num:54,words:[["Ua fetalai atu foi o ia i le motu o tagata,", "And he said also to the people,"], ["Pe a outou iloa le ao o loo alu ae i sisifo,", "When ye see a cloud rise out of the west,"], ["ona outou fai ane loa lea,", "straightway ye say,"], ["Anei e ua;", "There cometh a shower;"], ["ona taunuu foi lea.", "and so it is."]]},
  {num:55,words:[["A agi mai foi le toga,", "And when ye see the south wind blow,"], ["ua outou fai ane. Anei e la;", "ye say, There will be heat;"], ["ona taunuu foi lea.", "and it cometh to pass."]]},
  {num:56,words:[["O outou tagata pepelo,", "Ye hypocrites,"], ["ua outou iloa ona mātauina le amio a le lagi ma le lalolagi;", "ye can discern the face of the sky and of the earth;"], ["se a foi le mea tou te le mātauina ai le uiga o lenei tausaga?", "but how is it that ye do not discern this time?"]]},
  {num:57,words:[["Se a foi le mea tou te le filifili ai e outou i mea tonu?", "Yea, and why even of yourselves judge ye not what is right?"]]},
  {num:58,words:[["Pe a lua ō i le alii ma lē ua e aitalafu ai,", "When thou goest with thine adversary to the magistrate,"], ["ia e taumafai lava i le ala ina ia oulua lelei ma ia;", "as thou art in the way,"], ["ne'i toso o ia ia te oe i le faamasino,", "give diligence that thou mayest be delivered from him; lest he hale thee to the judge,"], ["e tuu atu foi le faamasino ia te oe i le auauna,", "and the judge deliver thee to the officer,"], ["ona tuuina atu lea oe e le auauna i le fale puipui.", "and the officer cast thee into prison."]]},
  {num:59,words:[["Ou te fai atu ia te oe,", "I tell thee,"], ["e te le toe ulufafo ai,", "thou shalt not depart thence,"], ["seia e avatu tupe uma lava.", "till thou hast paid the very last mite."]]},
];
renderVerseSet(luk_ch_12_Verses, 'luk-ch12-verses');

var luk_ch_13_Verses = [
  {num:1,words:[["O ia ona aso ua o mai ai isi tagata, ua tala mai ia te ia i tagata Kalilaia,", "There were present at that season some that told him of the Galilaeans,"], ["ina ua fefiloi e Pilato lo latou toto ma le toto o a latou taulaga.", "whose blood Pilate had mingled with their sacrifices."]]},
  {num:2,words:[["Ona tali atu lea o Iesu, ua faapea atu ia te i latou,", "And Jesus answering said unto them,"], ["Fa te outou ea,", "Suppose ye that these Galilaeans were sinners above all the Galilaeans,"], ["ua sili ona agasala ia Kalilaia i tagata Kalilaia uma, ina ua tigaina i latou i mea faapena?", "because they suffered such things?"]]},
  {num:3,words:[["Ou te fai atu ia te outou,", "I tell you,"], ["e leai;", "Nay:"], ["a e afai tou te le salamo,", "but, except ye repent,"], ["e faapena lava ona fano outou uma.", "ye shall all likewise perish."]]},
  {num:4,words:[["I le ma le toasefulu ma le toavalu sa paū i o latou luga le 'olo i Seloa,", "Or those eighteen,"], ["ua latou oti ai;", "upon whom the tower in Siloam fell,"], ["fa te outou ea,", "and slew them,"], ["ua sili a latou agasala i tagata uma e na nonofo i Ierusalema?", "think ye that they were sinners above all men that dwelt in Jerusalem?"]]},
  {num:5,words:[["Ou te fai atu ia te outou,", "I tell you,"], ["e leai;", "Nay:"], ["a e afai tou te le salamo,", "but, except ye repent,"], ["e faapena lava ona fano outou uma.", "ye shall all likewise perish."]]},
  {num:6,words:[["Ua fetalai atu ia le faataoto nei. Sa i le tasi tagata le mati,", "He spake also this parable;"], ["na totō i lana tovine;", "A certain man had a fig tree planted in his vineyard;"], ["ua alu atu ia e saili ai ni fua,", "and he came and sought fruit thereon,"], ["a e lei maua.", "and found none."]]},
  {num:7,words:[["Ona fai atu lea o ia i le galue vine,", "Then said he unto the dresser of his vineyard,"], ["Faauta,", "Behold,"], ["ua ou sau i ia tausaga ua tolu e saili ni fua i lenei mati,", "these three years I come seeking fruit on this fig tree,"], ["a ou te lei maua lava;", "and find none:"], ["ina tuu ia i lalo;", "cut it down;"], ["se a foi le mea e faaleaoga ai le fanua?", "why cumbereth it the ground?"]]},
  {num:8,words:[["Ua tali mai o ia ia te ia,", "And he answering said unto him,"], ["ua faapea mai,", "Lord,"], ["Le alii e, tuu pea ia i lenei tausaga foi,", "let it alone this year also,"], ["seia ou eli faataaliolio i ai,", "till I shall dig about it,"], ["ma avane i ai otaota.", "and dung it:"]]},
  {num:9,words:[["Afai foi e fua mai,", "And if it bear fruit,"], ["e lelei;", "well:"], ["pe afai e leai,", "and if not,"], ["e mulimuli ane ona e tuu ai lea i lalo.", "then after that thou shalt cut it down."]]},
  {num:10,words:[["Sa a'oa'o ia i le tasi sunako i le sapati.", "And he was teaching in one of the synagogues on the sabbath."]]},
  {num:11,words:[["Faauta foi,", "And,"], ["sa i ai le fafine ua ia te ia le agaga e vaivai ai i ona tausaga ua sefulu ma le valu,", "behold,"], ["ua faano'uno'u lava ia,", "there was a woman which had a spirit of infirmity eighteen years, and was bowed together,"], ["e le mafai lava ona tu sa'o i luga.", "and could in no wise lift up herself."]]},
  {num:12,words:[["Ua silafia o ia e Iesu,", "And when Jesus saw her,"], ["ona valaau atu lea o ia ia te ia,", "he called her to him,"], ["ua faapea atu,", "and said unto her,"], ["Funa e,", "Woman,"], ["ua tatalaina lou vaivai.", "thou art loosed from thine infirmity."]]},
  {num:13,words:[["Ua faaee atu e ia ona aao ia te ia;", "And he laid his hands on her:"], ["ona faasa'oloaina lea o ia,", "and immediately she was made straight,"], ["ua vivii atu foi o ia i le Atua.", "and glorified God."]]},
  {num:14,words:[["Ona tautala mai ai lea o lē pule i le sunako,", "And the ruler of the synagogue answered with indignation,"], ["ua ita ina ua faamalolo Iesu i le sapati,", "because that Jesus had healed on the sabbath day,"], ["ua fai ane ia i le motu o tagata,", "and said unto the people,"], ["E ono ia aso e tatau ona galulue ai;", "There are six days in which men ought to work:"], ["o aso ia tou te o mai ai ia faamaloloina,", "in them therefore come and be healed,"], ["a e aua lava i le sapati.", "and not on the sabbath day."]]},
  {num:15,words:[["Ua tali atu le Alii ia te ia,", "The Lord then answered him,"], ["ua faapea atu,", "and said,"], ["O oe na le pepelo; e le ua taitasi ea o outou i le sapati ma tatala i lana povi,", "Thou hypocrite,"], ["po o lana asini i le fale povi,", "doth not each one of you on the sabbath loose his ox or his ass from the stall,"], ["ma ta'ita'i e faainu?", "and lead him away to watering?"]]},
  {num:16,words:[["A o le fafine nei,", "And ought not this woman,"], ["o le afafine o Aperaamo,", "being a daughter of Abraham,"], ["ua noanoatia e Satani,", "whom Satan hath bound, lo,"], ["faauta ona tausaga ia ua sefulu ma le valu,", "these eighteen years,"], ["e le tatau ea ona tatalaina o lenei noanoaga ia te ia i le aso sapati?", "be loosed from this bond on the sabbath day?"]]},
  {num:17,words:[["Ua fetalai ane ia na upu,", "And when he had said these things,"], ["ona mamā uma ai lea o e ita mai ia te ia;", "all his adversaries were ashamed:"], ["a ua olioli lava le motu o tagata uma ona o ia mea silisili uma na faia e ia.", "and all the people rejoiced for all the glorious things that were done by him."]]},
  {num:18,words:[["Ua fetalai ane foi o ia,", "Then said he,"], ["E tusa le malo o le Atua i ni a? ou te faatatau i ai i ni a?", "Unto what is the kingdom of God like? and whereunto shall I resemble it?"]]},
  {num:19,words:[["E tusa ia ma le fua o le sinapi,", "It is like a grain of mustard seed,"], ["ua ave e le tasi tagata,", "which a man took,"], ["ma lafo i lona fanua;", "and cast into his garden;"], ["ua tupu,", "and it grew,"], ["ua avea ma laau tele;", "and waxed a great tree;"], ["ua momoe foi manu felelei i ona la.", "and the fowls of the air lodged in the branches of it."]]},
  {num:20,words:[["Ua toe fetalai atu foi o ia,", "And again he said,"], ["Ou te faatatau le malo o le Atua i ni a?", "Whereunto shall I liken the kingdom of God?"]]},
  {num:21,words:[["E tusa ia ma le mea faafefete,", "It is like leaven,"], ["ua ave e le fafine ma tuu i totonu o le falaoa e tolu tumu,", "which a woman took and hid in three measures of meal,"], ["ua oo ina faafefeteina uma ai.", "till the whole was leavened."]]},
  {num:22,words:[["Ua ui ane foi o ia i aai ma faoa aai,", "And he went through the cities and villages,"], ["ua a'oa'o fano,", "teaching,"], ["o alu malaga atu i Ierusalema.", "and journeying toward Jerusalem."]]},
  {num:23,words:[["Ua fai mai le tasi ia te ia,", "Then said one unto him,"], ["Le Alii e,", "Lord,"], ["e toaitiiti ea e faaolaina? Ona fetalai atu lea o ia ia te i latou,", "are there few that be saved? And he said unto them,"]]},
  {num:24,words:[["Ia outou finafinau ina ia ulu atu i le faitotoa va apiapi;", "Strive to enter in at the strait gate:"], ["auā ou te fai atu ia te outou,", "for many,"], ["e toatele latou te saili ina ia ulu atu,", "I say unto you, will seek to enter in,"], ["a e le mafai lava.", "and shall not be able."]]},
  {num:25,words:[["A uma ona tulai o le matai o le fale,", "When once the master of the house is risen up,"], ["ma pupuni le faitotoa,", "and hath shut to the door,"], ["ona outou tutū lea i fafo,", "and ye begin to stand without,"], ["ma tu'itu'i i le faitotoa,", "and to knock at the door,"], ["e faapea mai, Le Alii e,", "saying,"], ["le Alii e,", "Lord,"], ["ia e to mai ia te i matou;", "Lord,"], ["a e tali atu ia,", "open unto us;"], ["e faapea atu ia te outou,", "and he shall answer and say unto you,"], ["Ou te lei iloa outou pe maifea.", "I know you not whence ye are:"]]},
  {num:26,words:[["Ona fai mai ai lea outou,", "Then shall ye begin to say,"], ["Na matou aai ma inu i ou luma;", "We have eaten and drunk in thy presence,"], ["na e a'oa'o foi i o matou ala.", "and thou hast taught in our streets."]]},
  {num:27,words:[["Ona faapea atu lea o ia,", "But he shall say,"], ["Ou te fai atu ia te outou,", "I tell you,"], ["ou te lei iloa outou pe maifea;", "I know you not whence ye are;"], ["ina o ese ia outou ia te au,", "depart from me,"], ["o outou uma o e fai amio leaga.", "all ye workers of iniquity."]]},
  {num:28,words:[["E i ai le taufaitagiaue ma le lilivau o nifo,", "There shall be weeping and gnashing of teeth,"], ["pe a iloa e outou o Aperaamo,", "when ye shall see Abraham,"], ["ma Isaako,", "and Isaac, and Jacob,"], ["ma Iakopo,", "and all the prophets,"], ["ma le au perofeta uma i le malo o le Atua,", "in the kingdom of God,"], ["a o outou ua tulia i fafo.", "and you yourselves thrust out."]]},
  {num:29,words:[["E o atu tagata mai sasae,", "And they shall come from the east,"], ["ma sisifo,", "and from the west,"], ["ma le itu i matu,", "and from the north,"], ["atoa ma le itu i toga,", "and from the south,"], ["e taooto e aai i le malo o le Atua.", "and shall sit down in the kingdom of God."]]},
  {num:30,words:[["Faauta foi,", "And,"], ["o e mulimuli e avea ia ma muamua;", "behold, there are last which shall be first,"], ["o e muamua foi e avea ia ma mulimuli.", "and there are first which shall be last."]]},
  {num:31,words:[["O lea lava aso ua o mai ai isi o le au faresaio,", "The same day there came certain of the Pharisees,"], ["na fai mai ia te ia,", "saying unto him,"], ["Alu ia oe,", "Get thee out,"], ["ina alu lava;", "and depart hence:"], ["auā o Herota ua na fia fasioti ia te oe.", "for Herod will kill thee."]]},
  {num:32,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["Ina o ia,", "Go ye,"], ["fai atu i lea alope,", "and tell that fox,"], ["Faauta,", "Behold,"], ["ou te tuli i fafo temoni,", "I cast out devils,"], ["ou te faamalolo foi i e mamai i le asō ma taeao,", "and I do cures to day and to morrow,"], ["a oo i e luā ou te faaiuina ai.", "and the third day I shall be perfected."]]},
  {num:33,words:[["Peitai e tatau ona ou fealualuai i le asō,", "Nevertheless I must walk to day,"], ["ma taeao,", "and to morrow,"], ["atoa ma e luā;", "and the day following:"], ["auā e le mafaia lava ona fano se perofeta i se tasi mea na o Ierusalema lava.", "for it cannot be that a prophet perish out of Jerusalem."]]},
  {num:34,words:[["Ierusalema e,", "O Jerusalem,"], ["Ierusalema e,", "Jerusalem,"], ["o lē fasiotia perofeta,", "which killest the prophets,"], ["ma fetogi i maa e na aauina atu ia te oe;", "and stonest them that are sent unto thee;"], ["ua tele lava o'u manao e faapotopoto i lau fanau,", "how often would I have gathered thy children together,"], ["e pei o le moa ona ofaofatai i lana toloai i lalo i ona apaau,", "as a hen doth gather her brood under her wings,"], ["a e le mafafai outou.", "and ye would not!"]]},
  {num:35,words:[["Faauta,", "Behold,"], ["e tuua lo outou fale,", "your house is left unto you desolate:"], ["e faatafunaina; a e moni ou te fai atu ia te outou,", "and verily I say unto you,"], ["tou te le iloa mai lava a'u,", "Ye shall not see me,"], ["seia oo atu i le aso tou te fai ane ai,", "until the time come when ye shall say,"], ["Ia manuia lē maliu mai i le suafa o le Alii.", "Blessed is he that cometh in the name of the Lord."]]},
];
renderVerseSet(luk_ch_13_Verses, 'luk-ch13-verses');

var luk_ch_14_Verses = [
  {num:1,words:[["Ua oo i le tasi sapati,", "And it came to pass,"], ["ua maliu atu ai o ia i le fale o le tasi alii o le au faresaio e taumafa ai,", "as he went into the house of one of the chief Pharisees to eat bread on the sabbath day,"], ["ona latou lamalama lea ia te ia.", "that they watched him."]]},
  {num:2,words:[["Faauta foi,", "And, behold,"], ["sa i ona luma le tasi tagata ua ma'i i le fula.", "there was a certain man before him which had the dropsy."]]},
  {num:3,words:[["Ua fetalai atu Iesu i le au a'oa'o tulafono ma le au faresaio,", "And Jesus answering spake unto the lawyers and Pharisees,"], ["ua faapea atu,", "saying,"], ["Pe sa ea ona faamalolo i ma'i i le sapati?", "Is it lawful to heal on the sabbath day?"]]},
  {num:4,words:[["Ua latou faalologo lava. Ona tago atu lea o ia ia te ia,", "And they held their peace. And he took him,"], ["ua faamalolo ia te ia,", "and healed him,"], ["ma tuu atu e alu.", "and let him go;"]]},
  {num:5,words:[["Ua fetalai atu foi o ia ia te i latou,", "And answered them,"], ["ua faapea atu,", "saying,"], ["O ai so outou ua i ai se asini po o se povi, ua paū i le lua,", "Which of you shall have an ass or an ox fallen into a pit,"], ["e le sisi ae loa i luga i le aso sapati?", "and will not straightway pull him out on the sabbath day?"]]},
  {num:6,words:[["A ua latou le mafai ona tali mai ia te ia i na mea.", "And they could not answer him again to these things."]]},
  {num:7,words:[["Ua fetalai atu ia le faataoto i e na tala'iina,", "And he put forth a parable to those which were bidden,"], ["ina ua silafia e ia o i latou ua filifili i mea sili e taoto ai;", "when he marked how they chose out the chief rooms;"], ["ua faapea atu ia te i latou.", "saying unto them,"]]},
  {num:8,words:[["Pe a fai atu se tasi ia te oe e alu i le faigaai,", "When thou art bidden of any man to a wedding,"], ["aua e te taoto i le mea sili,", "sit not down in the highest room;"], ["ne'i i ai foi se tasi ua tala'iina e ia ua sili ia te oe;", "lest a more honourable man than thou be bidden of him;"]]},
  {num:9,words:[["ona alu atu lea o le na tala'i ia te oulua ma ia,", "And he that bade thee and him come and say to thee,"], ["ma fai atu ia te oe, Ina sōsō atu ia ma le alii nei;", "Give this man place;"], ["ona e alu ai lea ma le mā i le mea e aupito faatauvaa.", "and thou begin with shame to take the lowest room."]]},
  {num:10,words:[["Peitai o oe,", "But when thou art bidden,"], ["pe a tala'iina oe,", "go and sit down in the lowest room;"], ["e te alu e taoto i le mea e aupito faatauvaa;", "that when he that bade thee cometh,"], ["ina ia fai atu le na tala'i ia te oe, pe a sau o ia,", "he may say unto thee,"], ["Sole,", "Friend,"], ["ina alu ae ia oe i le mea e sili;", "go up higher:"], ["ona mamalu ai lea oe i luma o e taooto e aai faatasi ma oe.", "then shalt thou have worship in the presence of them that sit at meat with thee."]]},
  {num:11,words:[["Auā so se faamaualuga e ia ia te ia, e faamaulaloina lea;", "For whosoever exalteth himself shall be abased;"], ["a o lē faamaulalo e ia ia te ia, e faamaualugaina lea.", "and he that humbleth himself shall be exalted."]]},
  {num:12,words:[["Ua fetalai atu foi o ia i le na tala'i mai ia te ia,", "Then said he also to him that bade him,"], ["Pe a e sauni se faigaai,", "When thou makest a dinner or a supper,"], ["po o se talisuaga,", "call not thy friends,"], ["aua e te tala'i i au uo,", "nor thy brethren,"], ["po o ou uso, po o tagata o lou aiga,", "neither thy kinsmen,"], ["po o tagata mauoa tou te tuaoi,", "nor thy rich neighbours;"], ["ne'i latou toe tala'i mai foi ia te oe,", "lest they also bid thee again,"], ["ona tauia mai lea o oe.", "and a recompence be made thee."]]},
  {num:13,words:[["Peitai o oe,", "But when thou makest a feast,"], ["pe a e sauni le faigaai,", "call the poor,"], ["ina tala'i ia i e matitiva, i e mumutu,", "the maimed,"], ["i e pipili,", "the lame,"], ["ma e tauaso;", "the blind:"]]},
  {num:14,words:[["e manuia ai oe;", "And thou shalt be blessed;"], ["auā latou te le mafaia ona taui mai ia te oe;", "for they cannot recompense thee:"], ["a e tauia oe i le toe tutū mai o e amiotonu.", "for thou shalt be recompensed at the resurrection of the just."]]},
  {num:15,words:[["O le tasi o e na taooto e aai ma ia,", "And when one of them that sat at meat with him heard these things,"], ["ua faalogo o ia i na mea, ona fai mai lea o ia ia te ia,", "he said unto him,"], ["Amuia lē 'ai i le malo o le Atua.", "Blessed is he that shall eat bread in the kingdom of God."]]},
  {num:16,words:[["A ua fetalai atu o ia ia te ia,", "Then said he unto him,"], ["Na saunia e le tasi tagata le talisuaga tele,", "A certain man made a great supper,"], ["na tala'i atu foi e ia i tagata e toatele;", "and bade many:"]]},
  {num:17,words:[["ua oo foi i le itu aso e fai ai le talisuaga,", "And sent his servant at supper time to say to them that were bidden,"], ["ona auina atu lea e ia o lana auauna e fai atu i e na tala'iina, Ia outou o mai,", "Come;"], ["auā ua uma ona saunia o mea uma.", "for all things are now ready."]]},
  {num:18,words:[["Ona latou fealoalofa'i ai lea, ua tasi le loto .", "And they all with one consent began to make excuse."], ["Ua fai mai le tasi ia te ia,", "The first said unto him,"], ["Ua ou faatau le fanua,", "I have bought a piece of ground,"], ["e tatau ona ou alu atu e matamata ai; se'i e faapea ,", "and I must needs go and see it:"], ["ia tuu mai ia te au.", "I pray thee have me excused."]]},
  {num:19,words:[["Ua fai mai foi le tasi,", "And another said,"], ["Ua ou faatau povi e lima ni tailua,", "I have bought five yoke of oxen,"], ["ou te alu e faataitai i ai; se'i e faapea ,", "and I go to prove them:"], ["ia tuu mai ia te au.", "I pray thee have me excused."]]},
  {num:20,words:[["Ua fai mai foi le tasi,", "And another said,"], ["Ua ou fai avā;", "I have married a wife,"], ["o le mea lea ou te le mafai ai ona alu.", "and therefore I cannot come."]]},
  {num:21,words:[["Ua alu atu lea auauna ua faamatala atu ia mea i lona alii. Ona ita ai lea o le matai o le aiga,", "So that servant came,"], ["ua fai atu ia i lana auauna,", "and shewed his lord these things. Then the master of the house being angry said to his servant,"], ["Ina alu ia ia vave i ala ma alātua o le aai,", "Go out quickly into the streets and lanes of the city,"], ["ma ia au mai iinei i e matitiva,", "and bring in hither the poor,"], ["ma e mumutu,", "and the maimed,"], ["ma e pipili,", "and the halt,"], ["atoa ma e tauaso.", "and the blind."]]},
  {num:22,words:[["Ona fai mai lea o le auauna,", "And the servant said,"], ["Le alii e,", "Lord,"], ["ua uma ona faia o le mea na e poloai mai ai,", "it is done as thou hast commanded,"], ["a e lei nofoia le fale.", "and yet there is room."]]},
  {num:23,words:[["Ua fai atu le alii i le auauna,", "And the lord said unto the servant,"], ["Ina alu atu ia i ala tele ma magāala,", "Go out into the highways and hedges,"], ["ma ia pulunaunau atu latou te o mai,", "and compel them to come in,"], ["ina ia tumu lo'u nei fale.", "that my house may be filled."]]},
  {num:24,words:[["Auā ou te fai atu ia te outou, E leai lava se tasi o ia tagata e na tala'iina,", "For I say unto you,"], ["e 'ai i la'u talisuaga nei.", "That none of those men which were bidden shall taste of my supper."]]},
  {num:25,words:[["Ua o faatasi ma ia le motu o tagata e toatele;", "And there went great multitudes with him:"], ["ona fāliu lea o ia,", "and he turned,"], ["ma fetalai atu ia te i latou,", "and said unto them,"]]},
  {num:26,words:[["Afai e sau se tasi ia te au,", "If any man come to me,"], ["a e le 'ino'ino i lona tamā,", "and hate not his father,"], ["ma le tinā,", "and mother, and wife,"], ["ma le avā,", "and children,"], ["ma le fanau,", "and brethren,"], ["ma uso,", "and sisters, yea,"], ["ma tuafāfine e oo lava i lona ola,", "and his own life also,"], ["e le mafai ona fai o ia mo'u soo.", "he cannot be my disciple."]]},
  {num:27,words:[["O se le ave lona satauro,", "And whosoever doth not bear his cross,"], ["ma ua le mulimuli mai ia te au,", "and come after me,"], ["e le mafai ona fai o ia mo'u soo.", "cannot be my disciple."]]},
  {num:28,words:[["O ai foi so outou ua fia fai se 'olo,", "For which of you, intending to build a tower,"], ["e le muai nofo i lalo e faitau tupe e totogi a'i,", "sitteth not down first,"], ["po ua lava ana mea e faauma ai?", "and counteth the cost, whether he have sufficient to finish it?"]]},
  {num:29,words:[["ina nei tauemu mai ia te ia o tagata uma e maimoa,", "Lest haply,"], ["ina ua tuu le faavae,", "after he hath laid the foundation, and is not able to finish it,"], ["a e le mafai ona faauma ai,", "all that behold it begin to mock him,"]]},
  {num:30,words:[["e faapea mai,", "Saying,"], ["O le tagata lenei, na amata ona fai,", "This man began to build,"], ["a e lei mafai ona faauma.", "and was not able to finish."]]},
  {num:31,words:[["Po o ai le tupu, o le a alu atu e tau ma le tasi tupu,", "Or what king,"], ["e le muai nofo i lalo e filifili,", "going to make war against another king,"], ["pe mafai ia te ia ma ona tagata e sefulu afe,", "sitteth not down first,"], ["ona tau ma le ua sau e tau ma ia, ua ia te ia tagata e lua sefulu o afe?", "and consulteth whether he be able with ten thousand to meet him that cometh against him with twenty thousand?"]]},
  {num:32,words:[["pe afai e leai,", "Or else,"], ["e tuu atu e ia le sāvali,", "while the other is yet a great way off,"], ["manū o mamao ia,", "he sendeth an ambassage,"], ["e faatoga atu ia ola le taua.", "and desireth conditions of peace."]]},
  {num:33,words:[["E faapea foi so outou e le lafoai ana mea uma,", "So likewise, whosoever he be of you that forsaketh not all that he hath,"], ["e le mafai ona fai o ia mo'u soo.", "he cannot be my disciple."]]},
  {num:34,words:[["O le mea lelei le masima;", "Salt is good:"], ["a e afai e magalo le masina,", "but if the salt have lost his savour,"], ["pe se a se mea e faamāi a'i?", "wherewith shall it be seasoned?"]]},
  {num:35,words:[["E le aoga ia i le fanua,", "It is neither fit for the land,"], ["e le aoga foi e fai ma otaota e nasu a'i;", "nor yet for the dunghill;"], ["a ua lafoaiina i fafo. O lē ua i ai taliga e faalogo ai,", "but men cast it out. He that hath ears to hear,"], ["ina faalogo mai ia o ia.", "let him hear."]]},
];
renderVerseSet(luk_ch_14_Verses, 'luk-ch14-verses');

var luk_ch_15_Verses = [
  {num:1,words:[["Ua faalatalata ia te ia le au telona uma ma e agasala, e faalogologo ia te ia.", "Then drew near unto him all the publicans and sinners for to hear him."]]},
  {num:2,words:[["Ona muimui ai lea o le au faresaio ma le au tusiupu,", "And the Pharisees and scribes murmured,"], ["ua fapea ane,", "saying,"], ["Ua talia e lenei tagata o e agasala,", "This man receiveth sinners,"], ["ua aai faatasi foi o ia ma i latou.", "and eateth with them."]]},
  {num:3,words:[["Ona fetalai atu ai lea o ia lenei faataoto ia te i latou,", "And he spake this parable unto them,"], ["ua faapea atu,", "saying,"]]},
  {num:4,words:[["O ai ea so outou e ana mamoe e selau,", "What man of you,"], ["afai e le iloa le tasi,", "having an hundred sheep,"], ["e le tuua e ia le ivagafulu ma le iva i le vao,", "if he lose one of them, doth not leave the ninety and nine in the wilderness,"], ["a e alu ma saili i le na le iloa,", "and go after that which is lost,"], ["seia maua?", "until he find it?"]]},
  {num:5,words:[["A maua,", "And when he hath found it, he layeth it on his shoulders,"], ["ua faafuata ma le olioli.", "rejoicing."]]},
  {num:6,words:[["A oo atu foi i lona aiga,", "And when he cometh home,"], ["ua faapotopoto ai ana uo ma e tuaoi ma ia,", "he calleth together his friends and neighbours,"], ["ua fai atu ia te i latou,", "saying unto them,"], ["Ia tatou olioli ia;", "Rejoice with me;"], ["auā ua ou maua la'u mamoe na le iloa.", "for I have found my sheep which was lost."]]},
  {num:7,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["e faapea foi ona tele o le olioli i le lagi i le tagata agasala e toatasi e salamo,", "that likewise joy shall be in heaven over one sinner that repenteth, more than over ninety and nine just persons,"], ["a e itiiti i e amiotonu e toaivagafulu ma le toaiva e le tusa i ai le salamo.", "which need no repentance."]]},
  {num:8,words:[["O ai ea foi le fafine e ana tupe e fuagafulu,", "Either what woman having ten pieces of silver,"], ["afai e le iloa ia te ia le tasi tupe,", "if she lose one piece,"], ["e le tŭtŭ ea se afi, ma tafitafi le fale,", "doth not light a candle,"], ["ma matuā saili i ai,", "and sweep the house,"], ["seia maua?", "and seek diligently till she find it?"]]},
  {num:9,words:[["A maua,", "And when she hath found it,"], ["ua faapotopoto ai ana uo ma e tuaoi ma ia,", "she calleth her friends and her neighbours together,"], ["ua fai atu,", "saying,"], ["Ia tatou olioli ia;", "Rejoice with me;"], ["auā na ou maua le tupe na le iloa ia te au.", "for I have found the piece which I had lost."]]},
  {num:10,words:[["Ou te fai atu ia te outou,", "Likewise,"], ["ua faapea le olioli i luma o agelu a le Atua,", "I say unto you,"], ["ona o le tagata agasala e toatasi ua salamo.", "there is joy in the presence of the angels of God over one sinner that repenteth."]]},
  {num:11,words:[["Ua fetalai atu o ia,", "And he said,"], ["O le tasi tagata e toalua ona atalii.", "A certain man had two sons:"]]},
  {num:12,words:[["Ua fai atu le uii i lona tamā,", "And the younger of them said to his father,"], ["Sena e, ia e au mai ia te au lo'u tofi o le oa;", "Father,"], ["ona vaelua lea e ia o ana mea ia te i laua.", "give me the portion of goods that falleth to me. And he divided unto them his living."]]},
  {num:13,words:[["Ua mavae nai aso, ona faapotopoto ai lea e le uii mea uma,", "And not many days after the younger son gathered all together,"], ["ua alu malaga i le nuu mamao,", "and took his journey into a far country,"], ["ua faataapeape ai ana mea i lea nuu, ua soona ulavale.", "and there wasted his substance with riotous living."]]},
  {num:14,words:[["Ua uma atu ana mea,", "And when he had spent all,"], ["ona oge tele ai lea o lea nuu;", "there arose a mighty famine in that land;"], ["ona faatoa mativa ai lea o ia.", "and he began to be in want."]]},
  {num:15,words:[["Ua alu ia ua nofo i le tasi tagata o lea nuu,", "And he went and joined himself to a citizen of that country;"], ["ua ia auina foi o ia i ona fanua e fafaga ai puaa.", "and he sent him into his fields to feed swine."]]},
  {num:16,words:[["Ua tupu lona manao i atigi mea e 'aina e puaa ia maona ai o ia;", "And he would fain have filled his belly with the husks that the swine did eat:"], ["e leai lava se tasi ua avane sina mea ia te ia.", "and no man gave unto him."]]},
  {num:17,words:[["Ona atamai ai lea o ia,", "And when he came to himself,"], ["ua faapea ane,", "he said,"], ["E lē toatele ea o auauna a lo'u tamā ua faulai a latou areto ua totoe; a o au,", "How many hired servants of my father's have bread enough and to spare,"], ["ou te matelaina.", "and I perish with hunger!"]]},
  {num:18,words:[["O le a a'u tulai ma alu i lo'u tamā,", "I will arise and go to my father,"], ["ou te fai atu ia te ia,", "and will say unto him,"], ["Lo'u tamā e,", "Father,"], ["ua ou agasala i Lē o i le lagi,", "I have sinned against heaven,"], ["atoa ma ou luma;", "and before thee,"]]},
  {num:19,words:[["ua ou le toe aoga ona ta'ua o lou atalii;", "And am no more worthy to be called thy son:"], ["ia e avea a'u ia pei o se tasi o au auauna.", "make me as one of thy hired servants."]]},
  {num:20,words:[["Ona tulai lea o ia,", "And he arose,"], ["ua alu i lona tamā.", "and came to his father."], ["Ua iloa mamao atu foi o ia e lona tamā,", "But when he was yet a great way off,"], ["ona mutimuti vale lea o lona alofa,", "his father saw him,"], ["ua momo'e atu ia,", "and had compassion, and ran,"], ["ua fusi ia te ia,", "and fell on his neck,"], ["ma sogi atu ia te ia.", "and kissed him."]]},
  {num:21,words:[["A ua fai mai le atalii ia te ia,", "And the son said unto him,"], ["Lo'u tamā e,", "Father,"], ["ua ou agasala i Lē o i le lagi,", "I have sinned against heaven,"], ["atoa ma ou luma,", "and in thy sight,"], ["ua ou le toe aoga ona ta'ua o lou atalii.", "and am no more worthy to be called thy son."]]},
  {num:22,words:[["A ua fai atu le tamā i ana auauna,", "But the father said to his servants,"], ["Au mai ia le ofu tatapuvae e aupito lelei,", "Bring forth the best robe,"], ["ma faaofu ia te ia;", "and put it on him;"], ["ma ia tuu se mama i lona lima,", "and put a ring on his hand,"], ["ma faasee i ona vae;", "and shoes on his feet:"]]},
  {num:23,words:[["au mai ia foi le tamai povi peti,", "And bring hither the fatted calf,"], ["ma fasi;", "and kill it; and let us eat,"], ["tatou te aai ma olioli;", "and be merry:"]]},
  {num:24,words:[["auā o lo'u atalii lenei,", "For this my son was dead,"], ["na oti,", "and is alive again;"], ["ua toe ola mai; na le iloa foi o ia,", "he was lost,"], ["a ua maua.", "and is found."], ["Ona latou olioli ai lea.", "And they began to be merry."]]},
  {num:25,words:[["Sa i le vao lona atalii ulumatua; ua sau ia,", "Now his elder son was in the field:"], ["ua latalata mai i le fale,", "and as he came and drew nigh to the house,"], ["ona faalogo ai lea o ia i laaupese ua ta, ma le siva.", "he heard musick and dancing."]]},
  {num:26,words:[["Ua valaau atu ia i le tasi auauna, ua fesili atu,", "And he called one of the servants,"], ["po o le a le uiga o nei mea.", "and asked what these things meant."]]},
  {num:27,words:[["Ua fai mai o ia ia te ia,", "And he said unto him,"], ["Ua sau lou uso;", "Thy brother is come;"], ["ua fasi ai foi e lou tamā le tamai povi peti,", "and thy father hath killed the fatted calf,"], ["ina ua toe oo mai o ia o ola.", "because he hath received him safe and sound."]]},
  {num:28,words:[["Ona ita ai lea o ia,", "And he was angry,"], ["e le mafaia ona ulufale i ai;", "and would not go in:"], ["ona alu atu ai lea o lona tamā i fafo,", "therefore came his father out,"], ["ua faaoleole ia te ia.", "and intreated him."]]},
  {num:29,words:[["Ona tali mai ai lea o ia,", "And he answering said to his father,"], ["ua faapea mai i lona tamā. Faauta,", "Lo,"], ["o tausaga ua tele, ua ou auauna ai ia te oe,", "these many years do I serve thee,"], ["ua leai lava sau poloaiga ua ou solia;", "neither transgressed I at any time thy commandment:"], ["e te lei au mai lava se tamai 'oti ma a'u,", "and yet thou never gavest me a kid,"], ["matou te olioli ai ma a'u uo.", "that I might make merry with my friends:"]]},
  {num:30,words:[["Peitai o lou atalii lena,", "But as soon as this thy son was come,"], ["sa na faaumatia au mea faatasi ma fafine talitane, ua sau o ia,", "which hath devoured thy living with harlots,"], ["ona e fasi lea le tamai povi peti māna.", "thou hast killed for him the fatted calf."]]},
  {num:31,words:[["Ua fai atu ia ia te ia. Tā e,", "And he said unto him,"], ["ta te nonofo pea ma oe,", "Son,"], ["o a'u mea uma foi,", "thou art ever with me,"], ["o āu ia.", "and all that I have is thine."]]},
  {num:32,words:[["Ua tatau foi ona tatou fiafia ma olioli,", "It was meet that we should make merry,"], ["auā o lou uso lena na oti,", "and be glad:"], ["a ua toe ola mai;", "for this thy brother was dead, and is alive again;"], ["na le iloa foi,", "and was lost,"], ["a ua maua.", "and is found."]]},
];
renderVerseSet(luk_ch_15_Verses, 'luk-ch15-verses');

var luk_ch_16_Verses = [
  {num:1,words:[["Ua fetalai atu foi o ia i ona soo,", "And he said also unto his disciples,"], ["O le tasi tagata mauoa sa i ai le auauna e pule;", "There was a certain rich man,"], ["na molia o ia ia te ia,", "which had a steward;"], ["ua ia faamāumau ana mea.", "and the same was accused unto him that he had wasted his goods."]]},
  {num:2,words:[["Ua na valaau atu ia te ia,", "And he called him,"], ["ua fai atu i ai. O le a lenei mea ua ou faalogo ai ia te oe? Tala mai ia le tala i mea na e pule i ai;", "and said unto him, How is it that I hear this of thee? give an account of thy stewardship;"], ["auā ou te le mafai ona e toe fai ma auauna e pule.", "for thou mayest be no longer steward."]]},
  {num:3,words:[["Ona fai ifo ai lea o le auauna i lona loto,", "Then the steward said within himself,"], ["Se a se mea ou te faia? auā o le a faateaina a'u e lo'u alii i le faiva o auauna e pule;", "What shall I do? for my lord taketh away from me the stewardship:"], ["ou te le mafai ona eli;", "I cannot dig;"], ["ou te mā i faatoga.", "to beg I am ashamed."]]},
  {num:4,words:[["Ua ou iloa le mea ou te faia,", "I am resolved what to do,"], ["ina ia talia a'u i o latou aiga,", "that, when I am put out of the stewardship,"], ["pe a tuueseina a'u i le faiva o auauna e pule.", "they may receive me into their houses."]]},
  {num:5,words:[["Ona amiami lea e ia o tagata taitasi uma e na i ai mea a lona alii,", "So he called every one of his lord's debtors unto him,"], ["ua fai atu ia i le tasi,", "and said unto the first,"], ["Pe fia mea a lo'u alii ua ia te oe?", "How much owest thou unto my lord?"]]},
  {num:6,words:[["Ona fai mai ai lea o ia,", "And he said,"], ["O paita o suāuu e selau. Ua fai atu ia ia te ia,", "An hundred measures of oil. And he said unto him,"], ["Ina tago ia i lau tusi,", "Take thy bill,"], ["ia vave nofo i lalo,", "and sit down quickly,"], ["ma tusi e lima sefulu.", "and write fifty."]]},
  {num:7,words:[["Ona fai atu lea o ia i le tasi,", "Then said he to another,"], ["Pe fia mea ua ia te oe? Ua fai mai o ia. O kori o saito e selau. Ona fai atu lea o ia ia te ia,", "And how much owest thou? And he said,"], ["Ina tago ia i lau tusi,", "An hundred measures of wheat. And he said unto him, Take thy bill,"], ["ma tusi e valu sefulu.", "and write fourscore."]]},
  {num:8,words:[["Ua vivii atu le alii i le auauna amioletonu, auā ua na togafiti poto;", "And the lord commended the unjust steward,"], ["auā e sili le poto o tagata o le olaga nei,", "because he had done wisely:"], ["i lo latou tupulaga, i lo tagata o le malamalama.", "for the children of this world are in their generation wiser than the children of light."]]},
  {num:9,words:[["Ou te fai atu foi ia te outou,", "And I say unto you,"], ["O le mamone o le amioletonu ia outou fai ai uo mā outou,", "Make to yourselves friends of the mammon of unrighteousness;"], ["ina ia latou talia mai outou i fale e faavavau,", "that, when ye fail,"], ["pe a tuueseina outou.", "they may receive you into everlasting habitations."]]},
  {num:10,words:[["O lē faamaoni i le mea itiiti, e faamaoni foi o ia i mea e tele;", "He that is faithful in that which is least is faithful also in much:"], ["o lē amioletonu i le mea itiiti, e amioletonu foi o ia i mea e tele.", "and he that is unjust in the least is unjust also in much."]]},
  {num:11,words:[["Afai foi tou te lei faamaoni i le mamone o le amioletonu,", "If therefore ye have not been faithful in the unrighteous mammon,"], ["o ai se na te tuu atu ia te outou le oa moni e tausi?", "who will commit to your trust the true riches?"]]},
  {num:12,words:[["Afai foi ua outou le faamaoni i mea a le tagata ese,", "And if ye have not been faithful in that which is another man's,"], ["o ai se na te tuu atu ia te outou a outou lava mea?", "who shall give you that which is your own?"]]},
  {num:13,words:[["E le mafai se auauna ona auauna i alii e toalua;", "No servant can serve two masters:"], ["auā e 'ino'ino o ia i le tasi,", "for either he will hate the one,"], ["a e alofa atu i le tasi; a le o lea,", "and love the other;"], ["e faapipii atu ia i le tasi,", "or else he will hold to the one,"], ["a e faaleaoga i le tasi.", "and despise the other."], ["Tou te le mafaia ona auauna i le Atua atoa ma mamone.", "Ye cannot serve God and mammon."]]},
  {num:14,words:[["Ua faalogo le au faresaio i ia mea uma,", "And the Pharisees also,"], ["o i latou foi ua matapeapea;", "who were covetous, heard all these things:"], ["ona latou tauemu ai lea ia te ia.", "and they derided him."]]},
  {num:15,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["O outou ua faafiaamiotonu outou i luma o tagata;", "Ye are they which justify yourselves before men;"], ["a ua silafia e le Atua o outou loto; auā o le mea e sili ona lelei i tagata,", "but God knoweth your hearts:"], ["e inosia lea i luma o le Atua.", "for that which is highly esteemed among men is abomination in the sight of God."]]},
  {num:16,words:[["O le tulafono ma le au perofeta na oo lava ia ia Ioane;", "The law and the prophets were until John:"], ["talu ai ia ona po ua folafolaina le tala lelei o le malo o le Atua,", "since that time the kingdom of God is preached,"], ["ua taufaoa foi e tagata uma.", "and every man presseth into it."]]},
  {num:17,words:[["E mavaegofie atu le lagi ma le lalolagi,", "And it is easier for heaven and earth to pass,"], ["a e le iuvale sina fāsi mataitusi e tasi o le tulafono.", "than one tittle of the law to fail."]]},
  {num:18,words:[["O sē faatea i lana avā,", "Whosoever putteth away his wife,"], ["a e fai avā i se tasi,", "and marrieth another,"], ["o le mulilua lea; o sē fai avā i le ua faateaina e lana tane,", "committeth adultery:"], ["o le mulilua foi lea.", "and whosoever marrieth her that is put away from her husband committeth adultery."]]},
  {num:19,words:[["O le tasi tagata mauoa,", "There was a certain rich man,"], ["ua ofu i le ofu pāuli, ma le ie vavae,", "which was clothed in purple and fine linen,"], ["ua taileleiia lava ia i aso uma.", "and fared sumptuously every day:"]]},
  {num:20,words:[["O le tasi tagata mativa foi e igoa ia Lasalo,", "And there was a certain beggar named Lazarus,"], ["ua taatia i lona faitotoa,", "which was laid at his gate,"], ["ua lilo i le papala,", "full of sores,"]]},
  {num:21,words:[["ua manao tele ia e 'ai momoi mea na pauu ifo i le laoai a le mauoa;", "And desiring to be fed with the crumbs which fell from the rich man's table:"], ["a ua o mai ulī ua etoeto ona papala.", "moreover the dogs came and licked his sores."]]},
  {num:22,words:[["Ua oo foi ina oti o le tagata mativa,", "And it came to pass, that the beggar died,"], ["ona avea lea o ia e agelu i le fatafata o Aperaamo. Ua oti foi le mauoa,", "and was carried by the angels into Abraham's bosom:"], ["ma ua tanu;", "the rich man also died, and was buried;"]]},
  {num:23,words:[["ua i seoli na faataugaina,", "And in hell he lift up his eyes,"], ["ona tepa ae ai lea o ia,", "being in torments, and seeth Abraham afar off,"], ["ua na iloa mamao atu ia Aperaamo ma Lasalo i lona fatafata;", "and Lazarus in his bosom."]]},
  {num:24,words:[["ua alaga atu foi o ia,", "And he cried and said,"], ["ua fai atu, Lo'u tamā e,", "Father Abraham,"], ["Aperaamo,", "have mercy on me,"], ["ia e alofa mai ia te au,", "and send Lazarus,"], ["ma ia e auina mai Lasalo,", "that he may dip the tip of his finger in water,"], ["na te fufui i le tumutumu o lona tamatamailima i se vai, e faamālulu a'i lo'u nei laulaufaiva;", "and cool my tongue;"], ["auā ua ou puapuaga i le mumū o le afi nei.", "for I am tormented in this flame."]]},
  {num:25,words:[["Ona fai ane lea o Aperaamo,", "But Abraham said,"], ["Lo'u atalii e, ia e manatu,", "Son,"], ["na e maua au mea lelei i lou olaga,", "remember that thou in thy lifetime receivedst thy good things,"], ["na maua foi e Lasalo o mea leaga;", "and likewise Lazarus evil things:"], ["a o lenei, ua faaolioliina ia;", "but now he is comforted,"], ["a ua puapuagaina oe.", "and thou art tormented."]]},
  {num:26,words:[["E le gata i nei mea uma,", "And beside all this,"], ["a ua tumau le vanu tele i lo tatou va;", "between us and you there is a great gulf fixed:"], ["o le mea lea e le masao ai o e ua iinei ua fia o atu ia te outou;", "so that they which would pass from hence to you cannot; neither can they pass to us,"], ["e le masao mai foi o e ua iina ia te i matou nei.", "that would come from thence."]]},
  {num:27,words:[["Ona fai atu lea o ia,", "Then he said,"], ["Lo'u tamā e,", "I pray thee therefore,"], ["ou te faatoga atu ia te oe,", "father,"], ["ina ia e auina atu o ia i le aiga o lo'u tamā;", "that thou wouldest send him to my father's house:"]]},
  {num:28,words:[["auā e toalima o'u uso;", "For I have five brethren;"], ["ina ia molitino atu ia ia te i latou,", "that he may testify unto them,"], ["ne'i latou o mai foi i lenei mea puapuaga.", "lest they also come into this place of torment."]]},
  {num:29,words:[["Ua fai ane Aperaamo ia te ia,", "Abraham saith unto him,"], ["O ia te i latou Mose ma le au perofeta,", "They have Moses and the prophets;"], ["ia latou faalogo i ai.", "let them hear them."]]},
  {num:30,words:[["A ua faapea atu ia,", "And he said,"], ["Lo'u tamā e,", "Nay,"], ["Aperaamo, aua;", "father Abraham:"], ["a e afai e alu atu se tasi ia te i latou nai e ua oti,", "but if one went unto them from the dead,"], ["e salamo ai i latou.", "they will repent."]]},
  {num:31,words:[["Ua fai ane o ia ia te ia,", "And he said unto him,"], ["Pe afai latou te le faalogo ia Mose ma le au perofeta,", "If they hear not Moses and the prophets,"], ["e ui lava ina tu mai se tasi nai e ua oti,", "neither will they be persuaded,"], ["latou te le mafafai lava.", "though one rose from the dead."]]},
];
renderVerseSet(luk_ch_16_Verses, 'luk-ch16-verses');

var luk_ch_17_Verses = [
  {num:1,words:[["Ua fetalai atu o ia i le au soo,", "Then said he unto the disciples,"], ["E le mafai lava ona le oo mai o mea e tausuai ai;", "It is impossible but that offences will come: but woe unto him,"], ["oi talofa foi i le e oo mai ai.", "through whom they come!"]]},
  {num:2,words:[["E lelei pe ana noatia i lona ua se maaolo tele,", "It were better for him that a millstone were hanged about his neck,"], ["i le lafo ai o ia i le sami,", "and he cast into the sea,"], ["a e leaga lava ona faatausuaiina e ia so latou nei e faatauvaa.", "than that he should offend one of these little ones."]]},
  {num:3,words:[["Ia outou ia te outou. Pe afai a e agaleaga mai lou uso ia te oe,", "Take heed to yourselves:"], ["ia e aoai atu ia te ia;", "If thy brother trespass against thee,"], ["pe afai e salamo ia,", "rebuke him; and if he repent,"], ["ia e faamagalo atu ia te ia.", "forgive him."]]},
  {num:4,words:[["Pe afai e foi faafitu i le aso ona agaleaga mai o ia ia te oe,", "And if he trespass against thee seven times in a day,"], ["ma foi faafitu i le aso ona liliu mai ia te oe,", "and seven times in a day turn again to thee,"], ["ua faapea mai,", "saying,"], ["Ua ou salamo;", "I repent;"], ["ia e faamagalo atu ia te ia.", "thou shalt forgive him."]]},
  {num:5,words:[["Ona fai mai lea o le au aposetolo i le Alii,", "And the apostles said unto the Lord,"], ["Ia e faatuputeleina lo matou faatuatua.", "Increase our faith."]]},
  {num:6,words:[["Ua fetalai atu le Alii,", "And the Lord said,"], ["Afai ua tusa lo outou faatuatua ma le fua o le sinapi,", "If ye had faith as a grain of mustard seed,"], ["po ua outou fai atu i lenei sukamina,", "ye might say unto this sycamine tree,"], ["Ia liaiina oe,", "Be thou plucked up by the root,"], ["ma ia totōina i le sami;", "and be thou planted in the sea;"], ["ona anaana mai lava lea ia te outou.", "and it should obey you."]]},
  {num:7,words:[["O ai foi so outou e ana le auauna o suatia le eleele,", "But which of you,"], ["po o leoleo i mamoe,", "having a servant plowing or feeding cattle,"], ["e fai atu ea, pe a sau o ia mai le vao,", "will say unto him by and by,"], ["Sau loa ia,", "when he is come from the field,"], ["ina taoto e 'ai?", "Go and sit down to meat?"]]},
  {num:8,words:[["a e le fai atu ea ia te ia,", "And will not rather say unto him,"], ["Ina sauni mai ia sa'u sua,", "Make ready wherewith I may sup,"], ["ma ia fusi ou ofu, i le laulau mai o mea,", "and gird thyself,"], ["se'i 'ai ae a'u ma inu;", "and serve me,"], ["a mavae lea,", "till I have eaten and drunken;"], ["i le 'ai ai oe ma inu?", "and afterward thou shalt eat and drink?"]]},
  {num:9,words:[["E faafetai atu ea ia i lea auauna, ina ua fai mea na fai atu ai ia te ia?", "Doth he thank that servant because he did the things that were commanded him? I trow not."]]},
  {num:10,words:[["Ai lava e leai. E faapea foi outou,", "So likewise ye,"], ["pe a uma ona fai o mea uma na poloaiina atu ia te outou,", "when ye shall have done all those things which are commanded you,"], ["tou te fai ane, O auauna le aoga i matou nei;", "say,"], ["auā o mea e tatau ona matou fai,", "We are unprofitable servants:"], ["o mea ia ua matou faia.", "we have done that which was our duty to do."]]},
  {num:11,words:[["Ua lau malaga atu ia i Ierusalema,", "And it came to pass, as he went to Jerusalem,"], ["ua ui ai i Samaria ma Kalilaia.", "that he passed through the midst of Samaria and Galilee."]]},
  {num:12,words:[["Ua oo atu ia i le tasi aai,", "And as he entered into a certain village,"], ["ona fetaiai lea ma ia o tagata lepela e toatinoagafulu,", "there met him ten men that were lepers,"], ["ua tutū mamao mai i latou.", "which stood afar off:"]]},
  {num:13,words:[["Ua latou alalaga mai,", "And they lifted up their voices,"], ["ua faapea mai,", "and said,"], ["Le Alii e,", "Jesus,"], ["Iesu,", "Master,"], ["ia e alofa mai ia te i matou.", "have mercy on us."]]},
  {num:14,words:[["Ua silafia e ia,", "And when he saw them,"], ["ona fetalai atu lea o ia ia te i latou, Ina o ia,", "he said unto them,"], ["ia faaali atu outou i faitaulaga.", "Go shew yourselves unto the priests."], ["Ua latou o,", "And it came to pass, that,"], ["ona faamamāina lea o i latou.", "as they went, they were cleansed."]]},
  {num:15,words:[["O le tasi o i latou,", "And one of them,"], ["ua na iloa ua faamaloloina ia,", "when he saw that he was healed,"], ["ona toe foi mai lea o ia,", "turned back,"], ["ua vivii atu i le Atua ma le leo tele;", "and with a loud voice glorified God,"]]},
  {num:16,words:[["ua faapaū fao ia i ona vae,", "And fell down on his face at his feet,"], ["ua faafetai mai ia te ia;", "giving him thanks:"], ["o le Samaria foi o ia.", "and he was a Samaritan."]]},
  {num:17,words:[["Ona fetalai atu lea o Iesu, ua faapea atu,", "And Jesus answering said,"], ["E lei faamamāina ea le toatinoagafulu? a o ifea le toaiva?", "Were there not ten cleansed? but where are the nine?"]]},
  {num:18,words:[["Ua le iloa ni e toe foi mai e vivii atu i le Atua,", "There are not found that returned to give glory to God,"], ["na o lenei tagata ese.", "save this stranger."]]},
  {num:19,words:[["Ua fetalai atu o ia ia te ia,", "And he said unto him,"], ["Ina tulai ia,", "Arise,"], ["ina alu;", "go thy way:"], ["ua e ola i lou faatuatua.", "thy faith hath made thee whole."]]},
  {num:20,words:[["Ua fesili mai ia te ia le au faresaio,", "And when he was demanded of the Pharisees,"], ["Pe oo mai afea le malo o le Atua? Ua tali atu ia ia te i latou,", "when the kingdom of God should come,"], ["ua faapea atu,", "he answered them and said,"], ["E le oo mai le malo o le Atua ma le vaaia e mata.", "The kingdom of God cometh not with observation:"]]},
  {num:21,words:[["E le fai ane foi tagata,", "Neither shall they say,"], ["Faauta,", "Lo here! or,"], ["o iinei! pe faapea , Faauta,", "lo there! for,"], ["o iila! auā faauta,", "behold,"], ["ua i ai lava ia te outou le malo o le Atua.", "the kingdom of God is within you."]]},
  {num:22,words:[["Ua fetalai atu ia i le au soo,", "And he said unto the disciples,"], ["E oo mai lava ona po tou te mananao tele ai ia iloa se aso e tasi o le Atalii o le tagata,", "The days will come, when ye shall desire to see one of the days of the Son of man,"], ["a e le iloa.", "and ye shall not see it."]]},
  {num:23,words:[["A fai mai tagata ia te outou,", "And they shall say to you,"], ["Faauta o iinei;", "See here;"], ["pe faapea ,", "or,"], ["Faauta o iila;", "see there:"], ["aua tou te o i ai,", "go not after them,"], ["pe mulimuli atu i ai.", "nor follow them."]]},
  {num:24,words:[["Auā e pei ona emo mai o le uila mai le tasi itu lagi,", "For as the lightning,"], ["e malamalama atu i le tasi ita lagi;", "that lighteneth out of the one part under heaven, shineth unto the other part under heaven;"], ["e faapea foi le Atalii o le tagata i lona aso.", "so shall also the Son of man be in his day."]]},
  {num:25,words:[["A e tatau ona muai tiga o ia i mea e tele,", "But first must he suffer many things,"], ["ma lafoaiina e lenei tupulaga.", "and be rejected of this generation."]]},
  {num:26,words:[["Pei ona faia foi i ona aso o Noa,", "And as it was in the days of Noe,"], ["e faapea lava ona fai i ona aso o le Atalii o le tagata.", "so shall it be also in the days of the Son of man."]]},
  {num:27,words:[["Na aai i latou ma inu,", "They did eat,"], ["na latou fai avā foi ma latou faaavaga,", "they drank, they married wives,"], ["ua oo lava i le aso na ulu ai Noa i le vaa,", "they were given in marriage,"], ["ona oo mai ai lea o le lolo,", "until the day that Noe entered into the ark, and the flood came,"], ["ua fano ai i latou uma.", "and destroyed them all."]]},
  {num:28,words:[["E pei ona faia foi i ona aso o Lota;", "Likewise also as it was in the days of Lot;"], ["ua latou aai,", "they did eat,"], ["ua inu,", "they drank,"], ["ua faatau,", "they bought,"], ["ua avane e faatau,", "they sold,"], ["ua totō mea,", "they planted,"], ["ma fai fale;", "they builded;"]]},
  {num:29,words:[["a o lea lava aso na alu ese ai Lota i Sotoma, ua to faaua mai le afi ma le teio mai le lagi,", "But the same day that Lot went out of Sodom it rained fire and brimstone from heaven,"], ["ua fano ai i latou uma.", "and destroyed them all."]]},
  {num:30,words:[["E faapea lava i le aso e faaalia mai ai le Atalii o le tagata.", "Even thus shall it be in the day when the Son of man is revealed."]]},
  {num:31,words:[["O le ua i luga o le fale i lea aso,", "In that day,"], ["ma ana mea ua i le fale,", "he which shall be upon the housetop,"], ["aua le alu ifo ia e ave;", "and his stuff in the house, let him not come down to take it away:"], ["e faapea foi le ua i le vao,", "and he that is in the field,"], ["aua le toe foi mai o ia.", "let him likewise not return back."]]},
  {num:32,words:[["Ia outou manatua le avā a Lota.", "Remember Lot's wife."]]},
  {num:33,words:[["O sē saili ia saogalemu lona ola, e māumau ai ia te ia;", "Whosoever shall seek to save his life shall lose it;"], ["a o sē faamāumau ai, e faasaoina e ia.", "and whosoever shall lose his life shall preserve it."]]},
  {num:34,words:[["Ou te fai atu ia te outou,", "I tell you,"], ["O lea lava po,", "in that night there shall be two men in one bed;"], ["e i le moega e tasi tagata e toalua; e avea le tasi,", "the one shall be taken,"], ["a e tuua le tasi.", "and the other shall be left."]]},
  {num:35,words:[["E olo faatasi fafine e toalua;", "Two women shall be grinding together;"], ["e avea le tasi,", "the one shall be taken,"], ["a e tuua le ta i.", "and the other left."]]},
  {num:36,words:[["E i le vao tagata e toalua;", "Two men shall be in the field;"], ["e avea le tasi,", "the one shall be taken,"], ["a e tuua le tasi.", "and the other left."]]},
  {num:37,words:[["Ua latou fai mai ia te ia,", "And they answered and said unto him,"], ["ua faapea mai. Le Alii e,", "Where,"], ["po o fea e fai ai? Ua fetalai atu ia ia te i latou,", "Lord? And he said unto them,"], ["O le mea o i ai le tino,", "Wheresoever the body is,"], ["e aofaga i ai aeto.", "thither will the eagles be gathered together."]]},
];
renderVerseSet(luk_ch_17_Verses, 'luk-ch17-verses');

var luk_ch_18_Verses = [
  {num:1,words:[["Ua fetalai atu foi o ia le faataoto ia te i latou,", "And he spake a parable unto them to this end,"], ["ina ia tatalo soo e tatau ai,", "that men ought always to pray,"], ["a e aua le faavaivai;", "and not to faint;"]]},
  {num:2,words:[["ua faapea atu,", "Saying,"], ["Sa i le tasi aai le faamasino,", "There was in a city a judge,"], ["ua le mata'u i le Atua,", "which feared not God,"], ["e le ava foi i tagata;", "neither regarded man:"]]},
  {num:3,words:[["sa i lea aai foi le tasi fafine ua oti lana tane,", "And there was a widow in that city;"], ["ua alu atu ia te ia,", "and she came unto him,"], ["ua faapea atu,", "saying,"], ["Ia e faamasino atu i le ua i ai a'u mea.", "Avenge me of mine adversary."]]},
  {num:4,words:[["O nai aso e lei mafai ai o ia;", "And he would not for a while:"], ["a e mulimuli ane ua faapea ifo o ia i lona loto,", "but afterward he said within himself,"], ["E ui lava ina ou le mata'u i le Atua,", "Though I fear not God,"], ["ma a'u le ava i tagata,", "nor regard man;"]]},
  {num:5,words:[["a e peitai ona o le faasoesa mai ia te au o le fafine nei ua oti lana tane,", "Yet because this widow troubleth me,"], ["ou te faamasino i ana mea,", "I will avenge her,"], ["ina ne'i faatiga mai ia te au i lona sau soo.", "lest by her continual coming she weary me."]]},
  {num:6,words:[["Ona fetalai atu ai lea o le Alii,", "And the Lord said,"], ["Ia outou faalogo mai i le upu a le faamasino amioletonu.", "Hear what the unjust judge saith."]]},
  {num:7,words:[["E ui lava ina tuai mai le Atua i e na ia filifilia,", "And shall not God avenge his own elect,"], ["o loo alalaga i latou ia te ia i le ao ma le po,", "which cry day and night unto him,"], ["pe le faamasino ea o ia i a latou mea?", "though he bear long with them?"]]},
  {num:8,words:[["Ou te fai atu ia te outou, e vave ona faamasino e ia o a latou mea.", "I tell you that he will avenge them speedily."], ["Peitai a sau le Atalii o le tagata,", "Nevertheless when the Son of man cometh,"], ["e iloga ea e maua e ia le faatuatua i le lalolagi.", "shall he find faith on the earth?"]]},
  {num:9,words:[["Ua fetalai atu foi o ia lenei faataoto i nisi tagata e na faatuatua ia te i latou fa'i ua amiotonu,", "And he spake this parable unto certain which trusted in themselves that they were righteous,"], ["a e faaleaogaina nisi;", "and despised others:"]]},
  {num:10,words:[["Na o ae i le malumalu tagata e toalua e tatalo,", "Two men went up into the temple to pray;"], ["o le faresaio le tasi,", "the one a Pharisee,"], ["a o le telona le tasi.", "and the other a publican."]]},
  {num:11,words:[["Na tulai le faresaio,", "The Pharisee stood and prayed thus with himself,"], ["ua tatalo lemu atu i nei upu,", "God,"], ["Le Atua e,", "I thank thee,"], ["ou te faafetai atu ia te oe,", "that I am not as other men are,"], ["ina ua ou le pei o isi tagata, o e fao mea,", "extortioners,"], ["o e amio leaga,", "unjust,"], ["o e mulilulua,", "adulterers,"], ["e le pei o lela telona foi.", "or even as this publican."]]},
  {num:12,words:[["E tailua i vaiasosa ona ou anapogi,", "I fast twice in the week,"], ["ou te avatu mea e sefulu a'i mea uma ou te maua.", "I give tithes of all that I possess."]]},
  {num:13,words:[["O le telona foi,", "And the publican,"], ["ua tu mamao atu,", "standing afar off,"], ["e le mafaia ona tepa ae ona mata i le lagi, a ua pōpō lona fatafata,", "would not lift up so much as his eyes unto heaven,"], ["ua faapea atu,", "but smote upon his breast,"], ["Le Atua e,", "saying,"], ["ia e alofa mai ia te au le tagata agasala.", "God be merciful to me a sinner."]]},
  {num:14,words:[["Ou te fai atu ia te outou, na alu ifo lena tagata i lona fale ua ta'uamiotonuina,", "I tell you,"], ["a e le faapea le isi; auā o sē faamaualuga ia te ia,", "this man went down to his house justified rather than the other:"], ["e faamaulaloina lea;", "for every one that exalteth himself shall be abased;"], ["a o lē faamaulalo ia te ia, e faamaualugaina lea.", "and he that humbleth himself shall be exalted."]]},
  {num:15,words:[["Ua latou au mai tama meamea ia te ia,", "And they brought unto him also infants,"], ["ina ia pa'i ane o ia ia te i latou;", "that he would touch them:"], ["ua iloa e le au soo,", "but when his disciples saw it,"], ["ona latou vavao lea ia te i latou.", "they rebuked them."]]},
  {num:16,words:[["A o Iesu,", "But Jesus called them unto him,"], ["ua valaau atu o ia ia te i latou,", "and said,"], ["ua faapea atu, Ina tuu mai ia o tama iti e o mai ia te au,", "Suffer little children to come unto me,"], ["a e aua tou te vavao ia te i latou;", "and forbid them not:"], ["auā e faapei o i latou nei o e o i le malo o le Atua.", "for of such is the kingdom of God."]]},
  {num:17,words:[["E moni, ou te fai atu ia te outou,", "Verily I say unto you,"], ["Ai se le tali i le malo o le Atua e pei o se tama itiiti, e le sao lava ia i ai.", "Whosoever shall not receive the kingdom of God as a little child shall in no wise enter therein."]]},
  {num:18,words:[["Ua fesili mai foi ia te ia le tasi alii,", "And a certain ruler asked him,"], ["ua faapea mai,", "saying,"], ["Le a'oa'o lelei e, se a le mea ou te faia,", "Good Master,"], ["ou te maua ai le ola e faavavau?", "what shall I do to inherit eternal life?"]]},
  {num:19,words:[["A ua fetalai atu Iesu ia te ia,", "And Jesus said unto him,"], ["Se a le mea e te ta'ulelei mai ai a'u? e leai sē lelei,", "Why callest thou me good? none is good,"], ["na o le toatasi,", "save one, that is,"], ["o le Atua lea.", "God."]]},
  {num:20,words:[["Ua e iloa poloaiga,", "Thou knowest the commandments,"], ["Aua e te mulilua;", "Do not commit adultery,"], ["aua e te fasioti;", "Do not kill,"], ["aua e te gaoi;", "Do not steal,"], ["aua e te molimau pepelo;", "Do not bear false witness,"], ["ia e ava i lou tamā ma lou tinā.", "Honour thy father and thy mother."]]},
  {num:21,words:[["Ona fai mai lea o ia,", "And he said,"], ["Ua ou tausia ia mea uma talu lava ina ou itiiti.", "All these have I kept from my youth up."]]},
  {num:22,words:[["Ua faafofoga Iesu i ia upu,", "Now when Jesus heard these things,"], ["ona fetalai atu lea ia te ia,", "he said unto him,"], ["Ua toe o le mea e tasi e te lei maua;", "Yet lackest thou one thing:"], ["ia e faatau atu i au mea uma,", "sell all that thou hast,"], ["ma ia e tufatufaina i e matitiva,", "and distribute unto the poor,"], ["ona ia te oe lea o le faulaigāoloa i le lagi;", "and thou shalt have treasure in heaven:"], ["i le e sau,", "and come,"], ["ma mulimuli mai ia te au.", "follow me."]]},
  {num:23,words:[["Ua faalogo o ia i na upu,", "And when he heard this,"], ["ona tiga tele ai lea o ia;", "he was very sorrowful:"], ["auā o le mauoa tele lava ia.", "for he was very rich."]]},
  {num:24,words:[["Ua silafia e Iesu o ia ua tiga tele ona fetalai atu lea o ia,", "And when Jesus saw that he was very sorrowful, he said,"], ["O le mea faigata nauā ona sao atu o e mauoa i le malo o le Atua!", "How hardly shall they that have riches enter into the kingdom of God!"]]},
  {num:25,words:[["E faigofie ona ui atu o le kamela i le pu o le au,", "For it is easier for a camel to go through a needle's eye,"], ["a e faigata ona sao atu o le mauoa i le malo o le Atua.", "than for a rich man to enter into the kingdom of God."]]},
  {num:26,words:[["O e na faalogo i ai ua fai mai, Afai o lea,", "And they that heard it said,"], ["o ai se tasi e mafai ona faaolaina?", "Who then can be saved?"]]},
  {num:27,words:[["Ua fetalai atu ia, O mea e le mafaia e tagata,", "And he said,"], ["e mafaia e le Atua.", "The things which are impossible with men are possible with God."]]},
  {num:28,words:[["Ona fai mai lea o Peteru,", "Then Peter said,"], ["Faauta,", "Lo,"], ["ua matou tuua mea uma,", "we have left all,"], ["a e matou mulimuli atu ia te oe.", "and followed thee."]]},
  {num:29,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou,", "There is no man that hath left house,"], ["Ai se tagata ua tuua e ia le fale,", "or parents,"], ["po o mātua, po o uso,", "or brethren,"], ["po o le avā,", "or wife,"], ["po o le fanau,", "or children,"], ["ona o le malo o le Atua,", "for the kingdom of God's sake,"]]},
  {num:30,words:[["e maua e ia o mea sautualasi i nei ona po,", "Who shall not receive manifold more in this present time,"], ["o le ola foi e faavavau i le olaga atali.", "and in the world to come life everlasting."]]},
  {num:31,words:[["Ua ave e ia le toasefulu ma le toalua,", "Then he took unto him the twelve,"], ["ua fetalai ia te i latou,", "and said unto them,"], ["Faauta,", "Behold,"], ["o le a o ae i tatou i Ierusalema,", "we go up to Jerusalem,"], ["e taunuu ai o mea uma ua tusia e le au perofeta i le Atalii o le tagata.", "and all things that are written by the prophets concerning the Son of man shall be accomplished."]]},
  {num:32,words:[["Auā e tuuina atu ia i nuu ese,", "For he shall be delivered unto the Gentiles,"], ["e faatauemuina,", "and shall be mocked,"], ["e faaleagaina,", "and spitefully entreated,"], ["e feanu foi i latou ia te ia,", "and spitted on:"]]},
  {num:33,words:[["latou te sasa foi ma fasioti ia te ia;", "And they shall scourge him, and put him to death:"], ["a o le aso tolu e toe tu mai ai o ia.", "and the third day he shall rise again."]]},
  {num:34,words:[["E lei lagona lava e i latou ia mea;", "And they understood none of these things:"], ["ua lilo foi lena upu ia te i latou,", "and this saying was hid from them,"], ["e lei iloa e i latou o mea na fetalaia mai.", "neither knew they the things which were spoken."]]},
  {num:35,words:[["Ua latalata ia i Ieriko,", "And it came to pass, that as he was come nigh unto Jericho,"], ["a ua nofo i le auala le tasi tauaso o faatoga i mea:", "a certain blind man sat by the way side begging:"]]},
  {num:36,words:[["ua faalogo o ia i le motu o tagata ua savavali ane, ona fesili lea a ia,", "And hearing the multitude pass by,"], ["pe se a lea.", "he asked what it meant."]]},
  {num:37,words:[["Ua latou fai atu ia te ia,", "And they told him,"], ["o Iesu le Nasareta ua maliu ane.", "that Jesus of Nazareth passeth by."]]},
  {num:38,words:[["Ona alaga mai ai lea o ia,", "And he cried,"], ["ua faapea mai,", "saying,"], ["Iesu e,", "Jesus,"], ["le alo o Tavita,", "thou Son of David,"], ["ia e alofa mai ia te au.", "have mercy on me."]]},
  {num:39,words:[["Ua vavao ia te ia e na muamua,", "And they which went before rebuked him,"], ["ina ia faalologo o ia;", "that he should hold his peace:"], ["peitai o ia ua atili ai ona alaga,", "but he cried so much the more,"], ["Le alo o Tavita e,", "Thou Son of David,"], ["ia e alofa mai ia te au.", "have mercy on me."]]},
  {num:40,words:[["Ua tu Iesu,", "And Jesus stood,"], ["ma fetalai atu ia ta'ita'iina mai o ia ia te ia. Ua latalata mai o ia,", "and commanded him to be brought unto him: and when he was come near,"], ["ona fesili atu lea o ia ia te ia,", "he asked him,"]]},
  {num:41,words:[["ua faapea atu,", "Saying,"], ["Se a le mea e te manao i ai ou te faia mo oe? Ua fai mai o ia,", "What wilt thou that I shall do unto thee? And he said,"], ["Le Alii e,", "Lord,"], ["ia vaai o'u nei mata.", "that I may receive my sight."]]},
  {num:42,words:[["Ona fetalai atu lea o Iesu ia te ia. Ina vaai ia ou mata;", "And Jesus said unto him, Receive thy sight:"], ["o lou faatuatua ua e ola ai.", "thy faith hath saved thee."]]},
  {num:43,words:[["Ona vaai loa lea o ona mata,", "And immediately he received his sight,"], ["ua mulimuli atu ia te ia,", "and followed him,"], ["ua vivii atu i le Atua;", "glorifying God: and all the people,"], ["ua iloa atu ai e le nuu uma,", "when they saw it,"], ["ona latou vivii atu lea i le Atua.", "gave praise unto God."]]},
];
renderVerseSet(luk_ch_18_Verses, 'luk-ch18-verses');

var luk_ch_19_Verses = [
  {num:1,words:[["Ua oo atu ia i Ieriko, ua ui ane i ai,", "And Jesus entered and passed through Jericho."]]},
  {num:2,words:[["faauta foi,", "And,"], ["o le tagata ua igoa ia Sakaio,", "behold,"], ["o ia o le telona sili,", "there was a man named Zacchaeus, which was the chief among the publicans,"], ["o le mauoa foi o ia.", "and he was rich."]]},
  {num:3,words:[["Ua fia maimoa o ia ia Iesu pe faapefea o ia;", "And he sought to see Jesus who he was;"], ["a e le mafaia ona o le motu o tagata;", "and could not for the press,"], ["auā o le tagata saasaa o ia.", "because he was little of stature."]]},
  {num:4,words:[["Ua momo'e ia i luma,", "And he ran before,"], ["ua ae i le laau o le sukamoru, e vaavaai ifo ai ia te ia;", "and climbed up into a sycomore tree to see him:"], ["auā o le a ui ane ai.", "for he was to pass that way."]]},
  {num:5,words:[["Ua oo atu Iesu i lea mea,", "And when Jesus came to the place,"], ["ona tepa ae lea o ia,", "he looked up,"], ["ua silafia o ia,", "and saw him,"], ["ona fetalai atu lea ia te ia,", "and said unto him, Zacchaeus,"], ["Sakaio e,", "make haste,"], ["ia e vave ifoifo ia i lalo,", "and come down;"], ["auā e tatau ona ou nofo i lou fale i le aso nei.", "for to day I must abide at thy house."]]},
  {num:6,words:[["Ona vave alu ifo ai lea o ia,", "And he made haste, and came down,"], ["ua tali mai ia te ia ma le fiafia.", "and received him joyfully."]]},
  {num:7,words:[["Ua muimui uma e na iloa,", "And when they saw it,"], ["ua faapea ane,", "they all murmured, saying,"], ["Ua alu atu ia i le tagata agasala e api ai.", "That he was gone to be guest with a man that is a sinner."]]},
  {num:8,words:[["A ua tu mai Sakaio,", "And Zacchaeus stood,"], ["ua faapea mai i le Alii,", "and said unto the Lord;"], ["Faauta,", "Behold,"], ["le Alii e,", "Lord,"], ["o le a ou vaeluaina atu a'u mea i e matitiva;", "the half of my goods I give to the poor;"], ["afai foi ua tiga se tasi i lo'u tuua'i ane,", "and if I have taken any thing from any man by false accusation,"], ["ou te taui atu ai e taifā.", "I restore him fourfold."]]},
  {num:9,words:[["Ua fetalai ane Iesu ia te ia,", "And Jesus said unto him,"], ["Ua oo mai le faaolataga i le aiga nei i le asō,", "This day is salvation come to this house,"], ["ina ua fai o ia ma atalii o Aperaamo.", "forsomuch as he also is a son of Abraham."]]},
  {num:10,words:[["Auā ua sau le Atalii o le tagata e saili ma faaola i le na le iloa.", "For the Son of man is come to seek and to save that which was lost."]]},
  {num:11,words:[["Ua latou faalogo i na mea,", "And as they heard these things,"], ["ona toe fetalai atu lea o ia i le faataoto,", "he added and spake a parable,"], ["ina ua latalata ia i Ierusalema,", "because he was nigh to Jerusalem,"], ["auā foi fa te i latou o le a faaalia loa mai le malo o le Atua.", "and because they thought that the kingdom of God should immediately appear."]]},
  {num:12,words:[["O lea foi ua fetalai atu ai o ia,", "He said therefore,"], ["Na alu le tasi alii i le nuu mamao e maua ai sona ao e fai ai o ia ma tupu,", "A certain nobleman went into a far country to receive for himself a kingdom,"], ["i le toe foi mai.", "and to return."]]},
  {num:13,words:[["Ua valaau e ia i ana auauna e toasefulu,", "And he called his ten servants,"], ["ua avatu ia te i latou mina e fuagafulu,", "and delivered them ten pounds,"], ["ua fai atu foi ia te i latou,", "and said unto them,"], ["tou te faatau a'i seia ou toe sau.", "Occupy till I come."]]},
  {num:14,words:[["A ua itagia o ia e lona nuu,", "But his citizens hated him,"], ["ua latou auina atu foi le sāvali e mulimuli atu ia te ia,", "and sent a message after him,"], ["ua faapea atu,", "saying,"], ["Matou te le mananao i lena tagata e fai mo matou tupu.", "We will not have this man to reign over us."]]},
  {num:15,words:[["Ua toe foi mai o ia ina ua maua lona ao e fai ai o ia ma tupu,", "And it came to pass, that when he was returned,"], ["ona fai ane ai lea,", "having received the kingdom,"], ["ia valaauina ia auauna na ia avatu i ai tupe ia o mai ia te ia,", "then he commanded these servants to be called unto him,"], ["ina ia iloa e ia taitasi a latou faatau po ua faapefea.", "to whom he had given the money, that he might know how much every man had gained by trading."]]},
  {num:16,words:[["Ona sau ai lea o le tasi,", "Then came the first,"], ["ua faapea mai,", "saying,"], ["Le alii e,", "Lord,"], ["o lau mina ua maua ai isi mina e fuagafulu.", "thy pound hath gained ten pounds."]]},
  {num:17,words:[["Ona fai atu lea o ia ia te ia,", "And he said unto him,"], ["Ua lelei ia,", "Well,"], ["le auauna lelei e,", "thou good servant:"], ["ua e faamaoni i le mea itiiti lava,", "because thou hast been faithful in a very little,"], ["o lea ia e pule ai i aai e sefulu.", "have thou authority over ten cities."]]},
  {num:18,words:[["Ua sau foi le tasi,", "And the second came,"], ["ua faapea mai,", "saying,"], ["Le alii e,", "Lord,"], ["o lau mina ua maua ai mina e lima gafua.", "thy pound hath gained five pounds."]]},
  {num:19,words:[["Ua fai atu foi o ia i lena,", "And he said likewise to him,"], ["Ina pule foi ia oe i aai e lima.", "Be thou also over five cities."]]},
  {num:20,words:[["Ua sau foi le tasi,", "And another came,"], ["ua faapea mai,", "saying,"], ["Le alii e,", "Lord,"], ["faauta,", "behold,"], ["o lau mina lenei,", "here is thy pound,"], ["sa ia te au na teu i le solosolo;", "which I have kept laid up in a napkin:"]]},
  {num:21,words:[["auā na ou mata'u lava ia te oe,", "For I feared thee,"], ["auā o oe le tagata faigata;", "because thou art an austere man:"], ["ua e avae le mea na e le tuuina i lalo,", "thou takest up that thou layedst not down,"], ["ua e selesele foi i le saito e te lei luluina.", "and reapest that thou didst not sow."]]},
  {num:22,words:[["Ona fai atu lea o ia ia te ia,", "And he saith unto him,"], ["Le auauna leaga e, o lau upu lava ou te faasala ai ia te oe;", "Out of thine own mouth will I judge thee,"], ["ua e iloa lava,", "thou wicked servant. Thou knewest that I was an austere man,"], ["o a'u o le tagata faigata, o lē avae le mea na ou le tuuina i lalo,", "taking up that I laid not down,"], ["o lē selesele foi i le saito na au le luluina.", "and reaping that I did not sow:"]]},
  {num:23,words:[["Se a le mea na e le avatu ai la'u ario i le fale e faatau ai tupe,", "Wherefore then gavest not thou my money into the bank,"], ["po ua ou sau ona ou maua ai lea atoa ma lona taui?", "that at my coming I might have required mine own with usury?"]]},
  {num:24,words:[["Ua fai atu ia i e na tutū mai,", "And he said unto them that stood by,"], ["Ia outou fao le mina ua ia te ia,", "Take from him the pound,"], ["ma avatu i le ua i ai mina e fuagafulu.", "and give it to him that hath ten pounds."]]},
  {num:25,words:[["(Ua latou fai mai ia te ia,", "(And they said unto him,"], ["Le alii e,", "Lord,"], ["ua ia te ia mina e fuagafulu.)", "he hath ten pounds.)"]]},
  {num:26,words:[["Auā ou te fai atu ia te outou,", "For I say unto you,"], ["O le o i ai mea,", "That unto every one which hath shall be given;"], ["e avatu i ai; a o le ua leai sana mea,", "and from him that hath not,"], ["e faoa mea ua ia te ia.", "even that he hath shall be taken away from him."]]},
  {num:27,words:[["Peitai o i latou ua fai a'u mo latou fili,", "But those mine enemies,"], ["e na le mafafai ona fai o a'u mo latou tupu,", "which would not that I should reign over them,"], ["ia outou ta'ita'i mai iinei,", "bring hither,"], ["ma fasioti ia te i latou i o'u luma.", "and slay them before me."]]},
  {num:28,words:[["Ua mavae atu ia upu ona muamua atu ai lea o ia,", "And when he had thus spoken, he went before,"], ["ua maliu ae i Ierusalema.", "ascending up to Jerusalem."]]},
  {num:29,words:[["Ua latalata i ai Petefake ma Petania i le mauga,", "And it came to pass,"], ["o Olive le igoa,", "when he was come nigh to Bethphage and Bethany, at the mount called the mount of Olives,"], ["ona aau atu lea e ia o ona soo e toalua,", "he sent two of his disciples,"]]},
  {num:30,words:[["ua faapea atu,", "Saying,"], ["Lua te o atu i le aai oulua o lumanai;", "Go ye into the village over against you;"], ["a oulua oo i ai, lua te iloa le tamai asini ua noatia,", "in the which at your entering ye shall find a colt tied,"], ["e lei tietie ai lava se tasi tagata,", "whereon yet never man sat:"], ["lua te talaina,", "loose him,"], ["i le ta'ita'i mai.", "and bring him hither."]]},
  {num:31,words:[["Afai foi e fesili mai se tasi ia te oulua,", "And if any man ask you,"], ["Se a le mea lua te tatala ai le asini? lua te fai atu ia te ia, ia faapea atu,", "Why do ye loose him? thus shall ye say unto him,"], ["E manao i ai le Alii.", "Because the Lord hath need of him."]]},
  {num:32,words:[["Ua o e na aauina atu, ona la maua ai lea,", "And they that were sent went their way,"], ["pei ona fetalai mai o ia ia te i laua.", "and found even as he had said unto them."]]},
  {num:33,words:[["O tatala e i laua le tamai asini ,", "And as they were loosing the colt,"], ["ua fai mai ia te i laua tagata e a latou le mea,", "the owners thereof said unto them,"], ["Se a le mea lua te tatala ai le tamai asini?", "Why loose ye the colt?"]]},
  {num:34,words:[["Ona la fai atu lea,", "And they said,"], ["E manao i ai le Alii.", "The Lord hath need of him."]]},
  {num:35,words:[["Ua la ta'ita'i mai i ai ia Iesu;", "And they brought him to Jesus:"], ["ua latou lafo o latou ofu i luga i le tamai asini ,", "and they cast their garments upon the colt,"], ["ona latou faatietie ai lea o Iesu.", "and they set Jesus thereon."]]},
  {num:36,words:[["O maliu ane ia,", "And as he went,"], ["a ua latou fofola o latou ofu i le ala.", "they spread their clothes in the way."]]},
  {num:37,words:[["Ua latalata ia ua i le ifoa'i o le mauga o Olive,", "And when he was come nigh,"], ["ona afua ai lea o le olioli o le au soo uma e toatele, ua latou vivii atu i le Atua ma le leo tele,", "even now at the descent of the mount of Olives,"], ["auā o vavega uma na vaaia e i latou;", "the whole multitude of the disciples began to rejoice and praise God with a loud voice for all the mighty works that they had seen;"]]},
  {num:38,words:[["ua faapea ane,", "Saying,"], ["Ia manuia le tupu o loo maliu mai i le suafa o le Alii;", "Blessed be the King that cometh in the name of the Lord:"], ["o le manuia i le lagi,", "peace in heaven,"], ["o le viiga foi i mea aupitoaluga.", "and glory in the highest."]]},
  {num:39,words:[["Ona fai mai lea ia te ia o isi o le au faresaio mai le motu o tagata,", "And some of the Pharisees from among the multitude said unto him,"], ["Le a'oa'o e,", "Master,"], ["ia e aoai atu i ou soo.", "rebuke thy disciples."]]},
  {num:40,words:[["Ona tali atu lea o ia ia te i latou,", "And he answered and said unto them,"], ["ua faapea atu,", "I tell you that,"], ["Ou te fai atu ia te outou, a le feganavai i latou nei,", "if these should hold their peace,"], ["e alalaga mai lava o maa.", "the stones would immediately cry out."]]},
  {num:41,words:[["Ua latalata ia,", "And when he was come near,"], ["ua silafia e ia le aai,", "he beheld the city,"], ["ona tagi ai lea o ia,", "and wept over it,"]]},
  {num:42,words:[["ua faapea ane,", "Saying,"], ["Ana e iloa,", "If thou hadst known,"], ["o oe lava i lenei lou lava aso,", "even thou, at least in this thy day,"], ["o mea e te manuia ai! A o lenei ua lilo ia te oe.", "the things which belong unto thy peace! but now they are hid from thine eyes."]]},
  {num:43,words:[["Auā e oo mai ia te oe ona aso e tanu ai le mea mautietie e sio ai ia te oe e i latou ua ita ia te oe,", "For the days shall come upon thee,"], ["latou te sioina lava ia te oe,", "that thine enemies shall cast a trench about thee, and compass thee round,"], ["e puipui ia te oe i itu uma;", "and keep thee in on every side,"]]},
  {num:44,words:[["latou te faagatasi foi ia te oe ma le eleele,", "And shall lay thee even with the ground,"], ["atoa ma lau fanau i totonu ia te oe;", "and thy children within thee;"], ["latou te le tuua foi se maa i luga o le tasi maa i totonu ia te oe;", "and they shall not leave in thee one stone upon another;"], ["auā ua le iloa e oe ona po ua asia mai ai oe.", "because thou knewest not the time of thy visitation."]]},
  {num:45,words:[["Ua ulu atu ia i le malumalu,", "And he went into the temple, and began to cast out them that sold therein,"], ["ona tulia lea i fafo e ia o e na fefaataua'i;", "and them that bought;"]]},
  {num:46,words:[["ua faapea atu ia te i latou. Ua tusia,", "Saying unto them,"], ["O lo'u fale o le fale tatalo lea;", "It is written, My house is the house of prayer:"], ["a ua outou faia ma ana o e fao mea.", "but ye have made it a den of thieves."]]},
  {num:47,words:[["Ua a'oa'o ia i aso fai soo i le malumalu.", "And he taught daily in the temple."], ["A o le au faitaulaga sili ma le au tusiupu, atoa ma alii o le nuu, ua latou fia fasioti ia te ia;", "But the chief priests and the scribes and the chief of the people sought to destroy him,"]]},
  {num:48,words:[["a e lei maua e i latou se mea e fai ai;", "And could not find what they might do:"], ["auā ua naunau le nuu uma i le fia faalogo atu ia te ia.", "for all the people were very attentive to hear him."]]},
];
renderVerseSet(luk_ch_19_Verses, 'luk-ch19-verses');

var luk_ch_20_Verses = [
  {num:1,words:[["O le tasi o ia aso,", "And it came to pass,"], ["a o a'oa'o ia i le nuu i le malumalu,", "that on one of those days,"], ["ma folafola i le tala lelei, ua tutū mai ai ia te ia faitaulaga sili,", "as he taught the people in the temple,"], ["ma tusiupu,", "and preached the gospel,"], ["ma toeaina.", "the chief priests and the scribes came upon him with the elders,"]]},
  {num:2,words:[["Ona latou fai mai lea ia te ia,", "And spake unto him,"], ["ua faapea mai,", "saying,"], ["Fai mai ia ia te i matou, se a le pule e te fai ai na mea;", "Tell us,"], ["po o ai foi na ia avatu ia te oe lenei pule?", "by what authority doest thou these things? or who is he that gave thee this authority?"]]},
  {num:3,words:[["Ua tali atu ia,", "And he answered and said unto them,"], ["ua faapea atu ia te i latou, Ou te fesili atu foi ia te outou se upu e tasi;", "I will also ask you one thing;"], ["tou te fai mai ai ia te au.", "and answer me:"]]},
  {num:4,words:[["Mai le lagi ea le papatisoga a Ioane,", "The baptism of John, was it from heaven,"], ["pe mai tagata?", "or of men?"]]},
  {num:5,words:[["Ona latou felafolafoai lea,", "And they reasoned with themselves,"], ["ua faapea ane,", "saying,"], ["Afai tatou te fai atu,", "If we shall say,"], ["Mai le lagi;", "From heaven;"], ["ona fai mai ai lea o ia,", "he will say,"], ["Se a foi le mea tou te lei talitonu ai ia te ia?", "Why then believed ye him not?"]]},
  {num:6,words:[["A tatou fai atu. Mai tagata;", "But and if we say,"], ["ona fetogi mai ai lea o le nuu uma ia te i tatou i maa;", "Of men;"], ["auā o la latou le taofi,", "all the people will stone us:"], ["o Ioane o le perofeta ia.", "for they be persuaded that John was a prophet."]]},
  {num:7,words:[["Ona latou tali mai lea. Matou te le iloa pe maifea.", "And they answered, that they could not tell whence it was."]]},
  {num:8,words:[["Ona fetalai atu lea o Iesu ia te i latou,", "And Jesus said unto them,"], ["Ou te le ta'u atu foi ia te outou le pule ou te fai ai nei mea.", "Neither tell I you by what authority I do these things."]]},
  {num:9,words:[["Ona fetalai atu lea o ia i lenei faataoto i le nuu,", "Then began he to speak to the people this parable;"], ["Na fai e le tasi tagata le tovine,", "A certain man planted a vineyard,"], ["ua tuu atu ai i e galulue i vine,", "and let it forth to husbandmen,"], ["ona alu malaga lea o ia i le nuu ese ua fāi po.", "and went into a far country for a long time."]]},
  {num:10,words:[["Ua fai le fuata,", "And at the season he sent a servant to the husbandmen,"], ["ona auina atu lea e ia o le auauna i e galulue i vine,", "that they should give him of the fruit of the vineyard:"], ["ia latou au mai ia te ia ni fua o le tovine; a o e galulue i vine ua latou sasaina o ia,", "but the husbandmen beat him,"], ["ma aufuaina mai o ia.", "and sent him away empty."]]},
  {num:11,words:[["Ua toe auina atu e ia le tasi auauna;", "And again he sent another servant:"], ["ua latou sasa ma agaleaga ia te ia,", "and they beat him also, and entreated him shamefully,"], ["ona latou aufuaina mai lea o ia.", "and sent him away empty."]]},
  {num:12,words:[["Ua toe auina atu e ia lona toatolu,", "And again he sent a third:"], ["ua latou fasia o ia ua manua,", "and they wounded him also,"], ["ma latou tuliesea.", "and cast him out."]]},
  {num:13,words:[["Ona fai ane ai lea o le alii e ona le tovine,", "Then said the lord of the vineyard,"], ["Se a se mea ou te faia? Ou te auina atu lo'u atalii pele; atonu latou te ava mai ia te ia,", "What shall I do? I will send my beloved son:"], ["pe a iloa mai o ia.", "it may be they will reverence him when they see him."]]},
  {num:14,words:[["A ua iloa atu o ia e tagata galulue i vine,", "But when the husbandmen saw him,"], ["ona latou fetautalatala'i ai lea,", "they reasoned among themselves,"], ["ua faapea ane,", "saying,"], ["O le suli lena;", "This is the heir:"], ["o mai ia,", "come,"], ["ina tatou fasioti ia te ia,", "let us kill him,"], ["e maua ai le fanua mo i tatou.", "that the inheritance may be our's."]]},
  {num:15,words:[["Ua latou tuli ia te ia i tua o le tovine,", "So they cast him out of the vineyard,"], ["ma latou fasiotia. Se a foi le mea e faia ia te i latou e le alii e ona le tovine?", "and killed him. What therefore shall the lord of the vineyard do unto them?"]]},
  {num:16,words:[["E alu atu ia ma faauma ia tagata galulue i vine,", "He shall come and destroy these husbandmen,"], ["e tuu atu foi le tovine i nisi tagata. Ua latou faalogo atu,", "and shall give the vineyard to others. And when they heard it,"], ["ona latou fai mai lea,", "they said,"], ["Aua ne'i faapea.", "God forbid."]]},
  {num:17,words:[["Ona silasila lea o ia ia te i latou,", "And he beheld them,"], ["ua faapea atu,", "and said,"], ["Se a foi lenei upu ua tusia. O le maa na lafoaiina e tufuga fai fale,", "What is this then that is written, The stone which the builders rejected,"], ["ua avea lea ma maa tulimanu aupitoaluga?", "the same is become the head of the corner?"]]},
  {num:18,words:[["O sē paū i luga o lea maa,", "Whosoever shall fall upon that stone shall be broken;"], ["e gaugau ai o ia; a o se tasi e paū ifo i ai le maa ,", "but on whomsoever it shall fall,"], ["e nutipalaina ai o ia.", "it will grind him to powder."]]},
  {num:19,words:[["Ua fia pue ia te ia le au faitaulaga sili ma le au tusiupu i lea lava itu aso;", "And the chief priests and the scribes the same hour sought to lay hands on him;"], ["a ua latou matatau i le nuu,", "and they feared the people:"], ["auā ua latou iloa ua faatu e ia lena faataoto ia te i latou.", "for they perceived that he had spoken this parable against them."]]},
  {num:20,words:[["Ua latou lamalama ma aauina atu nisi e vaavaai ia te ia,", "And they watched him, and sent forth spies,"], ["ua latou faataga amiotonu,", "which should feign themselves just men,"], ["ina ia latou maua ai sana upu e tuu atu ai ia te ia i le lima ma le pule a le alii.", "that they might take hold of his words, that so they might deliver him unto the power and authority of the governor."]]},
  {num:21,words:[["Ua latou fesili mai ia te ia,", "And they asked him,"], ["ua faapea mai. Le a'oa'o e,", "saying,"], ["ua matou iloa ua e tautala ma a'oa'o mai ma le tonu,", "Master, we know that thou sayest and teachest rightly,"], ["e le faailogaina e oe se tagata,", "neither acceptest thou the person of any,"], ["a ua e a'oa'o i le ala o le Atua ma le faamaoni.", "but teachest the way of God truly:"]]},
  {num:22,words:[["Pe sa ea ona matou avatu le taulaga ia Kaisara,", "Is it lawful for us to give tribute unto Caesar,"], ["pe leai?", "or no?"]]},
  {num:23,words:[["A ua silafia e ia la latou togafiti,", "But he perceived their craftiness, and said unto them,"], ["ona fetalai atu ai lea o ia ia te i latou. Se a le mea tou te tofotofo mai ai ia te au?", "Why tempt ye me?"]]},
  {num:24,words:[["Faaali mai ia ia te au se tenari. O ai ea e ona le faatagata ma le tusi e i ai? Ua latou fai mai ia te ia,", "Shew me a penny. Whose image and superscription hath it? They answered and said,"], ["E o Kaisara.", "Caesar's."]]},
  {num:25,words:[["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["O mea a Kaisara ia outou avatu ia Kaisara;", "Render therefore unto Caesar the things which be Caesar's,"], ["a o mea a le Atua avatu ia i le Atua.", "and unto God the things which be God's."]]},
  {num:26,words:[["Latou te le mafaia lava ona maua o ana upu i luma o le nuu;", "And they could not take hold of his words before the people:"], ["ua latou ofo i lana tali,", "and they marvelled at his answer,"], ["ua latou faalologo ai.", "and held their peace."]]},
  {num:27,words:[["Ua o mai ia te ia isi o le au satukaio o e taofi e leai se toe tu;", "Then came to him certain of the Sadducees, which deny that there is any resurrection;"], ["ua latou fesili mai ia te ia,", "and they asked him,"]]},
  {num:28,words:[["ua faapea mai,", "Saying,"], ["Le a'oa'o e,", "Master,"], ["ua tusi mai Mose ia te i matou,", "Moses wrote unto us,"], ["pe afai e oti le uso o le tasi tagata ua fai lana avā,", "If any man's brother die, having a wife,"], ["a ua oti ia e leai sana fanau,", "and he die without children,"], ["ia fai avā lona uso i le fafine,", "that his brother should take his wife,"], ["ina ia tupu ai se gafa o lona uso.", "and raise up seed unto his brother."]]},
  {num:29,words:[["Ia,", "There were therefore seven brethren:"], ["e toafitu le au uso; na fai avā le ulumatua,", "and the first took a wife,"], ["ua oti e leai sana fanau.", "and died without children."]]},
  {num:30,words:[["Ona fai avā lea i le fafine o le aupito ane i ai,", "And the second took her to wife,"], ["ua oti foi o ia e leai sana fanau.", "and he died childless."]]},
  {num:31,words:[["Ua fai avā foi i ai lona toatolu,", "And the third took her;"], ["ua faapea foi ua oo i lona toafitu,", "and in like manner the seven also: and they left no children,"], ["ua latou oti ua leai ni a latou fanau.", "and died."]]},
  {num:32,words:[["A e muliai oti foi le fafine.", "Last of all the woman died also."]]},
  {num:33,words:[["A oo foi i le toe tu, o ai so latou e ana le avā? auā na fai avā ai le toafitu.", "Therefore in the resurrection whose wife of them is she? for seven had her to wife."]]},
  {num:34,words:[["Ona tali atu lea o Iesu,", "And Jesus answering said unto them,"], ["ua faapea atu ia te i latou, O tagata o le olaga nei,", "The children of this world marry,"], ["ua fai avā ma nofo tane i latou;", "and are given in marriage:"]]},
  {num:35,words:[["a o e ta'uaogaina ia maua e i latou lea olaga,", "But they which shall be accounted worthy to obtain that world,"], ["ma le toe tu mai o e ua oti,", "and the resurrection from the dead,"], ["latou te le fai avā,", "neither marry,"], ["pe nofo tane;", "nor are given in marriage:"]]},
  {num:36,words:[["e le mafai foi ona toe oti o i latou;", "Neither can they die any more:"], ["auā ua latou tutusa ma agelu;", "for they are equal unto the angels;"], ["o fanau foi i latou a le Atua,", "and are the children of God,"], ["o tagata o le toe tu.", "being the children of the resurrection."]]},
  {num:37,words:[["A o le faatuina o e ua oti,", "Now that the dead are raised,"], ["ua faailoa mai lea mea e Mose i le laau talatala i lona ta'ua o le Alii o le Atua o Aperaamo,", "even Moses shewed at the bush,"], ["o le Atua foi o Isaako,", "when he calleth the Lord the God of Abraham, and the God of Isaac,"], ["o le Atua foi o Iakopo.", "and the God of Jacob."]]},
  {num:38,words:[["E le o le Atua ia o e ua oti,", "For he is not a God of the dead,"], ["a o e ola;", "but of the living:"], ["auā ua ola uma ia te ia.", "for all live unto him."]]},
  {num:39,words:[["Ona tali mai ai lea isi o le au tusiupu,", "Then certain of the scribes answering said,"], ["ua faapea mai, Le a'oa'o e,", "Master,"], ["ua tonu lau upu.", "thou hast well said."]]},
  {num:40,words:[["E mulimuli ane latou te lei toe faamalosi ona fesili mai ia te ia se mea e tasi.", "And after that they durst not ask him any question at all."]]},
  {num:41,words:[["Ona fetalai atu lea o ia ia te i latou, Pe faapefea ona fai mai tagata,", "And he said unto them,"], ["o le Keriso o le Atalii ia o Tavita?", "How say they that Christ is David's son?"]]},
  {num:42,words:[["A ua fai mai e Tavita lava i le tusi o salāmo,", "And David himself saith in the book of Psalms,"], ["Na fetalai atu le Alii i lo'u Alii,", "The LORD said unto my Lord,"], ["Ina nofo ia oe i lo'u itu taumatau,", "Sit thou on my right hand,"]]},
  {num:43,words:[["seia ou faia e ua fai oe mo latou fili ma mea e tu ai ou vae.", "Till I make thine enemies thy footstool."]]},
  {num:44,words:[["O lenei, ua ta'ua o ia e Tavita o lona Alii,", "David therefore calleth him Lord,"], ["pe faapefea ona fai mona atalii?", "how is he then his son?"]]},
  {num:45,words:[["Ona fetalai atu lea o ia i ona soo, a o faalogo mai le nuu uma,", "Then in the audience of all the people he said unto his disciples,"]]},
  {num:46,words:[["Ia outou i le au tusiupu e ua fia evaeva ma ofu tatapuvae,", "Beware of the scribes,"], ["ua manao foi ia alofagia i latou i malae,", "which desire to walk in long robes,"], ["ma nofoa sili i sunako,", "and love greetings in the markets, and the highest seats in the synagogues,"], ["ma mea sili e taooto ai i faigaai;", "and the chief rooms at feasts;"]]},
  {num:47,words:[["o e faauma fale o fafine ua oti a latou tane,", "Which devour widows' houses,"], ["ua faalevaleva foi a latou tatalo e fai ma ufiufi;", "and for a shew make long prayers:"], ["e atili ai ona faasalaina o i latou.", "the same shall receive greater damnation."]]},
];
renderVerseSet(luk_ch_20_Verses, 'luk-ch20-verses');

var luk_ch_21_Verses = [
  {num:1,words:[["Ua tepa ae ia, ua silafia o e mauoa,", "And he looked up,"], ["o lafo a latou taulaga i le mea e teu ai tupe.", "and saw the rich men casting their gifts into the treasury."]]},
  {num:2,words:[["Ua silafia foi e ia le tasi fafine mativa ua oti lana tane, ua lafo i ai tupe iti e lua.", "And he saw also a certain poor widow casting in thither two mites."]]},
  {num:3,words:[["Ona fetalai atu lea o ia, E moni,", "And he said,"], ["ou te fai atu ia te outou,", "Of a truth I say unto you,"], ["o mea a lenei fafine mativa ua oti lana tane ua lafo i ai, ua sili lea i a latou uma.", "that this poor widow hath cast in more than they all:"]]},
  {num:4,words:[["Auā o i latou uma, ua latou lafo atu i taulaga a le Atua nisi mea mai a latou mea ua tele;", "For all these have of their abundance cast in unto the offerings of God:"], ["a o ia ua mativa, ua lafo e ia ana mea uma e ola ai sa ia te ia.", "but she of her penury hath cast in all the living that she had."]]},
  {num:5,words:[["Ua tautalatala nisi i mea a le malumalu,", "And as some spake of the temple,"], ["i lona teuteuina i maa lalelei ma taulaga,", "how it was adorned with goodly stones and gifts,"], ["ona fetalai atu lea o ia,", "he said,"]]},
  {num:6,words:[["O ia mea ua outou vaavaai i ai,", "As for these things which ye behold,"], ["e oo mai lava ona aso e le toe ai se tasi maa i luga o le tasi maa,", "the days will come, in the which there shall not be left one stone upon another,"], ["a e uma ona sōloia i lalo.", "that shall not be thrown down."]]},
  {num:7,words:[["Ona latou fesili mai ai lea ia te ia,", "And they asked him,"], ["ua faapea mai,", "saying,"], ["Le a'oa'o e,", "Master,"], ["e taunuu ea ia mea afea? se a foi le faailoga pe a tāli taunuu ai ia mea?", "but when shall these things be? and what sign will there be when these things shall come to pass?"]]},
  {num:8,words:[["Ua fetalai atu ia,", "And he said,"], ["Ia outou,", "Take heed that ye be not deceived:"], ["ne'i faaseseina outou;", "for many shall come in my name,"], ["auā e toatele e o mai i lo'u igoa, e taitasi ma faapea ane,", "saying,"], ["O a'u o ia;", "I am Christ;"], ["ua latalata foi ona po;", "and the time draweth near:"], ["aua foi tou te mulimuli atu ia te i latou.", "go ye not therefore after them."]]},
  {num:9,words:[["Pe a outou faalogo i taua ma fouvalega,", "But when ye shall hear of wars and commotions,"], ["aua tou te atuatuvale;", "be not terrified:"], ["auā e ao ina muai taunuu mai o ia mea,", "for these things must first come to pass;"], ["a e le oo loa mai le gataaga.", "but the end is not by and by."]]},
  {num:10,words:[["Ona fetalai atu lea o ia ia te i latou,", "Then said he unto them, Nation shall rise against nation,"], ["E sii le taua e le tasi nuu i le tasi nuu ma le tasi malo i le tasi malo.", "and kingdom against kingdom:"]]},
  {num:11,words:[["E i ai mafuie tetele i lea mea ma lea mea,", "And great earthquakes shall be in divers places,"], ["o oge foi,", "and famines,"], ["ma faamai;", "and pestilences;"], ["ma faaiteite ma faailoga tetele mai le lagi.", "and fearful sights and great signs shall there be from heaven."]]},
  {num:12,words:[["A o lei oo nei mea,", "But before all these, they shall lay their hands on you,"], ["latou te pupue ma faasaua ia te outou,", "and persecute you,"], ["e tuuina atu ia te outou i sunako ma fale puipui,", "delivering you up to the synagogues,"], ["latou te ta'ita'iina atu outou i tupu ma alii ona o lo'u igoa.", "and into prisons, being brought before kings and rulers for my name's sake."]]},
  {num:13,words:[["E oo ia mea ia te outou e fai ma molimau.", "And it shall turn to you for a testimony."]]},
  {num:14,words:[["O lenei, ia tuu i o outou loto,", "Settle it therefore in your hearts,"], ["tou te le muai mafaufau i se upu tou te tali atu ai.", "not to meditate before what ye shall answer:"]]},
  {num:15,words:[["Auā ou te avatu mo outou le upu ma le poto, e leai so latou o e finau mai ia te outou na te mafaia ona tali mai,", "For I will give you a mouth and wisdom,"], ["pe tetee mai ia te outou.", "which all your adversaries shall not be able to gainsay nor resist."]]},
  {num:16,words:[["E tuuina atu foi outou e mātua,", "And ye shall be betrayed both by parents,"], ["ma uso,", "and brethren,"], ["ma aiga,", "and kinsfolks,"], ["ma uo;", "and friends;"], ["o isi foi o outou e fasiotia e i latou.", "and some of you shall they cause to be put to death."]]},
  {num:17,words:[["E inosia foi outou e tagata uma ona o lo'u igoa.", "And ye shall be hated of all men for my name's sake."]]},
  {num:18,words:[["A e leai lava so outou lauulu e tasi e paū.", "But there shall not an hair of your head perish."]]},
  {num:19,words:[["O lo outou onosai ia maua ai lo outou ola.", "In your patience possess ye your souls."]]},
  {num:20,words:[["A iloa e outou ua siosiomia Ierusalema i 'au o le taua,", "And when ye shall see Jerusalem compassed with armies,"], ["ia outou iloa i lea aso ua latalata ona faatafunaina.", "then know that the desolation thereof is nigh."]]},
  {num:21,words:[["O lea aso, o e ua i Iutaia ia latou sosola i mauga;", "Then let them which are in Judaea flee to the mountains;"], ["o e ua i totonu o lea aai , ia latou o ese;", "and let them which are in the midst of it depart out;"], ["o e ua i le vao foi, aua ne'i latou o atu i totonu o le aai .", "and let not them that are in the countries enter thereinto."]]},
  {num:22,words:[["Auā o ona aso ia e faasalaina ai,", "For these be the days of vengeance,"], ["ina ia taunuu mai o mea uma ua tusia.", "that all things which are written may be fulfilled."]]},
  {num:23,words:[["Oi talofa i fafine ua totō,", "But woe unto them that are with child,"], ["atoa foi ma ē failele i ia lava aso;", "and to them that give suck,"], ["auā e oo le puapuaga tele i le nuu,", "in those days! for there shall be great distress in the land,"], ["ma le toasa i le nuu nei.", "and wrath upon this people."]]},
  {num:24,words:[["E oti i latou i le mata o le pelu;", "And they shall fall by the edge of the sword,"], ["e tāfea foi i nuu uma;", "and shall be led away captive into all nations:"], ["e solia foi Ierusalema e nuu ese,", "and Jerusalem shall be trodden down of the Gentiles,"], ["seia faaiuina tausaga o nuu ese.", "until the times of the Gentiles be fulfilled."]]},
  {num:25,words:[["E i ai foi faailoga i le la,", "And there shall be signs in the sun,"], ["ma le masina,", "and in the moon,"], ["ma fetu;", "and in the stars; and upon the earth distress of nations,"], ["o i le lalolagi foi le atuatuvale o nuu i le fememeai;", "with perplexity;"], ["e ū foi le sami ma le sousou;", "the sea and the waves roaring;"]]},
  {num:26,words:[["e oti foi tagata i le matatau ma le faatalitali i mea e oo mai i le lalolagi;", "Men's hearts failing them for fear, and for looking after those things which are coming on the earth:"], ["auā e luluina 'au a le lagi.", "for the powers of heaven shall be shaken."]]},
  {num:27,words:[["Ona iloa atu ai lea e i latou o le Atalii o le tagata e sau i le ao, ma le mana ma le mamalu tele.", "And then shall they see the Son of man coming in a cloud with power and great glory."]]},
  {num:28,words:[["A afua ona faia o ia mea,", "And when these things begin to come to pass,"], ["ia tepa ae outou,", "then look up,"], ["ma ia ea i luga o outou ulu;", "and lift up your heads;"], ["auā e latalata ina faaolaina outou.", "for your redemption draweth nigh."]]},
  {num:29,words:[["Ua fetalai atu ia ia te i latou i le faataoto;", "And he spake to them a parable; Behold the fig tree,"], ["Ina vaai ia i le mati atoa ma laau uma;", "and all the trees;"]]},
  {num:30,words:[["pe a faatoa matala mai lau, ua outou vaai,", "When they now shoot forth,"], ["ona outou iloa ai lea ua latalata le tausaga vevela.", "ye see and know of your own selves that summer is now nigh at hand."]]},
  {num:31,words:[["Ia faapea foi outou,", "So likewise ye,"], ["pe a iloa e outou ia mea ua faia,", "when ye see these things come to pass,"], ["ia outou iloa ua latalata le malo o le Atua.", "know ye that the kingdom of God is nigh at hand."]]},
  {num:32,words:[["E moni,", "Verily I say unto you,"], ["ou te fai atu ia te outou, E le mavae atu lenei tupulaga,", "This generation shall not pass away,"], ["seia taunuu mea uma.", "till all be fulfilled."]]},
  {num:33,words:[["E mavae atu lava le lagi atoa ma le lalolagi; peitai o a'u upu,", "Heaven and earth shall pass away:"], ["e le mavae atu lava ia.", "but my words shall not pass away."]]},
  {num:34,words:[["Ia outou,", "And take heed to yourselves,"], ["ne'i faamamafaina o outou loto,", "lest at any time your hearts be overcharged with surfeiting,"], ["ma le faaniniva, ma le onā,", "and drunkenness,"], ["ma le popole i mea a le olaga nei,", "and cares of this life,"], ["ne'i faafuasei mai lea aso ia te outou.", "and so that day come upon you unawares."]]},
  {num:35,words:[["Auā e pei o se mailei ona oo mai ai i e nonofo uma lava i le fogāeleele uma.", "For as a snare shall it come on all them that dwell on the face of the whole earth."]]},
  {num:36,words:[["O lea ia outou mataala ai ma tatalo e le aunoa,", "Watch ye therefore,"], ["ina ia ta'uaogaina outou e sao mai ia mea uma ua tāli oo mai,", "and pray always, that ye may be accounted worthy to escape all these things that shall come to pass,"], ["ma ia tutū i luma o le Atalii o le tagata.", "and to stand before the Son of man."]]},
  {num:37,words:[["Sa masani ia i a'oa'o atu i le malumalu i le ao;", "And in the day time he was teaching in the temple;"], ["a o le po, ua maliu atu ai ia i tua,", "and at night he went out,"], ["ma nofo i le mauga o Olive le igoa.", "and abode in the mount that is called the mount of Olives."]]},
  {num:38,words:[["Ua malama ae le taeao,", "And all the people came early in the morning to him in the temple,"], ["ona o ane ai lea ia te ia o le nuu uma i le malumalu e faalogologo ai ia te ia.", "for to hear him."]]},
];
renderVerseSet(luk_ch_21_Verses, 'luk-ch21-verses');

var luk_ch_22_Verses = [
  {num:1,words:[["Ua latalata le tausamiga o areto e le faafefeteina,", "Now the feast of unleavened bread drew nigh,"], ["e ta'ua o le paseka.", "which is called the Passover."]]},
  {num:2,words:[["Ona saili lea e le au faitaulaga sili ma le au tusiupu pe faapefea ona latou fasioti ia te ia;", "And the chief priests and scribes sought how they might kill him;"], ["auā ua latou matatau i le nuu.", "for they feared the people."]]},
  {num:3,words:[["Ona uluitino ai lea o Satani ia Iuta e ta'ua o le Sekara,", "Then entered Satan into Judas surnamed Iscariot,"], ["o le tasi lea o le toasefulu ma le toalua.", "being of the number of the twelve."]]},
  {num:4,words:[["Ua alu ia,", "And he went his way, and communed with the chief priests and captains,"], ["ua tautalatala ma le au faitaulaga sili ma ta'ita'i o 'au i se togafiti na te faalataina ai o ia ia te i latou.", "how he might betray him unto them."]]},
  {num:5,words:[["Ona latou fiafia lea,", "And they were glad,"], ["ua latou tautalatala ma ia e avatu ai tupe.", "and covenanted to give him money."]]},
  {num:6,words:[["Ua lelei ia te ia, ona lamalama lea o ia se itu aso e faigofie ai,", "And he promised,"], ["na te faalataina ai o ia ia te i latou, a o le i ai le motu o tagata.", "and sought opportunity to betray him unto them in the absence of the multitude."]]},
  {num:7,words:[["Ona oo mai ai lea o le aso o areto e le faafefeteina,", "Then came the day of unleavened bread,"], ["e tatau ona fasi ai o le paseka.", "when the passover must be killed."]]},
  {num:8,words:[["Ona aauina atu lea e ia o Peteru ma Ioane,", "And he sent Peter and John,"], ["ua faapea atu,", "saying,"], ["Lua te o e sauni le paseka mo i tatou,", "Go and prepare us the passover,"], ["tatou te aai ai.", "that we may eat."]]},
  {num:9,words:[["Ona la fai mai ai lea ia te ia,", "And they said unto him,"], ["O ifea e te finagalo i ai ma te saunia?", "Where wilt thou that we prepare?"]]},
  {num:10,words:[["Ona fetalai atu lea o ia ia te i laua,", "And he said unto them,"], ["Faauta,", "Behold,"], ["a oo oulua i totonu o le aai,", "when ye are entered into the city, there shall a man meet you,"], ["tou te fetaiai ma le tagata o ave le vai omea,", "bearing a pitcher of water;"], ["lua te mulimuli atu ia te ia i le fale e ulu atu ai o ia.", "follow him into the house where he entereth in."]]},
  {num:11,words:[["Lua te fai atu i le matai o le aiga,", "And ye shall say unto the goodman of the house,"], ["Ua fai mai le a'oa'o ia te oe,", "The Master saith unto thee,"], ["Po o ifea le afeafe e api ai malo, ina ia matou aai ai le paseka,", "Where is the guestchamber,"], ["o a'u ma o'u soo?", "where I shall eat the passover with my disciples?"]]},
  {num:12,words:[["Ona tusi atu ai lea e ia o le afeafe tele aupitoaluga ua uma ona teu;", "And he shall shew you a large upper room furnished:"], ["lua te sauni ai le paseka .", "there make ready."]]},
  {num:13,words:[["Ona la o ai lea,", "And they went,"], ["ua iloa ai pei ona fetalai atu o ia ia te i laua;", "and found as he had said unto them:"], ["ona la sauni ai lea o le paseka.", "and they made ready the passover."]]},
  {num:14,words:[["Ua oo i le itu aso,", "And when the hour was come,"], ["ona taoto ai lea o ia e taumafa,", "he sat down,"], ["sa faatasi ma ia le au aposetolo e toasefulu ma le toalua.", "and the twelve apostles with him."]]},
  {num:15,words:[["Ua fetalai atu ia ia te i latou, O lo'u manao,", "And he said unto them,"], ["ua tele lava lo'u manao e muai 'ai lenei paseka ma outou, a o lei oo i lo'u tiga.", "With desire I have desired to eat this passover with you before I suffer:"]]},
  {num:16,words:[["Auā ou te fai atu ia te outou,", "For I say unto you,"], ["ou te le toe 'ai ai lava,", "I will not any more eat thereof,"], ["seia oo ina faaiuina i le malo o le Atua.", "until it be fulfilled in the kingdom of God."]]},
  {num:17,words:[["Ona tago ai lea o ia i le ipu,", "And he took the cup,"], ["ua faafetai,", "and gave thanks,"], ["ua fetalai atu,", "and said,"], ["Ia outou tago i lenei ipu ,", "Take this,"], ["ma ia tufatufa ane ia te outou;", "and divide it among yourselves:"]]},
  {num:18,words:[["auā ou te fai atu ia te outou,", "For I say unto you,"], ["ou te le inu lava i le fua o le vine,", "I will not drink of the fruit of the vine,"], ["seia oo mai le malo o le Atua.", "until the kingdom of God shall come."]]},
  {num:19,words:[["Ona tago ai lea o ia i le areto,", "And he took bread,"], ["ua faafetai,", "and gave thanks,"], ["ua tofitofi,", "and brake it,"], ["ma avatu ia te i latou, ua faapea atu,", "and gave unto them,"], ["O lo'u tino lenei,", "saying,"], ["ua foaiina atu mo outou;", "This is my body which is given for you:"], ["tou te faia le mea nei e fai ma faamanatuga ia te au.", "this do in remembrance of me."]]},
  {num:20,words:[["Sa faapea foi ona tago i le ipu,", "Likewise also the cup after supper,"], ["ina ua uma ona tālisua,", "saying,"], ["ua faapea atu, O lenei ipu o le feagaiga fou lea i lo'u toto,", "This cup is the new testament in my blood,"], ["ua faamaligiina mo outou.", "which is shed for you."]]},
  {num:21,words:[["A e peitai,", "But,"], ["faauta mai,", "behold,"], ["o ia te au i le laulau nei le lima o lē faalata ia te au.", "the hand of him that betrayeth me is with me on the table."]]},
  {num:22,words:[["E alu lava le Atalii o le tagata e pei ona tofia;", "And truly the Son of man goeth,"], ["a o lea tagata na te faalataina o ia,", "as it was determined:"], ["oi talofa ia te ia!", "but woe unto that man by whom he is betrayed!"]]},
  {num:23,words:[["ona latou fesueai ai lea,", "And they began to enquire among themselves,"], ["po o ai so latou o le a na faia lea mea.", "which of them it was that should do this thing."]]},
  {num:24,words:[["Sa latou fefinauai foi po o ai so latou e sili.", "And there was also a strife among them, which of them should be accounted the greatest."]]},
  {num:25,words:[["A ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["O tupu o nuu ese ua aliitai i latou;", "The kings of the Gentiles exercise lordship over them;"], ["o e pule foi ia i latou ua ta'ua i latou o e agalelei.", "and they that exercise authority upon them are called benefactors."]]},
  {num:26,words:[["A e le faapea outou;", "But ye shall not be so:"], ["peitai o lē sili ia te outou,", "but he that is greatest among you,"], ["ia avea o ia ia pei o le aupito itiiti;", "let him be as the younger;"], ["o lē pule foi,", "and he that is chief,"], ["ia pei o le auauna ia.", "as he that doth serve."]]},
  {num:27,words:[["Auā po o ai lē sili;", "For whether is greater,"], ["o lē taoto ea e 'ai, po o lē auauna mai? E le o lē taoto e 'ai ea? A o a'u nei,", "he that sitteth at meat,"], ["o loo ia te outou pei o le auauna lava.", "or he that serveth? is not he that sitteth at meat? but I am among you as he that serveth."]]},
  {num:28,words:[["O outou foi, ua outou tumau ia te au i o'u tofotofoga.", "Ye are they which have continued with me in my temptations."]]},
  {num:29,words:[["E faapei ona tofia mai e lo'u Tamā o le malo ia te au,", "And I appoint unto you a kingdom,"], ["e faapea foi ona ou tofia outou,", "as my Father hath appointed unto me;"]]},
  {num:30,words:[["ina ia outou aai ma inu i la'u laoai i lo'u malo, ma ia nonofo i nofoālii,", "That ye may eat and drink at my table in my kingdom,"], ["ma faamasino atu i itu aiga o Isaraelu e sefulu ma le lua.", "and sit on thrones judging the twelve tribes of Israel."]]},
  {num:31,words:[["Ua fetalai atu le Alii,", "And the Lord said,"], ["Simona e,", "Simon,"], ["Simona e,", "Simon,"], ["faauta,", "behold,"], ["ua manao tele Satani ia te outou,", "Satan hath desired to have you,"], ["ia lulu ia te outou pei o le saito;", "that he may sift you as wheat:"]]},
  {num:32,words:[["a ua ou faatoga mo oe,", "But I have prayed for thee,"], ["ina ne'i mavae lou faatuatua;", "that thy faith fail not:"], ["a o oe foi, pe a liua mai oe,", "and when thou art converted,"], ["ona e faamalosi ai lea i ou uso.", "strengthen thy brethren."]]},
  {num:33,words:[["Ua fai mai o ia ia te ia,", "And he said unto him, Lord,"], ["Le Alii e,", "I am ready to go with thee,"], ["ua ou sauni ta te o faatasi ma oe i le fale puipui atoa ma le oti.", "both into prison, and to death."]]},
  {num:34,words:[["Ona fetalai atu lea o ia,", "And he said,"], ["Peteru e,", "I tell thee,"], ["ou te fai atu ia te oe,", "Peter,"], ["e le vivini moa i le po nei,", "the cock shall not crow this day,"], ["seia e faafiti faatolu mai e te le iloa a'u.", "before that thou shalt thrice deny that thou knowest me."]]},
  {num:35,words:[["Ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["Na ou aauina atu ia te outou e leai sa outou ete tupe,", "When I sent you without purse,"], ["po o se 'ato,", "and scrip,"], ["po o seevae,", "and shoes,"], ["pe na outou matitiva ea i se mea e tasi? Ua fai mai i latou,", "lacked ye any thing? And they said,"], ["E leai lava.", "Nothing."]]},
  {num:36,words:[["Ona fetalai atu ai lea o ia ia te i latou,", "Then said he unto them,"], ["A o lenei,", "But now,"], ["ai se tagata e ana se ete tupe,", "he that hath a purse,"], ["ina tago ia i ai,", "let him take it, and likewise his scrip:"], ["e faapea foi sana 'ato;", "and he that hath no sword,"], ["o le tagata foi e leai sana pelu,", "let him sell his garment,"], ["ia avatu lona ofu e faatau a'i mai.", "and buy one."]]},
  {num:37,words:[["Auā ou te fai atu ia te outou,", "For I say unto you,"], ["e tatau ona taunuu mai ia te au o le mea ua tusia,", "that this that is written must yet be accomplished in me,"], ["o lea, Na faitauina foi o ia faatasi ma e pagotata;", "And he was reckoned among the transgressors:"], ["auā foi o le a faaiuina mea ua tusia ia te au.", "for the things concerning me have an end."]]},
  {num:38,words:[["Ua latou fai mai,", "And they said,"], ["Le Alii e,", "Lord,"], ["faauta,", "behold,"], ["o pelu nei e lua. Ona fetalai atu lea o ia ia te i latou,", "here are two swords. And he said unto them,"], ["Soia.", "It is enough."]]},
  {num:39,words:[["Ua maliu atu o ia i fafo,", "And he came out,"], ["ua savali atu i le mauga o Olive,", "and went,"], ["ua faapea lana masani;", "as he was wont, to the mount of Olives;"], ["ua mulimuli atu foi ona soo ia te ia.", "and his disciples also followed him."]]},
  {num:40,words:[["Ua oo atu ia i lea mea,", "And when he was at the place,"], ["ona fetalai atu lea o ia ia te i latou,", "he said unto them,"], ["Ia outou tatalo ne'i oo mai le faaosoosoga ia te outou.", "Pray that ye enter not into temptation."]]},
  {num:41,words:[["Ona maliu ese lea o ia ia te i latou,", "And he was withdrawn from them about a stone's cast,"], ["e pei o le togi o le maa ona mamao ,", "and kneeled down,"], ["ona tootuli ai lea o ia ua tatalo,", "and prayed,"]]},
  {num:42,words:[["ua faapea atu,", "Saying,"], ["Lo'u Tamā e,", "Father,"], ["a e finagalo i ai,", "if thou be willing, remove this cup from me:"], ["ia e ave ese lenei ipu ia te au;", "nevertheless not my will,"], ["a e aua le faia lo'u loto,", "but thine,"], ["a o lou finagalo .", "be done."]]},
  {num:43,words:[["Ona faaali mai ai lea ia te ia o le agelu mai le lagi,", "And there appeared an angel unto him from heaven,"], ["ua faamalosi ia te ia.", "strengthening him."]]},
  {num:44,words:[["Ua puapuaga o ia, ua atili ai lana tatalo;", "And being in an agony he prayed more earnestly:"], ["o lona afu foi ua pei o 'alu'alu toto ua paū ifo i le eleele.", "and his sweat was as it were great drops of blood falling down to the ground."]]},
  {num:45,words:[["Ua tulai o ia sa tatalo,", "And when he rose up from prayer,"], ["ona maliu atu lea i ona soo,", "and was come to his disciples,"], ["ua maua i latou ua momoe ina ua tiga i le alofa.", "he found them sleeping for sorrow,"]]},
  {num:46,words:[["Ona fetalai atu lea o ia ia te i latou,", "And said unto them,"], ["Se a le mea tou te momoe ai? ina tulai ia, ina tatalo,", "Why sleep ye? rise and pray,"], ["ne'i oo mai le faaosoosoga ia te outou.", "lest ye enter into temptation."]]},
  {num:47,words:[["O loo fetalai ia,", "And while he yet spake,"], ["faauta,", "behold a multitude,"], ["o le motu o tagata, ma lē ua igoa ia Iuta,", "and he that was called Judas,"], ["o le tasi o le toasefulu ma le toalua,", "one of the twelve,"], ["ua muamua mai o ia ia te i latou,", "went before them,"], ["ma soso mai ia Iesu e sogi ia te ia.", "and drew near unto Jesus to kiss him."]]},
  {num:48,words:[["A ua fetalai atu Iesu ia te ia,", "But Jesus said unto him,"], ["Iuta e,", "Judas,"], ["e te faalataina ea le Atalii o le tagata ma le sogi?", "betrayest thou the Son of man with a kiss?"]]},
  {num:49,words:[["Ua iloa e i latou ua faatasi ma ia o le mea o le a fai,", "When they which were about him saw what would follow,"], ["ona latou fai mai ai lea ia te ia,", "they said unto him,"], ["Le Alii e,", "Lord,"], ["pe matou te taia ea i le pelu?", "shall we smite with the sword?"]]},
  {num:50,words:[["O le tasi tagata o i latou, ua ta e ia le auauna a le faitaulaga sili,", "And one of them smote the servant of the high priest,"], ["ua tipiesea lona taliga taumatau.", "and cut off his right ear."]]},
  {num:51,words:[["Ona fetalai atu lea o Iesu, ua faapea atu,", "And Jesus answered and said,"], ["Tuu mai ia, seia faia lenei mea .", "Suffer ye thus far."], ["Ona tago ai lea o ia i lona taliga,", "And he touched his ear,"], ["ua faamalolo ia te ia.", "and healed him."]]},
  {num:52,words:[["Ua fetalai atu Iesu i le au faitaulaga sili,", "Then Jesus said unto the chief priests,"], ["ma ta'ita'i o 'au o le malumalu,", "and captains of the temple, and the elders,"], ["ma toeaina,", "which were come to him,"], ["e na o mai ia te ia Ua outou o mai ma pelu ma uatogi,", "Be ye come out, as against a thief,"], ["peiseai o se puega o se fao mea?", "with swords and staves?"]]},
  {num:53,words:[["Sa tatou i le malumalu ma outou i aso fai soo,", "When I was daily with you in the temple,"], ["e lei oo mai lava o outou lima ia te au;", "ye stretched forth no hands against me:"], ["a o lo outou itu po lenei,", "but this is your hour,"], ["ma le pule a le pouliuli.", "and the power of darkness."]]},
  {num:54,words:[["Ona latou pue lea ia te ia,", "Then took they him, and led him,"], ["ua ta'ita'i ma ave ia te ia i le fale o le faitaulaga sili.", "and brought him into the high priest's house."], ["A ua mulimuli mamao atu Peteru.", "And Peter followed afar off."]]},
  {num:55,words:[["Ua latou tafu le afi i totonu o le maota,", "And when they had kindled a fire in the midst of the hall,"], ["ua latou nonofo i lalo,", "and were set down together,"], ["ua nofo foi Peteru faatasi ma i latou.", "Peter sat down among them."]]},
  {num:56,words:[["A ua iloa atu o ia e le tasi auauna teine o nofo mai i tafatafa o le afi,", "But a certain maid beheld him as he sat by the fire,"], ["ona pulatoa lea ia te ia,", "and earnestly looked upon him,"], ["ua faapea ane,", "and said,"], ["O lenei tagata foi sa faatasi ma ia.", "This man was also with him."]]},
  {num:57,words:[["A ua faafiti atu o ia ia te ia,", "And he denied him,"], ["ua faapea atu,", "saying,"], ["Funa e,", "Woman,"], ["ou te le iloa o ia.", "I know him not."]]},
  {num:58,words:[["Ua toe itiiti,", "And after a little while another saw him,"], ["ona vaai mai lea o le tasi ia te ia, ua faapea mai,", "and said,"], ["O oe foi le tasi o i latou.", "Thou art also of them."], ["Ona fai atu lea o Peteru,", "And Peter said,"], ["Sole,", "Man,"], ["e le o a'u.", "I am not."]]},
  {num:59,words:[["Ua mavae, pe atoa le itu po e tasi,", "And about the space of one hour after another confidently affirmed,"], ["ona matuā fai mai ai lea o le tasi, ua faapea ane,", "saying,"], ["E moni lava,", "Of a truth this fellow also was with him:"], ["sa ia te ia lenei tagata; auā o le Kalilaia foi o ia.", "for he is a Galilaean."]]},
  {num:60,words:[["Ona fai atu lea o Peteru,", "And Peter said,"], ["Sole,", "Man,"], ["ou te le iloa le mea e te fai mai na.", "I know not what thou sayest."], ["Ona vivini loa lea o moa,", "And immediately, while he yet spake,"], ["a o tauatala o ia.", "the cock crew."]]},
  {num:61,words:[["Ona fāliu lea o le Alii,", "And the Lord turned,"], ["ua silasila atu ia Peteru.", "and looked upon Peter."], ["Ona manatu mai ai lea o Peteru i le fetalaiga a le Alii,", "And Peter remembered the word of the Lord,"], ["na ia fetalai mai ia te ia,", "how he had said unto him, Before the cock crow,"], ["E le vivini moa seia e faafiti faatolu mai ia te au.", "thou shalt deny me thrice."]]},
  {num:62,words:[["Ona alu ai lea o Peteru i fafo,", "And Peter went out,"], ["ua tagi lotulotu ia.", "and wept bitterly."]]},
  {num:63,words:[["O tagata ua taofi ia Iesu,", "And the men that held Jesus mocked him,"], ["ua latou tauemu ma sasa ia te ia.", "and smote him."]]},
  {num:64,words:[["Ua latou ufiufi ona fofoga ,", "And when they had blindfolded him,"], ["ona po mai ai lea i ona fofoga,", "they struck him on the face,"], ["ua fesili mai foi ia te ia,", "and asked him,"], ["ua faapea mai,", "saying,"], ["E te iite mai,", "Prophesy,"], ["po o ai na na po atu ia te oe?", "who is it that smote thee?"]]},
  {num:65,words:[["O isi foi upu e tele ua latou upu leaga ai ia te ia.", "And many other things blasphemously spake they against him."]]},
  {num:66,words:[["Ua ao, ona faapotopoto ai lea o le taupulega o le nuu,", "And as soon as it was day,"], ["o le au faitaulaga sili,", "the elders of the people and the chief priests and the scribes came together,"], ["ma le au tusiupu,", "and led him into their council,"], ["ona ta'ita'i atu lea ia te ia i la latou fono, ua faapea mai,", "saying,"]]},
  {num:67,words:[["Afai o oe o le Keriso, fai mai ia ia te i matou.", "Art thou the Christ? tell us."], ["Ona fetalai atu lea o ia ia te i latou,", "And he said unto them,"], ["Pe afai ou te fai atu ia te outou,", "If I tell you,"], ["tou te le tolitonu mai lava;", "ye will not believe:"]]},
  {num:68,words:[["afai foi ou te fesili ia te outou ,", "And if I also ask you,"], ["tou te le tali mai lava,", "ye will not answer me,"], ["pe tatala mai ia te au.", "nor let me go."]]},
  {num:69,words:[["E amata i nei ona po ona nofo o le Atalii o le tagata i le itu taumatau o le Atua mamana.", "Hereafter shall the Son of man sit on the right hand of the power of God."]]},
  {num:70,words:[["Ona fai mai lea o i latou uma,", "Then said they all,"], ["O oe foi ea le Alo o le Atua? Ua fetalai atu ia ia te i latou,", "Art thou then the Son of God? And he said unto them,"], ["O a'u lea ua outou fai mai ai na.", "Ye say that I am."]]},
  {num:71,words:[["Ona latou fai ane ai lea, Se a le aoga o sa tatou toe molimau? auā o i tatou lava,", "And they said,"], ["ua tatou faalogo i lana lava upu.", "What need we any further witness? for we ourselves have heard of his own mouth."]]},
];
renderVerseSet(luk_ch_22_Verses, 'luk-ch22-verses');

var luk_ch_23_Verses = [
  {num:1,words:[["Ua tutū i luga i latou uma lava,", "And the whole multitude of them arose,"], ["ua ta'ita'i ia te ia ia Pilato.", "and led him unto Pilate."]]},
  {num:2,words:[["Ona latou momoli ai lea ia te ia,", "And they began to accuse him,"], ["ua faapea atu, Na matou iloa lenei tagata ua ia faasese i le nuu,", "saying,"], ["ua vavao foi ona avatu o taulaga ia Kaisara,", "We found this fellow perverting the nation,"], ["ua faapea mai, o ia lava o le Tupu,", "and forbidding to give tribute to Caesar,"], ["o Keriso.", "saying that he himself is Christ a King."]]},
  {num:3,words:[["Ona fesili mai lea o Pilato ia te ia,", "And Pilate asked him,"], ["ua faapea mai,", "saying,"], ["O oe ea o le tupu o tagata Iutaia? Ua tali atu ia ia te ia, ua faapea atu,", "Art thou the King of the Jews? And he answered him and said,"], ["O lea lava.", "Thou sayest it."]]},
  {num:4,words:[["Ona fai ane lea o Pilato i le au faitaulaga sili ma le motu o tagata,", "Then said Pilate to the chief priests and to the people,"], ["Ou te le iloa se mea e sala ai lenei tagata.", "I find no fault in this man."]]},
  {num:5,words:[["A ua latou finau pea,", "And they were the more fierce,"], ["ua faapea mai,", "saying,"], ["Ua faaoso e ia i le nuu,", "He stirreth up the people,"], ["ua a'oa'o i Iutaia uma,", "teaching throughout all Jewry,"], ["ua afua mai i Kalilaia ua oo mai iinei.", "beginning from Galilee to this place."]]},
  {num:6,words:[["Ua faalogo Pilato ia Kalilaia, ona fesili ane lea o ia,", "When Pilate heard of Galilee,"], ["pe se tagata Kalilaia o ia.", "he asked whether the man were a Galilaean."]]},
  {num:7,words:[["Ua iloa e ia,", "And as soon as he knew that he belonged unto Herod's jurisdiction,"], ["o ia mai le itu malo o Herota, ona avatu lea o ia ia Herota,", "he sent him to Herod,"], ["o ia foi sa i Ierusalema i ia ona po.", "who himself also was at Jerusalem at that time."]]},
  {num:8,words:[["Ua iloa atu e Herota ia Iesu,", "And when Herod saw Jesus,"], ["ona fiafia tele ai lea o ia;", "he was exceeding glad:"], ["auā ua leva ona fia matamata ia te ia,", "for he was desirous to see him of a long season,"], ["ona o mea e tele ua logo mai ia te ia;", "because he had heard many things of him;"], ["ua faamoemoe foi o ia na te vaavaai i se faailoga e faia e ia.", "and he hoped to have seen some miracle done by him."]]},
  {num:9,words:[["Ua fesili mai o ia ia te ia i upu e tele;", "Then he questioned with him in many words;"], ["a e lei tali atu e ia se upu ia te ia.", "but he answered him nothing."]]},
  {num:10,words:[["Ua tutū i luga le au faitaulaga sili ma le au tusiupu, ua naunau lo latou momoli ia te ia.", "And the chief priests and scribes stood and vehemently accused him."]]},
  {num:11,words:[["Ua faaleaogaina o ia e Herota ma lana 'au,", "And Herod with his men of war set him at nought,"], ["ma tauemu mai ia te ia,", "and mocked him,"], ["ua latou faaofu foi ia te ia i le ofu pupula,", "and arrayed him in a gorgeous robe,"], ["ona toe au mai ai lea o ia ia Pilato.", "and sent him again to Pilate."]]},
  {num:12,words:[["Ua toe lelei o Pilato ma Herota i lea lava aso;", "And the same day Pilate and Herod were made friends together:"], ["auā sa muai feitagai i laua.", "for before they were at enmity between themselves."]]},
  {num:13,words:[["Ona faapotopoto lea e Pilato le au faitaulaga sili, ma le au faipule,", "And Pilate,"], ["ma le nuu,", "when he had called together the chief priests and the rulers and the people,"]]},
  {num:14,words:[["ona fai atu lea o ia ia te i latou,", "Said unto them,"], ["Ua outou au mai lenei tagata ia te au,", "Ye have brought this man unto me, as one that perverteth the people:"], ["e peiseai se faasese i le nuu;", "and,"], ["faauta mai foi,", "behold,"], ["ua ou suesue ia te ia i o outou luma,", "I, having examined him before you,"], ["ou te lei iloa se mea e sala ai lenei tagata i mea ua outou molia mai ai ia te ia.", "have found no fault in this man touching those things whereof ye accuse him:"]]},
  {num:15,words:[["A ua le iloa foi e Herota;", "No, nor yet Herod:"], ["auā na ou aauina atu outou ia te ia;", "for I sent you to him;"], ["faauta foi,", "and,"], ["e leai se mea ua faia e ia e tusa ai ona oti o ia.", "lo, nothing worthy of death is done unto him."]]},
  {num:16,words:[["O lenei foi, ou te aoai atu ia te ia,", "I will therefore chastise him,"], ["i le ou tatalaina atu ai.", "and release him."]]},
  {num:17,words:[["(E ao ina tatalaina e ia o se tasi tagata ia te i latou i le tausamiga.)", "(For of necessity he must release one unto them at the feast.)"]]},
  {num:18,words:[["A ua alaga mai le motu o tagata uma lava,", "And they cried out all at once,"], ["ua faapea mai,", "saying,"], ["Ave ese ia lena tagata ,", "Away with this man,"], ["a ia tatala mai Parapa ia te i matou.", "and release unto us Barabbas:"]]},
  {num:19,words:[["(O le tagata lea na tuuina i le fale puipui,", "(Who for a certain sedition made in the city,"], ["ona o le fouvale sa faia i le aai,", "and for murder,"], ["ma le fasioti tagata.)", "was cast into prison.)"]]},
  {num:20,words:[["Ona toe tautala atu ai lea o Pilato,", "Pilate therefore, willing to release Jesus,"], ["ina ua fia tatalaina atu Iesu.", "spake again to them."]]},
  {num:21,words:[["A ua latou leo tetele mai,", "But they cried,"], ["ua faapea mai,", "saying,"], ["Ina faasatauro ia,", "Crucify him,"], ["ina faasatauro ia ia te ia.", "crucify him."]]},
  {num:22,words:[["Ua fai atu faatolu foi o ia ia te i latou,", "And he said unto them the third time,"], ["Se a foi lona leaga ua na faia? Ou te lei iloa se mea e faasalaina ai o ia ia oti;", "Why,"], ["o lea foi ou te aoai atu ai ia te ia,", "what evil hath he done? I have found no cause of death in him: I will therefore chastise him,"], ["i le ou tatalaina atu ai.", "and let him go."]]},
  {num:23,words:[["A ua latou faatauanau mai ma leo tetele, o fai mai ia faasatauroina ia;", "And they were instant with loud voices,"], ["ua malo o latou leo ma leo o le au faitaulaga sili.", "requiring that he might be crucified. And the voices of them and of the chief priests prevailed."]]},
  {num:24,words:[["Ua fai atu e Pilato, ia faia lo latou manao.", "And Pilate gave sentence that it should be as they required."]]},
  {num:25,words:[["Ua tatalaina e ia ia te i latou o le na tuuina atu i le fale puipui ona o le fouvale ma le fasioti tagata ua latou fai mai ai;", "And he released unto them him that for sedition and murder was cast into prison, whom they had desired;"], ["a ua tuuina atu e ia o Iesu i lo latou manao.", "but he delivered Jesus to their will."]]},
  {num:26,words:[["Ua latou ta'ita'i atu ia te ia,", "And as they led him away, they laid hold upon one Simon,"], ["ona latou pue atu lea ia Simona,", "a Cyrenian,"], ["o le tasi Kurene ua sau mai le vao;", "coming out of the country,"], ["ua latou faaee ia te ia le satauro e faafuata ai ma mulimuli ia Iesu.", "and on him they laid the cross, that he might bear it after Jesus."]]},
  {num:27,words:[["Ua mulimuli atu ia te ia le motu o tagata e toatele,", "And there followed him a great company of people,"], ["ma fafine, e ua taufaitagitu'i,", "and of women,"], ["ma taufaitagiaue ia te ia.", "which also bewailed and lamented him."]]},
  {num:28,words:[["A ua fāliu Iesu ia te i latou,", "But Jesus turning unto them said,"], ["ua fetalai atu,", "Daughters of Jerusalem,"], ["Tama fafine a Ierusalema e, soia le tagi ia te au,", "weep not for me,"], ["a ia outou tagi ia te outou,", "but weep for yourselves,"], ["atoa foi ma a outou fanau.", "and for your children."]]},
  {num:29,words:[["Faauta foi,", "For,"], ["e oo mai ona aso,", "behold,"], ["e fai mai ai tagata,", "the days are coming, in the which they shall say,"], ["Amuia e ua pa,", "Blessed are the barren,"], ["ma fafine e lei fananau,", "and the wombs that never bare,"], ["ma susu e lei susuina.", "and the paps which never gave suck."]]},
  {num:30,words:[["Ona fai atu lea o tagata i mauga,", "Then shall they begin to say to the mountains,"], ["Mafuli mai ia ia te i matou;", "Fall on us;"], ["e fai atu foi i mea maupuepue,", "and to the hills,"], ["Ina ufiufi ifo ia ia te i matou.", "Cover us."]]},
  {num:31,words:[["Auā afai e faia nei mea i le laau mata,", "For if they do these things in a green tree,"], ["se a se mea e fai i le laau mago?", "what shall be done in the dry?"]]},
  {num:32,words:[["O isi foi pagotata e toalua,", "And there were also two other,"], ["ua ta'ita'iina atu faatasi ma ia,", "malefactors,"], ["ia fasiotia.", "led with him to be put to death."]]},
  {num:33,words:[["Ua latou oo atu i le mea e ta'ua o le mea o i ai le ulupoo,", "And when they were come to the place,"], ["ua latou faasatauro ia te ia i lea mea,", "which is called Calvary,"], ["ma e pagotata,", "there they crucified him, and the malefactors,"], ["o le tasi i le itu taumatau,", "one on the right hand,"], ["ma le tasi i le itu tauagavale.", "and the other on the left."]]},
  {num:34,words:[["Ona fetalai atu lea o Iesu,", "Then said Jesus,"], ["Lo'u Tamā e,", "Father,"], ["ia e faamagaloina atu ia te i latou;", "forgive them;"], ["auā ua latou le iloa le mea ua latou faia. Ua tufatufa e i latou ona ofu,", "for they know not what they do. And they parted his raiment,"], ["ona fai ai lea o le vili.", "and cast lots."]]},
  {num:35,words:[["Ua tutū mai le nuu,", "And the people stood beholding. And the rulers also with them derided him,"], ["ma matamata mai. O le au faipule foi ua tauemu mai ia te ia faatasi ma i latou,", "saying,"], ["ua faapea mai,", "He saved others;"], ["Na faaolaina e ia nisi tagata,", "let him save himself,"], ["ina faaola ia o ia ia te ia,", "if he be Christ,"], ["pe afai o le Keriso lena ua filifilia e le Atua.", "the chosen of God."]]},
  {num:36,words:[["Ua tauemu mai foi ia te ia tagata tau;", "And the soldiers also mocked him,"], ["ua o ane ia te ia,", "coming to him,"], ["ma avatu i ai le vineta,", "and offering him vinegar,"]]},
  {num:37,words:[["ua faapea atu,", "And saying,"], ["Afai o oe o le tupu o tagata Iutaia,", "If thou be the king of the Jews,"], ["ina faaola ia oe ia te oe.", "save thyself."]]},
  {num:38,words:[["Na tusia foi le tusi i ona luga,", "And a superscription also was written over him in letters of Greek,"], ["i le upu a Eleni,", "and Latin,"], ["ma Roma, ma Eperu,", "and Hebrew,"], ["O LE TUPU LENEI O TAGATA IUTAIA.", "THIS IS THE KING OF THE JEWS."]]},
  {num:39,words:[["O le tasi foi o e na pagotata ua faatautauina ua upu leaga o ia ia te ia,", "And one of the malefactors which were hanged railed on him,"], ["ua faapea mai,", "saying,"], ["Afai o oe o le Keriso,", "If thou be Christ,"], ["ina faaola ia oe ia te oe atoa ma i maua nei.", "save thyself and us."]]},
  {num:40,words:[["A ua tali atu le tasi,", "But the other answering rebuked him,"], ["ua vavao ia te ia,", "saying,"], ["ua faapea atu, E te le mata'u ea i le Atua,", "Dost not thou fear God,"], ["ina ua tatou sala faatasi?", "seeing thou art in the same condemnation?"]]},
  {num:41,words:[["Ua tonu lava la ta sala;", "And we indeed justly;"], ["auā ua tauia mai i taua e tusa ma mea na ta faia; a o ia nei,", "for we receive the due reward of our deeds:"], ["e leai se mea e le tusa na faia e ia.", "but this man hath done nothing amiss."]]},
  {num:42,words:[["Ona fai mai lea o ia ia Iesu,", "And he said unto Jesus,"], ["Le Alii e, ia e manatua mai a'u,", "Lord,"], ["pe a e afio mai i lou malo.", "remember me when thou comest into thy kingdom."]]},
  {num:43,words:[["Ona fetalai atu ai lea o Iesu ia te ia,", "And Jesus said unto him,"], ["E moni, ou te fai atu ia te oe,", "Verily I say unto thee,"], ["o le asō ta te faatasi ai ma oe i parataiso.", "To day shalt thou be with me in paradise."]]},
  {num:44,words:[["Ua oo i le itu aso po ua ono, ona pogisa uma ai lea o le nuu,", "And it was about the sixth hour,"], ["ua oo lava i le itu aso e iva.", "and there was a darkness over all the earth until the ninth hour."]]},
  {num:45,words:[["Ua faapouliuliina foi le la;", "And the sun was darkened,"], ["o le ie puipui foi o le malumalu ua saeluagalemuina.", "and the veil of the temple was rent in the midst."]]},
  {num:46,words:[["Ona valaau ai lea o Iesu,", "And when Jesus had cried with a loud voice,"], ["ua leo tele,", "he said,"], ["ua faapea atu, Lo'u Tamā e,", "Father,"], ["ou te tuuina atu lo'u nei agaga i ou aao;", "into thy hands I commend my spirit:"], ["ua na fetalai ia upu,", "and having said thus,"], ["ona to ai lea o lana mānava.", "he gave up the ghost."]]},
  {num:47,words:[["Ua iloa e le ta'ita'i o le toaselau le mea ua faia,", "Now when the centurion saw what was done,"], ["ona vivii atu lea o ia i le Atua,", "he glorified God,"], ["ua faapea atu, E moni,", "saying,"], ["o le tagata amiotonu lenei.", "Certainly this was a righteous man."]]},
  {num:48,words:[["O tagata uma e ua faapotopoto e maimoa i lea mea,", "And all the people that came together to that sight,"], ["ua vaavaai i mea ua faia,", "beholding the things which were done,"], ["ona pōpō lea o i latou i o latou lava fatafata,", "smote their breasts,"], ["ma toe foi atu.", "and returned."]]},
  {num:49,words:[["Ua tutū mamao atu foi tagata uma e sa masani ma ia,", "And all his acquaintance,"], ["atoa ma fafine e na mulimuli mai ia te ia mai Kalilaia,", "and the women that followed him from Galilee, stood afar off,"], ["ua vaavaai mai i latou i ia mea.", "beholding these things."]]},
  {num:50,words:[["Faauta foi,", "And, behold,"], ["o le tagata e igoa ia Iosefa,", "there was a man named Joseph,"], ["o le faipule ia,", "a counsellor;"], ["o le tagata amio lelei ma le tonu;", "and he was a good man, and a just:"]]},
  {num:51,words:[["(e lei faaopoopo o ia i la latou pule ma la latou mea na fai,", "(The same had not consented to the counsel and deed of them;"], [") o le Arimataia o ia,", ") he was of Arimathaea,"], ["o le aai lea o tagata Iutaia,", "a city of the Jews:"], ["o ia foi sa faatalitali atu i le malo o le Atua.", "who also himself waited for the kingdom of God."]]},
  {num:52,words:[["Ua alu atu o ia ia Pilato,", "This man went unto Pilate,"], ["ma faanoi atu i le tino o Iesu.", "and begged the body of Jesus."]]},
  {num:53,words:[["Ua na ave ifo ai,", "And he took it down,"], ["ona aui lea i le ie lino,", "and wrapped it in linen,"], ["ona tuu ai lea i le tuugamau na foa i le papa,", "and laid it in a sepulchre that was hewn in stone,"], ["e lei tuu ai lava se tasi.", "wherein never man before was laid."]]},
  {num:54,words:[["O le aso lea o le sauniga,", "And that day was the preparation,"], ["ua latalata le sapati.", "and the sabbath drew on."]]},
  {num:55,words:[["Ua mulimuli atu foi fafine e na o mai ma ia mai Kalilaia,", "And the women also, which came with him from Galilee,"], ["ua latou vaavaai i le tuugamau,", "followed after,"], ["ma le tuuina ai o lona tino.", "and beheld the sepulchre, and how his body was laid."]]},
  {num:56,words:[["Ua latou toe foi atu,", "And they returned,"], ["ua sauni mea manogi ma suāuu manogi; ua latou malolo foi i le sapati,", "and prepared spices and ointments;"], ["e tusa ma le poloaiga.", "and rested the sabbath day according to the commandment."]]},
];
renderVerseSet(luk_ch_23_Verses, 'luk-ch23-verses');

var luk_ch_24_Verses = [
  {num:1,words:[["O le uluai aso o le vaisapati,", "Now upon the first day of the week,"], ["ua latou o atu ai i le tuugamau i le tafa o ata,", "very early in the morning,"], ["ua ave mea manogi na latou saunia,", "they came unto the sepulchre, bringing the spices which they had prepared,"], ["o isi foi fafine sa faatasi ma i latou.", "and certain others with them."]]},
  {num:2,words:[["Ua iloa e i latou ua fulieseina le maa nai le tuugamau;", "And they found the stone rolled away from the sepulchre."]]},
  {num:3,words:[["ona latou ulu atu lea i totonu,", "And they entered in,"], ["a e lei iloa le tino o le Alii o Iesu.", "and found not the body of the Lord Jesus."]]},
  {num:4,words:[["Ua fememeai i latou i lenei mea,", "And it came to pass,"], ["faauta foi,", "as they were much perplexed thereabout, behold,"], ["ua tutū mai ia te i latou tagata e toalua ua oofu i ofu pupula.", "two men stood by them in shining garments:"]]},
  {num:5,words:[["Ua matatau i latou,", "And as they were afraid,"], ["ua punou foi o latou mata i le eleele,", "and bowed down their faces to the earth,"], ["ona la fai mai lea ia te i latou,", "they said unto them,"], ["Se a le mea tou te saili ai le ua soifua i e ua oti?", "Why seek ye the living among the dead?"]]},
  {num:6,words:[["E le o iinei o ia,", "He is not here,"], ["a ua tu; ia outou manatu i lona fetalai atu ia te outou,", "but is risen:"], ["ina o i Kalilaia o ia,", "remember how he spake unto you when he was yet in Galilee,"]]},
  {num:7,words:[["ua faapea atu,", "Saying,"], ["E tatau ona tuuina atu o le Atalii o le tagata i lima o tagata agasala,", "The Son of man must be delivered into the hands of sinful men,"], ["ma ia faasatauroina,", "and be crucified,"], ["ma toe tu mai i le aso tolu.", "and the third day rise again."]]},
  {num:8,words:[["Ona latou manatu ai lea i lana fetalaiga.", "And they remembered his words,"]]},
  {num:9,words:[["Ua latou toe foi mai nai le tuugamau,", "And returned from the sepulchre,"], ["ona latou faamatala mai lea o ia mea uma i le toasefulu ma le toatasi,", "and told all these things unto the eleven,"], ["atoa ma i latou uma.", "and to all the rest."]]},
  {num:10,words:[["O Maria foi le Makatala,", "It was Mary Magdalene,"], ["ma Ioana,", "and Joanna,"], ["ma Maria le tinā o Iakopo,", "and Mary the mother of James,"], ["ma i latou uma sa ia te i latou,", "and other women that were with them,"], ["o i latou ia e na faamatala mai ia mea i le au aposetolo.", "which told these things unto the apostles."]]},
  {num:11,words:[["Ua latou manatu foi i a latou upu e peiseai se talanoaga;", "And their words seemed to them as idle tales,"], ["latou te lei talitonu foi ia te i latou.", "and they believed them not."]]},
  {num:12,words:[["A ua tu i luga Peteru,", "Then arose Peter,"], ["ua momo'e i le tuugamau;", "and ran unto the sepulchre;"], ["ua punou foi,", "and stooping down,"], ["ua iloa e ia o ie ua tuu faatasi;", "he beheld the linen clothes laid by themselves,"], ["ona alu ai lea o ia,", "and departed,"], ["ua ofo i le mea ua faia.", "wondering in himself at that which was come to pass."]]},
  {num:13,words:[["Faauta foi,", "And,"], ["ua ō le toalua o i latou i lea aso i le aai,", "behold,"], ["o Emau le igoa,", "two of them went that same day to a village called Emmaus,"], ["o lo la va ma Ierusalema e onogafulu o setatio.", "which was from Jerusalem about threescore furlongs."]]},
  {num:14,words:[["Sa fetautalatala'i i laua i ia mea uma ua faia.", "And they talked together of all these things which had happened."]]},
  {num:15,words:[["Ua la fetautalatala'i,", "And it came to pass,"], ["ma fesueai,", "that,"], ["ona faalatalata mai ai lea o Iesu,", "while they communed together and reasoned, Jesus himself drew near,"], ["ua o faatasi ma i laua.", "and went with them."]]},
  {num:16,words:[["A ua punitia o laua mata, o lea ua le iloa ai o ia e i laua.", "But their eyes were holden that they should not know him."]]},
  {num:17,words:[["Ua fetalai atu ia ia te i laua,", "And he said unto them,"], ["O a ea ia upu ua oulua felafolafoai ai,", "What manner of communications are these that ye have one to another,"], ["o oulua o savavali,", "as ye walk,"], ["ma ua mata faanoanoa?", "and are sad?"]]},
  {num:18,words:[["O le tasi o i laua e igoa ia Kaleopa,", "And the one of them,"], ["ua tali mai ia te ia,", "whose name was Cleopas,"], ["ua faapea mai,", "answering said unto him, Art thou only a stranger in Jerusalem,"], ["Pe na o oe ea lē āumau i Ierusalema ma le le iloa o mea ua tutupu ai i ona po nei?", "and hast not known the things which are come to pass there in these days?"]]},
  {num:19,words:[["Ona fetalai atu lea o ia ia te i laua,", "And he said unto them,"], ["O a mea? Ona la fai mai ai lea ia te ia,", "What things? And they said unto him,"], ["O mea ia Iesu le Nasareta, o le perofeta lea sa malosi i mea na na faia,", "Concerning Jesus of Nazareth,"], ["atoa ma ana upu i luma o le Atua ma le nuu uma;", "which was a prophet mighty in deed and word before God and all the people:"]]},
  {num:20,words:[["na tuuina atu foi o ia e le au faitaulaga sili ma o tatou faipule, ia faasalaina o ia ia oti,", "And how the chief priests and our rulers delivered him to be condemned to death,"], ["ma ua latou faasatauroina o ia.", "and have crucified him."]]},
  {num:21,words:[["Sa matou faamoemoe foi,", "But we trusted that it had been he which should have redeemed Israel:"], ["o ia lava o le a togiolaina Isaraelu; a e le gata i ia mea uma,", "and beside all this,"], ["o lona aso tolu le asō talu ona faia o na mea.", "to day is the third day since these things were done."]]},
  {num:22,words:[["A ua matou ofo lava i nisi fafine o i matou sa i le tuugamau i le tafa o ata;", "Yea, and certain women also of our company made us astonished, which were early at the sepulchre;"]]},
  {num:23,words:[["e lei iloa e i latou lona tino,", "And when they found not his body,"], ["a ua latou o atu,", "they came,"], ["ma faapea atu, ua iloa e i latou agelu na faaali mai,", "saying,"], ["e na fai mai,", "that they had also seen a vision of angels,"], ["ua soifua o ia.", "which said that he was alive."]]},
  {num:24,words:[["O isi foi o matou, na latou o i le tuugamau,", "And certain of them which were with us went to the sepulchre,"], ["ua faapea foi ona iloa e i latou,", "and found it even so as the women had said:"], ["pei ona fai mai ai o fafine; a e lei iloa e i latou o ia.", "but him they saw not."]]},
  {num:25,words:[["Ona fetalai atu lea o ia ia te i laua,", "Then he said unto them,"], ["O tagata valea,", "O fools,"], ["ma loto faigata ona talitonu i mea uma ua fai mai ai e le au perofeta.", "and slow of heart to believe all that the prophets have spoken:"]]},
  {num:26,words:[["E le tatau ea ona tiga o le Keriso i mea faapena,", "Ought not Christ to have suffered these things,"], ["i le oo ai o ia i lona mamalu?", "and to enter into his glory?"]]},
  {num:27,words:[["Ona faamatala ai lea e ia ia te i laua o mea ua tusia ia te ia i Tusi uma,", "And beginning at Moses and all the prophets,"], ["ua amata mai ia Mose atoa ma le au perofeta uma.", "he expounded unto them in all the scriptures the things concerning himself."]]},
  {num:28,words:[["Ua latou faalatalata atu i le aai ua latou o i ai;", "And they drew nigh unto the village, whither they went:"], ["a o ia ua aga atu peiseai a alu loa.", "and he made as though he would have gone further."]]},
  {num:29,words:[["A ua la pulunaunau ia te ia,", "But they constrained him,"], ["na faapea mai,", "saying,"], ["Tatou te nonofo ma i maua nei;", "Abide with us:"], ["auā ua taugagaifo le la,", "for it is toward evening,"], ["ua lata i le afiafi.", "and the day is far spent."], ["Ona ulufale atu lea o ia, latou te nonofo.", "And he went in to tarry with them."]]},
  {num:30,words:[["Ua taoto ia e taumafa faatasi ma i laua,", "And it came to pass,"], ["ona tago ai lea i le areto,", "as he sat at meat with them,"], ["ua faafetai,", "he took bread, and blessed it,"], ["ua tofitofi,", "and brake,"], ["ma avatu ia te i laua.", "and gave to them."]]},
  {num:31,words:[["Ona pupula ai lea o laua mata,", "And their eyes were opened,"], ["ua la iloa o ia;", "and they knew him;"], ["a ua mou o ia nai ia i laua.", "and he vanished out of their sight."]]},
  {num:32,words:[["Ona la fetautalatala'i lea,", "And they said one to another,"], ["E lei mu ea o ta loto i totonu ia i taua,", "Did not our heart burn within us,"], ["ina ua fetalai o ia ia te i taua i le ala,", "while he talked with us by the way,"], ["ina ua faamatala mai foi e ia o Tusi ia te i taua?", "and while he opened to us the scriptures?"]]},
  {num:33,words:[["Ua la tutu i luga i lea lava itu aso,", "And they rose up the same hour,"], ["ua toe foi atu ai i Ierusalema,", "and returned to Jerusalem, and found the eleven gathered together,"], ["ua maua atu foi e i laua o le toasefulu ma le toatasi ua faapotopoto faatasi ma e na ia i latou;", "and them that were with them,"]]},
  {num:34,words:[["o faapea mai i latou,", "Saying,"], ["E moni, ua toe tu le Alii,", "The Lord is risen indeed,"], ["ua faaali foi o ia ia Simona.", "and hath appeared to Simon."]]},
  {num:35,words:[["O i laua foi ua la faamatala atu mea na faia i le ala,", "And they told what things were done in the way,"], ["mona ua iloa foi o ia e i laua ina o tofitofi le areto.", "and how he was known of them in breaking of bread."]]},
  {num:36,words:[["O tautalatala i latou i nei mea,", "And as they thus spake,"], ["a a ua tu mai Iesu lava i o latou luma,", "Jesus himself stood in the midst of them,"], ["ua fetalai atu ia te i latou,", "and saith unto them,"], ["Ia outou manuia.", "Peace be unto you."]]},
  {num:37,words:[["Ua fefefe i latou, ua matuā matatau lava,", "But they were terrified and affrighted,"], ["fa te i latou o le agaga ua latou vaaia.", "and supposed that they had seen a spirit."]]},
  {num:38,words:[["Ua fetalai atu foi o ia ia te i latou,", "And he said unto them,"], ["Se a le mea ua outou atuatuvale ai? se a foi e tutupu ai masalo i o outou loto?", "Why are ye troubled? and why do thoughts arise in your hearts?"]]},
  {num:39,words:[["Ia outou vaavaai mai i o'u lima ma o'u vae,", "Behold my hands and my feet,"], ["auā o a'u lava lenei;", "that it is I myself:"], ["ia outou tagotago mai ia te au,", "handle me,"], ["ma ia vaavaai mai;", "and see;"], ["auā o le agaga e leai sona aano ma ni ivi,", "for a spirit hath not flesh and bones,"], ["pei o a'u nei ua outou vaavaai i ai.", "as ye see me have."]]},
  {num:40,words:[["Ua uma ona fetalai atu,", "And when he had thus spoken,"], ["ona faaali atu ai lea e ia ia te i latou o ona lima ma ona vae.", "he shewed them his hands and his feet."]]},
  {num:41,words:[["A o lei talitonu i latou ona ua olioli,", "And while they yet believed not for joy,"], ["ma ua ofo,", "and wondered,"], ["ua fetalai atu ia ia te i latou,", "he said unto them,"], ["O iina ea ni a outou mea e 'ai?", "Have ye here any meat?"]]},
  {num:42,words:[["Ona latou avatu ai lea ia te ia se fāsi i'a tunu,", "And they gave him a piece of a broiled fish,"], ["ma se fāsi melikerio.", "and of an honeycomb."]]},
  {num:43,words:[["Ua tago ia i ai,", "And he took it,"], ["ma taumafa ai i o latou uma.", "and did eat before them."]]},
  {num:44,words:[["Ua fetalai atu ia ia te i latou,", "And he said unto them,"], ["O upu ia na ou fai atu ai ia te outou,", "These are the words which I spake unto you, while I was yet with you,"], ["ina o ou ia te outou;", "that all things must be fulfilled,"], ["e tatau ona taunuu o mea uma ua tusia ia te au i le tulafono a Mose,", "which were written in the law of Moses,"], ["ma le au perofeta,", "and in the prophets, and in the psalms,"], ["ma salāmo.", "concerning me."]]},
  {num:45,words:[["Ona tatalaina lea o ia o latou loto,", "Then opened he their understanding,"], ["ina ia latou lagona ai Tusi.", "that they might understand the scriptures,"]]},
  {num:46,words:[["Ua fetalai atu foi o ia ia te i latou,", "And said unto them,"], ["Ua faapea ona tusia,", "Thus it is written,"], ["e faapea foi ona tatau ina tiga o le Keriso,", "and thus it behoved Christ to suffer,"], ["ma toe tu nai e ua oti i le aso tolu;", "and to rise from the dead the third day:"]]},
  {num:47,words:[["ina ia tala'iina foi le salamo ma le faamagaloina o agasala i nuu uma i lona igoa,", "And that repentance and remission of sins should be preached in his name among all nations,"], ["e amata mai i Ierusalema.", "beginning at Jerusalem."]]},
  {num:48,words:[["O molimau foi outou i nei mea.", "And ye are witnesses of these things."]]},
  {num:49,words:[["Faauta foi,", "And,"], ["ou te auina mai ia te outou le na folafolaina e lo'u Tamā;", "behold,"], ["a ia outou nonofo i le aai o Ierusalema,", "I send the promise of my Father upon you: but tarry ye in the city of Jerusalem,"], ["seia maua e outou le mana mai lugā.", "until ye be endued with power from on high."]]},
  {num:50,words:[["Ua ave e ia ia te i latou i tua,", "And he led them out as far as to Bethany,"], ["ua oo lava i Petania; ona sisii ai lea o ona aao,", "and he lifted up his hands,"], ["ma faamanuia ia te i latou.", "and blessed them."]]},
  {num:51,words:[["Ua oo ina o faamanuia e ia ia te i latou,", "And it came to pass,"], ["ona te'a ese lea o ia ia te i latou,", "while he blessed them, he was parted from them,"], ["ua siitia i le lagi.", "and carried up into heaven."]]},
  {num:52,words:[["Ua latou ifo ia te ia,", "And they worshipped him,"], ["ona toe foi mai lea i Ierusalema ma le olioli tele;", "and returned to Jerusalem with great joy:"]]},
  {num:53,words:[["sa i le malumalu i latou e le aunoa,", "And were continually in the temple,"], ["o latou o vivii ma faafetai atu i le Atua. Amene.", "praising and blessing God. Amen."]]},
];
renderVerseSet(luk_ch_24_Verses, 'luk-ch24-verses');

})();